-- slr_rsl : esquema + datos (generado desde formularios de extracción)
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS `EXTRACCION_P1`;
DROP TABLE IF EXISTS `EXTRACCION_P2`;
DROP TABLE IF EXISTS `EXTRACCION_P3`;
DROP TABLE IF EXISTS `ARTICULO`;
CREATE TABLE `ARTICULO` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `codigo` VARCHAR(20) NOT NULL,
  `doi` VARCHAR(255) DEFAULT NULL,
  `fecha_extraccion` DATE DEFAULT NULL,
  `autores` VARCHAR(500) DEFAULT NULL,
  `titulo` VARCHAR(500) NOT NULL,
  `anio` INT DEFAULT NULL,
  `revista` VARCHAR(300) DEFAULT NULL,
  `resumen` TEXT,
  `cadena` ENUM('P1','P2','P3') NOT NULL,
  `prioridad` ENUM('Alta','Media','Baja') DEFAULT 'Media',
  `estado` ENUM('Pendiente','En_progreso','Completo') DEFAULT 'Pendiente',
  `acceso_pdf` ENUM('Disponible','Sin_acceso') DEFAULT 'Sin_acceso',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `EXTRACCION_P1` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `idArticulo` INT NOT NULL,
  `analisis_espacial` TEXT, `analisis_temporal` TEXT, `software` TEXT, `diseno_estudio` TEXT,
  PRIMARY KEY (`id`),
  CONSTRAINT `fk_p1_art` FOREIGN KEY (`idArticulo`) REFERENCES `ARTICULO`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `EXTRACCION_P2` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `idArticulo` INT NOT NULL,
  `contaminantes` TEXT, `fuente_ambiental` TEXT, `fuente_satelital` TEXT, `fuente_salud` TEXT,
  `otras_fuentes` TEXT, `poblacion` TEXT, `resolucion_espacial` TEXT, `resolucion_temporal` TEXT,
  `pais_region` TEXT, `periodo_cubierto` TEXT,
  PRIMARY KEY (`id`),
  CONSTRAINT `fk_p2_art` FOREIGN KEY (`idArticulo`) REFERENCES `ARTICULO`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `EXTRACCION_P3` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `idArticulo` INT NOT NULL,
  `metodo_modelamiento` TEXT, `lag_estimado` TEXT, `ajuste_confusores` TEXT, `factores_topograficos` TEXT,
  `metrica_evaluacion` TEXT, `valor_alcanzado` TEXT, `sistema_alerta` ENUM('Si','No') DEFAULT 'No',
  `tipo_alerta` TEXT, `resultado_principal` TEXT, `limitaciones` TEXT, `oportunidades` TEXT,
  PRIMARY KEY (`id`),
  CONSTRAINT `fk_p3_art` FOREIGN KEY (`idArticulo`) REFERENCES `ARTICULO`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

