INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (1,'P1-001','10.1007/s11869-026-01950-5','2026-04-18','da Cunha Tasca B.F. et al.','The respiratory health paradox in mato grosso seniors: environmental drivers of divergent hospitalization and mortality trends',2026,'Air Quality Atmosphere and Health','Estudio ecológico que evalúa la variabilidad espacio-temporal de las tasas de hospitalización y mortalidad por enfermedades respiratorias en adultos ≥65 años en Mato Grosso, Brasil (2000–2020), y su asociación con indicadores ambientales. Integra datos del SIH/SUS con precipitación (ERA5), humedad relativa (ERA-Interim), focos de calor (BDQueimadas/INPE) y PM2.5 (CAMS reanalysis), agregados a escala municipio-mes. Aplica funciones de correlación cruzada (CCF), bootstrapping y Moran\'s I local (LISA) para identificar clusters espaciales. Encuentra una paradoja de salud respiratoria: las hospitalizaciones disminuyen mientras la mortalidad aumenta, con patrones espaciales heterogéneos. A nivel estatal las correlaciones con focos de calor y PM2.5 son débiles e incluso contraintuitivas, pero a nivel local algunos clusters muestran co-variación positiva durante la estación seca. Esta heterogeneidad sugiere que los determinantes ambientales y la salud respiratoria interactúan de forma diferenciada según el contexto climático y el acceso a salud.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (2,'P1-002','10.1016/j.envres.2025.123453','2026-04-18','Li Z. et al.','Wildfire-sourced PM2.5 and cause-specific emergency department visits in Victoria, Australia from 2014 to 2019',2026,'Environmental Research','Evalúa la asociación entre PM2.5 de origen en incendios forestales (WS-PM2.5) y visitas a urgencias (ED) en Victoria, Australia (2014–2019). Utiliza datos de ED del VEMD en 460 comunidades SA2 y concentraciones de WS-PM2.5 modeladas con GEOS-Chem y machine learning. Aplica modelo de series temporales en dos etapas con regresión quasi-Poisson. Por cada 1 µg/m³ de WS-PM2.5, el riesgo de visitas a urgencias aumentó 0.27% (todas causas), 0.45% (cardiovascular) y 0.47% (respiratorio), con mayor carga en comunidades urbanas del sureste.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (3,'P1-003','10.1111/ppe.70080','2026-04-18','Syed A. et al.','The Joint Effects of Extreme Heat and Wildfire Smoke on Paediatric Acute Care Utilisation',2026,'Paediatric and Perinatal Epidemiology','Evalúa los efectos conjuntos del calor extremo y el humo de incendios forestales sobre la utilización de atención aguda pediátrica en California (2006–2019). Utiliza un dataset de WS-PM2.5 a nivel ZCTA y un índice de calor máximo diario de GRIDMET. Aplica diseño caso-cruzado estratificado por tiempo con regresión logística condicional y cuantifica la sinergia mediante RERI. El efecto conjunto es mayor que la suma de los efectos individuales (RERI hasta 0.11), con efectos sinérgicos consistentes para enfermedades respiratorias, asma y enteritis infecciosa en niños.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (4,'P1-004','10.7705/biomedica.8068','2026-04-18','Malagón-Rojas, J. et al.','Health effects of wildfire PM2.5 in Latin American cities: A rapid systematic review and comparative synthesis',2025,'Biomédica','Revisión sistemática rápida y meta-análisis sobre PM2.5 de incendios forestales y su asociación con mortalidad y morbilidad en ciudades latinoamericanas (PubMed, Scopus, Bireme; 14 estudios incluidos de 163 identificados). La mayoría de estudios son de Brasil y usan series temporales o modelamiento; la exposición a WS-PM2.5 se asocia con incrementos de 1.7–7.7% en mortalidad por todas causas, cardiovascular y respiratoria por 10 µg/m³. La alta heterogeneidad (I²=88–95%) impide un meta-análisis formal. La evidencia es escasa fuera de Brasil y casi inexistente en la región andina; las poblaciones indígenas y rurales están ausentes. Señala la quema agrícola en los Andes altos de Perú y Bolivia como práctica estacional no estudiada epidemiológicamente.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (5,'P1-005','10.1001/jamahealthforum.2025.4632','2026-04-18','Casey J.A. et al.','The 2025 Los Angeles Wildfires and Outpatient Acute Health Care Utilization',2025,'JAMA Health Forum','Evalúa el impacto de los incendios de Los Ángeles de enero 2025 sobre la utilización de atención médica ambulatoria en 3.7 millones de afiliados de Kaiser Permanente Southern California. Clasifica la exposición por proximidad a zonas de quema (<20 km = alta, resto del condado = moderada) y usa un modelo de series temporales interrumpidas en dos etapas con machine learning (Prophet-XGBoost). Las visitas respiratorias virtuales fueron 42% mayores de lo esperado en el grupo altamente expuesto y 36% en el moderadamente expuesto; las visitas cardiovasculares virtuales aumentaron 44% y 40% respectivamente durante la semana posterior al inicio de los incendios.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (6,'P1-006','10.1088/1748-9326/ae10c9','2026-04-18','He H. et al.','Assessing PM2.5 pollution in the Northeastern United States from the 2023 Canadian wildfire smoke',2025,'Environmental Research Letters','Evalúa el impacto en calidad del aire y salud del episodio de humo de incendios canadienses del 6–8 de junio 2023 sobre el noreste de EE.UU., donde PM2.5 superó 100 µg/m³ en NYC y Philadelphia. Desarrolla un sistema de modelamiento WRF-CMAQ-BenMAP usando dos datasets de emisiones de incendios (CAMS y QFED) y dos drivers meteorológicos (FNL y NAM), mostrando buena correlación con observaciones (R²~0.6–0.7). Cuantifica la incertidumbre en simulaciones y valida el impacto en salud contra registros de visitas a urgencias por asma en Nueva York, encontrando aumentos de hasta 40% en visitas ED por asma en los condados más afectados.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (7,'P1-007','10.1093/aje/kwaf147','2026-04-18','Dey A.K. et al.','Two-stage interrupted time series analysis with machine learning: evaluating the health effects of the 2018 wildfire smoke event in San Francisco County',2025,'American Journal of Epidemiology','Este estudio presenta un método de series temporales interrumpidas en dos etapas con machine learning (ARIMA, NNETAR y Prophet-XGBoost) para evaluar el impacto del humo del incendio de 2018 en las hospitalizaciones respiratorias del condado de San Francisco. El modelo híbrido Prophet-XGBoost mostró el mejor rendimiento y se usó para estimar el escenario contrafactual. Se calculó que el evento causó 92 hospitalizaciones excesas (12.5% del total observado), demostrando la utilidad de este enfoque cuando no hay grupos de control disponibles.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (8,'P1-008','10.1021/acsestair.5c00033','2026-04-18','Faulstich, S. et al.','Modeling Daily Plume Specific Smoke Concentrations for Health Effects Studies with Estimates of Fire Size, Plume Age, and Fuel Type',2025,'American Chemical Society Environmental Science and Technology Air','Presenta un método para estimar concentraciones diarias de PM2.5 específicas de penacho de incendio en el oeste de EE.UU. (2007–2019), integrando características del fuego (tipo de combustible, tamaño, distancia) con un modelo de dispersión atmosférica y un modelo bayesiano de series temporales aplicado a monitores EPA. Permite evaluar la variación espacial de la exposición y el papel de los atributos del fuego; por ejemplo, Lindon (UT) tuvo 398 incendios con concentraciones modestas (~2 µg/m³) mientras Carson City (NV) tuvo menos incendios (177) pero exposiciones más intensas (~6 µg/m³, máx. 159 µg/m³). Subraya la importancia de vincular características del fuego con exposición diaria en estudios de salud. Destaca la necesidad de considerar el humo transportado a larga distancia en estrategias de manejo de incendios.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (9,'P1-009','10.1016/j.envint.2025.109577','2026-04-18','Riss, C. et al.','Influence of fire characteristics on the associations between smoke PM2.5 exposure and acute cardiorespiratory health events',2025,'Environment International','Analiza visitas a urgencias y cuidados urgentes en la región Reno/Sparks, Nevada (julio–septiembre 2012–2019) para evaluar asociaciones entre PM2.5 de humo de incendios y 11 grupos de desenlaces cardiorrespiratorios. Estima concentraciones diarias de PM2.5 por incendio específico combinando datos de monitores EPA, modelamiento de dispersión atmosférica, inventarios de emisiones y modelamiento bayesiano de series temporales; usa modelos de lag distribuido. Encuentra asociaciones positivas entre PM2.5 total de humo y exacerbación de asma (RR lag 0: 1.040), enfermedad cardiovascular (RR lag 3: 1.015) y disritmia cardíaca (RR lag 3: 1.029). Los incendios de alta intensidad se asocian más fuertemente con asma y trastornos respiratorios inespecíficos; los de baja intensidad con disritmia. Concluye que la intensidad y tipo de combustible del incendio influyen en los efectos de salud.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (10,'P1-010','10.1016/j.scitotenv.2025.179560','2026-04-18','Botezat, E. et al.','How air pollution affects cause-specific emergency hospital admissions on days with biomass combustion in Spain?',2025,'Science of the Total Environment','Analiza el impacto a corto plazo de NO₂, PM10, PM2.5, O₃ y temperatura en olas de calor sobre urgencias hospitalarias en 9 provincias españolas en días con combustión de biomasa (2013–2018), usando modelos GLM de Poisson con eliminación stepwise-backward para causas respiratorias, circulatorias y todas las causas. Los días con advección de humo de biomasa incrementan PM y O₃ pero no NO₂; el principal factor de impacto en ingresos es el O₃, seguido de NO₂, PM y temperatura. El papel del PM es relegado a tercer factor y el de la temperatura a un orden de magnitud menor. Concluye que focalizar los impactos de los incendios exclusivamente en PM subestima el impacto real, y señala la necesidad de planes integrados que consideren el efecto conjunto de todas las variables atmosféricas afectadas.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (11,'P1-011','10.1093/ofid/ofaf262','2026-04-18','McHale, T. et al.','Spatiotemporal Association of Coronavirus Disease 2019 Cases and Deaths With Exposure to Wildfire Particulate Matter in 2020',2025,'Open Forum Infectious Diseases','Evalúa la asociación entre exposición a PM2.5 de humo de incendios forestales y casos y muertes por COVID-19 en condados de California en 2020, usando un modelo autorregresivo espacial con ajuste por factores demográficos, ambientales y autocorrelación espacial. Encuentra un aumento de 203 casos de COVID-19 por 10,000 personas por 10 µg/m³ de humo con lag de 1 mes; y 2.75 muertes adicionales por 10,000 personas con el mismo lag. A 2 meses, las asociaciones se atenúan. Concluye que la exposición a humo de incendios probablemente aumentó la diseminación de COVID-19 y empeoró la mortalidad. El año 2020 fue excepcionalmente severo para incendios en California y único por la pandemia de COVID-19.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (12,'P1-012','10.1503/cmaj.241506','2026-04-18','Chen, H. et al.','Impact of the 2023 wildfire smoke episodes in Ontario, Canada, on asthma and other health outcomes: an interrupted time-series analysis',2025,'CMAJ. Canadian Medical Association Journal','Cuantifica el impacto agudo de dos episodios consecutivos de humo de incendios en Ontario, Canadá (junio 2023) sobre visitas a urgencias, usando análisis de series temporales interrumpidas y caso-cruzado con datos de vigilancia sindrómica. Las visitas por asma aumentaron hasta 23.6% (IC95%: 13.2%–34.9%) con lag de 1 día tras el primer episodio, manteniéndose elevadas hasta 5 días. El segundo episodio, pese a mayor exposición, tuvo efecto reducido (posible agotamiento de casos susceptibles). Los niños mostraron aumentos del 40% y los adultos del 48% (efecto más sostenido por 1 semana). No se detectaron efectos en otros desenlaces. Concluye que los incendios aumentaron sustancialmente las visitas por asma en Ontario y que la edad y el momento de exposición son factores moduladores clave.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (13,'P1-013','10.21664/2238-8869.2025v14i1p.157-169','2026-04-18','da Rocha, R. et al.','Association between Respiratory Illnesses and Fires in a Brazilian\'s Central-West Region Municipality: An Ecological Time Series Study',2025,'Fronteiras','Analiza los perfiles temporales de focos de humo detectados por satélite e ingresos hospitalarios por problemas respiratorios en niños de 1–4 años y adultos mayores de 65 años en Anápolis, Goiás, Brasil (2012–2021), usando un estudio ecológico de series temporales con bases públicas de INPE, IBGE y DATASUS. La prevalencia de incendios en Anápolis sigue el patrón estatal, con mayor incidencia entre julio y agosto. El período con más incendios y hospitalaciones respiratorias coincidió en septiembre de 2017. Encuentra una posible asociación positiva entre el aumento de hotspots satelitales y hospitalizaciones en ambos grupos de edad. Señala la necesidad de estudios más detallados en la zona para confirmar y explorar la relación.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (14,'P1-014','10.1016/s0140-6736(24)02251-7','2026-04-18','Xu, R. et al.','Global, regional, and national mortality burden attributable to air pollution from landscape fires: a health impact assessment study',2024,'The Lancet','Estima la carga de mortalidad global, regional y nacional atribuible a la contaminación del aire por incendios de paisaje (LFS) durante 2000–2019, usando datos de PM2.5 y O₃ validados y riesgos relativos de 2,267 comunidades en 59 países. Globalmente, 1.53 millones de muertes anuales son atribuibles a LFS, con 77.6% por PM2.5 y 22.4% por O₃; más del 90% en países de ingreso bajo y medio. El África subsahariana lidera con 606,769 muertes anuales. Las muertes cardiovasculares atribuibles muestran un incremento del 1.67%/año. En 2019, las tasas de mortalidad en países de bajos ingresos cuadruplicaron las de países de altos ingresos. Concluye que la contaminación por LFS genera una carga sustancial con marcadas desigualdades geográficas y socioeconómicas.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (15,'P1-015','10.1186/s12940-024-01079-x','2026-04-18','Sambodo, N. et al.','When the smoke gets in your lungs: short-term effects of Indonesia’s 2015 forest fires on health care use',2024,'Environmental Health','Estima el impacto a corto plazo de los incendios forestales de Indonesia en 2015 (los más contaminantes del siglo) sobre tasas de visita a atención primaria y hospitalaria, con foco en condiciones relacionadas con el humo (enfermedades respiratorias, IRAG, resfriado común), combinando datos satelitales de AOD con registros del seguro nacional de salud (BPJS Kesehatan) de 203 distritos en Sumatra y Kalimantan (enero 2015–abril 2016). Usa una adaptación del modelo de efectos fijos ANCOVA, comparando distritos afectados (AOD >0.75) vs. control (<0.75), estratificando por niños <5 años y adultos >5, áreas urbanas y rurales. Para niños pequeños, encuentra efectos positivos en visitas por problemas respiratorios en centros de salud urbanos; en áreas rurales, las visitas hospitalarias generales disminuyen negativamente (acceso restringido durante incendios). Concluye que la severidad de los incendios y la accesibilidad reducida en zonas rurales crean grandes brechas en atención esencial para niños.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (16,'P1-016','10.1134/s1875372824700574','2026-04-18','Efimova, N. et al.','Using Geoinformation Services to Make Operational Decisions to Minimize Health Risks to Populations in Areas of Wildfires',2024,'Geography and Natural Resources','Efimova et al. (2024) Desarrolla y prueba servicios de geoinformación para la toma de decisiones operacionales orientadas a reducir el riesgo de salud cuando el humo de incendios forestales afecta áreas pobladas en la región del Baikal, República de Buriatia, Rusia. Implementa modelos de análisis espacial en la plataforma JupyterHub, probado durante períodos de contaminación significativa por humo local y a larga distancia (1,000–2,500 km). Los resultados se presentan como mapas temáticos interactivos, gráficos y tablas actualizables. Un entorno digital permite carga rápida de datos primarios, cálculos y visualización de riesgos en mapas multicapa. En la región del Baikal, la probabilidad de síntomas respiratorios asociados a la contaminación fue 27.4% para CO y 6.7% para partículas totales.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (17,'P1-017','10.1136/jech-2024-222072','2026-04-18','Shirangi, A. et al.','Impact of elevated fine particulate matter (PM 2.5) during landscape fire events on cardiorespiratory hospital admissions in Perth, Western Australia',2024,'Journal of Epidemiology and Community Health','Estudio poblacional de series temporales para evaluar la asociación entre PM2.5 elevado de incendios de paisaje (resolución 1.5×1.5 km, modelo empírico modificado) e ingresos hospitalarios en Perth, Australia Occidental (2015–2017), usando regresiones de Poisson multivariadas con efectos de lag 0–3 días. Los ingresos por todas causas y cardiovasculares aumentaron significativamente con la mayor concentración de PM2.5 evaluada (≥12.60 µg/m³), con las asociaciones más fuertes en lag 1 (3% y 7% respectivamente). Para hospitalización por asma, el exceso de riesgo relativo fue hasta 16% el mismo día para toda la población, 93% en niños con lag 1 y 52% en grupos socioeconómicamente desfavorecidos con lag 3. También se observaron incrementos en arritmias (12%) y riesgos muy elevados en angina e insuficiencia cardíaca en grupos desaventajados.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (18,'P1-018','10.1093/ije/dyae102','2026-04-18','Tajudin, M. et al.','Short-term associations of PM10 attributed to biomass burning with respiratory and cardiovascular hospital admissions in Peninsular Malaysia',2024,'International Journal of Epidemiology','Estima la asociación a corto plazo entre PM10 atribuible a quema de biomasa e ingresos hospitalarios respiratorios y cardiovasculares en cinco distritos de Malasia Peninsular (2005–2015), usando modelos de series temporales quasi-Poisson con pooling por meta-análisis, ajustando por confusores y examinando efectos por edad y sexo. Casi el 50% de los días fueron identificados como días de quema de biomasa, con PM10 promedio de 53.1 µg/m³ vs. 40.1 µg/m³ en días normales. Un incremento de 10 µg/m³ en PM10 de quema de biomasa se asoció con un aumento del 0.44% en ingresos respiratorios en lag 0–1, con asociaciones más fuertes en adultos de 15–64 años y mujeres. No se observaron asociaciones significativas para ingresos cardiovasculares. Sugiere que la exposición a corto plazo a PM10 de quema de biomasa aumenta el riesgo de hospitalizaciones respiratorias.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (19,'P1-019','10.1016/j.apr.2024.102159','2026-04-18','Vongruang, P. et al.','Assessing the impact of air pollution on short-term hospital visits for respiratory diseases in Lampang, a city heavily affected by biomass burning in Mainland Southeast Asia: Sex and age considerations',2024,'Atmospheric Pollution Research','Analiza el impacto de la contaminación del aire sobre visitas hospitalarias a corto plazo por enfermedades respiratorias en Lampang, Tailandia (enero 2014–diciembre 2017), ciudad severamente afectada por quema de biomasa (97% del PM10 proviene de quema de biomasa), usando modelos GLM con distribución de Poisson y diferentes tiempos de lag, estratificados por grupos de edad (0–14, 15–64, ≥65 años) y género. Las excedencias de guías OMS para PM10 (32%) y O₃ (29%) son frecuentes; la incidencia de enfermedades respiratorias es de 7,276.61 por 100,000 habitantes. Un incremento de 10 µg/m³ en PM10 y O₃ se asocia con aumentos estadísticamente significativos del 0.65% y 0.72% respectivamente en lag 0 para enfermedades respiratorias. Los adultos mayores masculinos son el grupo más afectado por PM10; el mayor impacto de O₃ se observa en adultos mayores masculinos y mujeres adultas.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (20,'P1-020','10.1016/s2542-5196(24)00117-7','2026-04-18','Chen, G. et al.','All-cause, cardiovascular, and respiratory mortality and wildfire-related ozone: a multicountry two-stage time series analysis',2024,'The Lancet Planetary Health','Realiza un análisis de series temporales multicountry en dos etapas para evaluar las asociaciones entre exposición a corto plazo a O₃ relacionado con incendios forestales y mortalidad diaria por todas causas, cardiovascular y respiratoria, usando datos de 749 localidades en 43 países (2000–2016) y estimaciones de O₃ de un modelo de transporte químico. Un incremento de 1 µg/m³ en O₃ relacionado con incendios (promedio lag 0–2 días) se asoció con aumentos del 0.55% en mortalidad por todas causas, 0.44% cardiovascular y 0.82% respiratoria. Las concentraciones máximas de O₃ ≥30 µg/m³ se observaron principalmente en América del Sur y Central, Sudeste Asiático y Sudáfrica. Las fracciones de mortalidad en exceso anuales atribuibles a O₃ de incendios fueron 0.58% (todas causas), 0.41% (cardiovascular) y 0.86% (respiratoria). Señala heterogeneidad geográfica sustancial.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (21,'P1-021','10.1016/j.scitotenv.2023.168134','2026-04-18','Jiao, A. et al.','Associations between short-term exposure to wildfire particulate matter and respiratory outcomes: A systematic review',2024,'Science of The Total Environment','Revisión sistemática (PubMed, Web of Science, Scopus, EMBASE; 2000–2022; 35 artículos incluidos de 3,196 identificados) sobre asociaciones a corto plazo entre PM2.5 específico de incendios forestales y desenlaces respiratorios, comparando efectos del PM2.5 de incendios vs. PM2.5 de todas las fuentes o no-incendio. La mayoría de estudios se enfocaron en visitas a urgencias u hospitalizaciones respiratorias con diseños de series temporales o caso-cruzado, concentrándose en EE.UU., Canadá y Australia. Se observaron asociaciones positivas con morbilidad respiratoria en la mayoría de estudios. El asma y la EPOC fueron los más estudiados, ambos afectados adversamente. Las mujeres podrían ser más vulnerables al impacto respiratorio del PM de incendios. Identifica brechas en estudios de mortalidad y efectos por componentes específicos del PM.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (22,'P1-022','10.1016/s2542-5196(23)00251-6','2026-04-18','Curto, A. et al.','Associations between landscape fires and child morbidity in southern Mozambique: a time-series study',2024,'The Lancet Planetary Health','Analiza la asociación entre humo de incendios de paisaje (PM2.5 de origen en fuego) y visitas e ingresos hospitalarios en niños (≤15 años) en el distrito de Manhiça, Mozambique (2012–2020), usando modelos quasi-Poisson con lags específicos y control por estacionalidad, tendencia, temperatura y lluvia. Un incremento de 10 µg/m³ en PM2.5 de incendio se asoció con un aumento del 6.12% en visitas hospitalarias por todas causas y del 12.43% por causas respiratorias el día siguiente (lag 1). Los incendios de bosque son más frecuentes, pero las asociaciones con morbilidad infantil fueron más fuertes para incendios en tierras de cultivo que en bosques. No se observaron asociaciones significativas para ingresos hospitalarios. Señala la necesidad de mejor evaluación de la exposición en regiones con escaso monitoreo de calidad del aire.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (23,'P1-023','10.1016/j.envres.2023.117154','2026-04-18','Chen, A. et al.','Emergency department visits associated with wildfire smoke events in California, 2016–2019',2023,'Environmental Research','Examina asociaciones entre episodios de humo de incendios forestales y visitas a urgencias por causas respiratorias, cardiovasculares, de diabetes y salud mental en California (junio–diciembre 2016–2019), usando concentraciones diarias de PM2.5 específico de incendios por área de cuenca aérea y análisis de series temporales quasi-Poisson en dos etapas con meta-análisis de efectos aleatorios. Los episodios de humo se asociaron con mayor riesgo de visitas respiratorias en lag 1 (14.4%), asma en lag 0 (57.1%) y enfermedad respiratoria crónica en lag 0 (12.7%). También se observaron asociaciones positivas con enfermedades cardiovasculares en lag 10. Los resultados estratificados revelaron disparidades potenciales por raza/etnia. Los impactos cardiovasculares parecen ser más tardíos que los respiratorios.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (24,'P1-24','10.1007/s11882-023-01090-1','2026-04-18','Noah, T. et al.','The Effects of Wildfire Smoke on Asthma and Allergy',2023,'Current Allergy and Asthma Reports','Revisa la literatura reciente sobre efectos del humo de incendios forestales (WFS) en asma y enfermedades alérgicas, y sobre posibles mecanismos de enfermedad. El modelamiento espacio-temporal y el mayor monitoreo terrestre están permitiendo una imagen más detallada de los efectos del WFS, especialmente en asma. Hay evidencia epidemiológica y experimental de que el WFS aumenta la predisposición alérgica y las enfermedades de las vías aéreas superiores, aunque gran parte de la literatura usa PM2.5 general, no específico de incendios. Los modelos experimentales sugieren disrupción de la integridad epitelial con efectos cascada en vías inflamatorias e inmunes, pero no han replicado consistentemente la enfermedad humana. Concluye que la exposición a WFS tiene un efecto agudo deletéreo en el asma.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (25,'P1-025','10.1016/j.envres.2023.115591','2026-04-18','Martenies, S. et al.','The COVID-19-wildfire smoke paradox: Reduced risk of all-cause mortality due to wildfire smoke in Colorado during the first year of the COVID-19 pandemic',2023,'Environmental Research','Evalúa cómo difirió el riesgo diario de mortalidad asociado al humo de incendios forestales (WFS) entre períodos antes y durante la pandemia de COVID-19, usando datos de 11 condados del Front Range de Colorado (2010–2020) con modelos aditivos generalizados ajustados por múltiples covariables. El WFS afectó el 10% de los días-condado; antes de la pandemia se observó asociación positiva entre presencia de WFS y mortalidad por todas causas (IRR=1.03). Durante la pandemia, la exposición a WFS resultó en riesgo reducido (IRR=0.90). Hipotetiza que las medidas de mitigación pandémica (uso de mascarillas) y los altos niveles de humo motivaron comportamientos protectores que redujeron la exposición a WFS y la mortalidad por todas causas. Sugiere lecciones de la pandemia aplicables a futuras políticas de protección durante incendios.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (26,'P1-026','10.1016/j.envint.2023.107906','2026-04-18','Wu, Y. et al.','Wildfire-related PM2.5 and health economic loss of mortality in Brazil',2023,'Environment International','Cuantifica las pérdidas económicas en salud por mortalidad atribuible a PM2.5 de incendios forestales en 510 regiones inmediatas de Brasil (2000–2016), usando GEOS-Chem con GFED más machine learning para estimar PM2.5 a resolución 0.25°×0.25° y un diseño de series temporales en dos etapas con meta-análisis de efectos aleatorios. Las pérdidas económicas totales atribuibles a PM2.5 de incendios fueron US$81.08 mil millones (US$5.07 mil millones/año), equivalentes al 0.14% del PIB de Brasil. La fracción atribuible de pérdidas económicas se asocia positivamente con la proporción del PIB agrícola y negativamente con la del sector servicios. Concluye que las pérdidas económicas sustanciales por incendios podrían usarse para determinar niveles óptimos de inversión en mitigación de sus impactos.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (27,'P1-027','10.1016/j.scitotenv.2022.159548','2026-04-18','Jiang, X. et al.','The impact of fire-specific PM2.5 calibration on health effect analyses',2023,'Science of the Total Environment','Propone una estrategia de calibración en dos etapas para mejorar la precisión de estimaciones de PM2.5 específico de incendios (quemas prescritas e incendios forestales) derivadas del modelo CMAQ, que presenta sesgos sistemáticos. En la primera etapa calibra PM2.5 no-incendio de CMAQ con observaciones terrestres usando un modelo ensemble; en la segunda multiplica por ratios de conversión específicos por localización y tiempo. Aplicado a la temporada de incendios de Washington 2016, el PM2.5 calibrado mejoró la concordancia con observaciones (R² 0.79 vs. 0.12 no calibrado). En el análisis de efectos en salud, el PM2.5 calibrado mostró asociaciones significativas con hospitalizaciones cardiorrespiratorias (RR respiratorio 1.078 en octubre); el no calibrado dio resultados inconsistentes. Subraya que la calibración afecta materialmente las evaluaciones de impacto en salud.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (28,'P1-028','10.1590/0102-311xpt238422','2026-04-18','Domingues, R. et al.','Burning of sugarcane biomass and hospitalizations of children and older adults for respiratory problems in Pernambuco State, Brazil',2023,'Cadernos de Saude Publica','Analiza la relación entre hospitalizaciones por enfermedades respiratorias y la quema regular de caña de azúcar en municipios productores vs. no productores de Pernambuco, Brasil (2008–2018), comparando tasas en niños <5 años y adultos >60 años mediante Mann-Whitney y correlación de Pearson entre hotspots satelitales y hospitalizaciones mensuales. Las tasas de hospitalización son mayores en municipios productores de caña, con diferencias estadísticamente significativas; adultos mayores presentan tasas 28% más altas y niños <5 años con ratio de medianas del 40%. Sin embargo, el comportamiento estacional de las hospitalizaciones difiere del de los hotspots, sin correlación temporal significativa. Sugiere asociación con exposición crónica a partículas de quema de biomasa más que con exposición aguda episódica. Respalda la necesidad de reemplazar la quema en el monocultivo de caña.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (29,'P1-029','10.1038/s41467-022-35326-x','2026-04-18','Ye, T. et al.','Short-term exposure to wildfire-related PM2.5 increases mortality risks and burdens in Brazil',2022,'Nature Communications','Evalúa los riesgos y cargas de mortalidad asociados con la exposición a corto plazo a PM2.5 de incendios forestales en 510 regiones de Brasil (2000–2016), integrando múltiples fuentes de datos con GEOS-Chem a resolución 0.25° y usando un modelo de series temporales en dos etapas. Un incremento de 10 µg/m³ en PM2.5 de incendios se asoció con aumentos del 3.1% en mortalidad por todas causas, 2.6% cardiovascular y 7.7% respiratoria (lag 0–14 días). El 0.65% de muertes por todas causas, 0.56% cardiovascular y 1.60% respiratoria son atribuibles a PM2.5 de incendios, correspondiendo a ~121,351, 29,510 y 31,287 muertes durante el período de estudio. Las asociaciones son más fuertes en mujeres y adultos ≥60 años, con diferencias geográficas notables. Destaca la urgencia de acciones para reducir la exposición al humo, especialmente en poblaciones más susceptibles.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (30,'P1-030','10.1007/s13762-022-03923-4','2026-04-18','Arifin, B. et al.','How palm oil industry is having a devastating impact on Indonesia\'s health, rainforests, and labor market',2022,'International Journal of Environmental Science and Technology','Estima el impacto de empresas palmicultoras sobre incendios forestales, contaminación del aire, desenlaces de salud y el mercado laboral en Indonesia, usando datos de la Encuesta Nacional Socioeconómica (SUSENAS), datos de seguro de salud (BPJS) y estadísticas del Ministerio de Medio Ambiente, con métodos de mínimos cuadrados ordinarios (OLS) y emparejamiento estadístico. Las empresas palmicultoras aumentan significativamente el área quemada; también incrementan la probabilidad de asma, los ingresos hospitalarios y disminuyen sustancialmente la decisión de trabajar. Los impactos negativos en salud son mayores en niños y adultos mayores. Los incendios forestales aumentan los ingresos hospitalarios tanto para asmáticos como para personas con síntomas respiratorios generales. Señala que las empresas palmicultoras tienen incentivos para quemar bosques para aclarear tierras, generando incendios y contaminación.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (31,'P1-031','10.3390/ijerph19095057','2026-04-18','Ademu, L. et al.','Impact of Short-Term Air Pollution on Respiratory Infections: A Time-Series Analysis of COVID-19 Cases in California during the 2020 Wildfire Season',2022,'International Journal of Environmental Research and Public Health','Analiza cuantitativamente el efecto a corto plazo de la contaminación del aire sobre la transmisión de COVID-19 usando datos a nivel de condado recopilados durante la temporada de incendios de California de 2020, mediante metodología de series temporales. Evaluó la relación entre exposición a corto plazo a PM2.5, CO, NO₂ y el índice de calidad del aire (AQI) con casos confirmados de COVID-19 en 20 condados afectados por incendios. Los resultados indican que PM2.5, CO y AQI se asocian positivamente con casos confirmados de COVID-19, sugiriendo que mayor contaminación del aire podría empeorar una crisis sanitaria como la pandemia. Recomienda políticas adaptadas para situaciones que aumenten la contaminación del aire, especialmente durante temporadas de incendios.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (32,'P1-032','10.1093/ije/dyac005','2026-04-18','Uttajug, A. et al.','Effect of a vegetation fire event ban on hospital visits for respiratory diseases in Upper Northern Thailand',2022,'International Journal of Epidemiology','Evalúa el efecto de una prohibición de quema de vegetación implementada en mayo de 2016 sobre las visitas hospitalarias por enfermedades respiratorias en el norte de Tailandia, usando datos de ocho provincias y análisis de series temporales interrumpidas controlado por tendencias temporales estacionales, día de semana, feriados, temperatura, humedad relativa, número de hospitales y población, con enfermedades gastrointestinales como control negativo. La concentración diaria promedio de PM10 y los hotspots satelitales disminuyeron tras la prohibición en todas las provincias (cambios del 5.3–34.3% y 14.3–81.5% respectivamente). Las visitas hospitalarias por enfermedades respiratorias disminuyeron un 9.1% (IC95%: 5.1, 12.9%) con la prohibición, sin asociación para enfermedades gastrointestinales. Concluye que la prohibición de quema tuvo impacto positivo tanto en los niveles de contaminación como en las tasas de visitas hospitalarias respiratorias.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (33,'P1-033','10.1093/ije/dyab206','2026-04-18','Mahsin, M. et al.','Respiratory and cardiovascular condition-related physician visits associated with wildfire smoke exposure in Calgary, Canada, in 2015: A population-based study',2022,'International Journal of Epidemiology','Estudia el impacto de la exposición a PM2.5 de un evento de incendio forestal remoto en el Pacífico Noroeste sobre visitas ambulatorias respiratorias y cardiovasculares en Calgary, Canadá, durante el período de incendio (24–31 agosto 2015) y post-incendio (1–30 septiembre 2015) vs. pre-incendio (1–23 agosto 2015), usando regresión quasi-Poisson ajustada por día de semana, humedad relativa, viento y metano. Se observó riesgo elevado de morbilidad respiratoria del 33% durante el incendio y 55% después, por incremento de 10 µg/m³ en PM2.5; mayor riesgo en niños de 0–9 años (RR=1.57 durante; RR=2.11 post-incendio), especialmente asma, bronquitis aguda e infección respiratoria aguda. En adultos mayores, el riesgo de visitas por insuficiencia cardíaca congestiva y enfermedad isquémica del corazón aumentó 11–19% en el período post-incendio. Las personas con diabetes preexistente mostraron mayor riesgo de morbilidad tanto respiratoria como cardiovascular post-incendio.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (34,'P1-034','10.1016/j.lana.2021.100102','2026-04-18','Schroeder, L. et al.','Fire association with respiratory disease and COVID-19 complications in the State of Pará, Brazil',2022,'The Lancet Regional Health - Americas','Evalúa la asociación entre ocurrencias de incendios forestales, tasas de mortalidad por COVID-19 y hospitalizaciones por enfermedades respiratorias generales en el estado de Pará, Brasil (2015–2020), usando k-means para identificar clusters de ciudades con alta y baja exposición a fuegos, seguido de un modelo ARIMAX para analizar la correlación serial de hospitalizaciones respiratorias con ocurrencias de fuego. Los clusters con alta exposición a incendios muestran que, además de la correlación serial, los incendios contribuyen al aumento de enfermedades respiratorias, con un lag observado de seis meses para el cluster de alta exposición. Históricamente, el riesgo de mortalidad respiratoria es el doble en regiones con alta vs. baja exposición a incendios. El mismo patrón se mantuvo durante la pandemia de COVID-19: el riesgo de mortalidad por COVID-19 fue 80% mayor en la región con alta exposición a incendios. Concluye que las ocurrencias de incendios se asocian con mayor mortalidad y hospitalizaciones respiratorias, incluyendo COVID-19.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (35,'P1-035','10.1513/annalsats.202103-252oc','2026-04-18','Rahman, M. et al.','Respiratory Emergency Department Visit Associations with Exposures to Fine Particulate Matter Mass, Constituents, and Sources in Dhaka, Bangladesh Air Pollution',2022,'Annals of the American Thoracic Society','Evalúa las asociaciones entre PM2.5 ambiente y visitas a urgencias respiratorias en Dhaka, Bangladesh (enero 2014–diciembre 2017), una región dominada por quema de biomasa y alta contaminación, usando regresión de series temporales con ajuste por tendencia, estacionalidad, día de semana, feriados, humedad relativa y temperatura, estratificando por estación, edad y sexo. Un incremento de 10 µg/m³ en PM2.5 se asoció con un aumento del 0.84% en visitas a urgencias respiratorias; el efecto fue mayor durante la temporada de monzón, cuando dominan fuentes de combustión fósil. El PM2.5 de combustión fósil mostró mayor efecto (2.79%) que el de quema de biomasa (1.27%) u otras fuentes (0.95%). Niños y adultos mayores fueron desproporcionadamente afectados, especialmente por partículas de combustión. Provee evidencia novedosa de efectos respiratorios específicos por fuente en un contexto de alta contaminación del Sur de Asia.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (36,'P1-036','10.1088/1748-9326/ac4138','2026-04-18','Stowell, J. et al.','Asthma exacerbation due to climate change-induced wildfire smoke in the Western US',2022,'Environmental Research Letters','Estima el aumento futuro de visitas a urgencias y hospitalizaciones por asma atribuibles al incremento de PM2.5 de humo de incendios en el oeste de EE.UU. en la década de 2050, usando proyecciones climáticas downscaleadas dinámicamente con el escenario ICLUS A2 y concentraciones de PM2.5 de humo estimadas con modelamiento sofisticado. Los incrementos promedio en PM2.5 de humo durante la temporada de incendios oscilaron entre 0.05 y 9.5 µg/m³, con los mayores aumentos en Idaho, Montana y Oregon. Se estima que los eventos de asma relacionados con humo podrían aumentar a una tasa de 15.1 visitas por 10,000 personas en el oeste de EE.UU., con las mayores tasas (25.7–41.9 por 10,000) en Idaho, Montana, Oregon y Washington. Los costos de salud por asma inducida por humo se estiman en más de US$1.5 mil millones durante una sola temporada de incendios futura.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (37,'P1-037','10.3390/atmos13010058','2026-04-18','Ciciretti, R. et al.','Relationship between Wildfire Smoke and Children’s Respiratory Health in the Metropolitan Cities of Central-Chile',2022,'Atmosphere','Caracteriza la relación entre la ocurrencia de incendios forestales en Chile central y los efectos sobre la salud respiratoria de niños, usando bases de datos públicas de visitas de urgencia, incendios y contaminantes del aire de las regiones Metropolitana y Valparaíso (2010–2013), con análisis de series temporales mensual. En Santiago, se observaron riesgos de salud significativos en niños <1 año para bronquitis (RR 1.007), enfermedades respiratorias crónicas bajas (RR 1.012) y neumonía (RR 1.026), y en niños de 1–4 años (RR 1.016). También se observó una relación dosis-respuesta para neumonía, afectando más a niños pequeños con mayor número de incendios. En Valparaíso, los incendios no cambiaron significativamente el riesgo de enfermedades respiratorias, posiblemente por mejor ventilación. Destaca la urgencia de monitoreo y estrategias de prevención para proteger la salud respiratoria infantil en Santiago.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (38,'P1-038','10.1038/s41467-021-26822-7','2026-04-18','Requia, W. et al.','Health impacts of wildfire-related air pollution in Brazil: a nationwide study of more than 2 million hospital admissions between 2008 and 2018',2021,'Nature Communications','Cuantifica los impactos del PM2.5 de incendios forestales sobre más de 2 millones de registros de ingresos hospitalarios por enfermedades cardiorrespiratorias en Brasil (2008–2018), clasificando oleadas de incendios con datos de FIRMS/MODIS y estimando concentraciones de PM2.5 de incendios con datos grillados de GEOS-Chem. A nivel nacional, las oleadas de incendios se asocian con un aumento del 23% (IC95%: 12%–33%) en ingresos hospitalarios respiratorios y del 21% (8%–35%) en ingresos circulatorios. En la región Norte (donde se ubica la mayor parte del Amazonas), los aumentos son del 38% para ingresos respiratorios y 27% para circulatorios. Proporciona evidencia epidemiológica de que la contaminación del aire por incendios forestales se asocia significativamente con mayor riesgo de ingresos cardiorrespiratorios, con mayor impacto en la región amazónica.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (39,'P1-039','10.1016/s2542-5196(21)00173-x','2026-04-18','Ye, T. et al.','Risk and burden of hospital admissions associated with wildfire-related PM2·5 in Brazil, 2000–15: a nationwide time-series study',2021,'The Lancet Planetary Health','Estima la asociación entre la exposición diaria a PM2.5 de incendios forestales y los ingresos hospitalarios por causa específica, y la carga atribuible de salud en Brasil (2000–2015), con datos de 1,814 municipios del SIH/SUS, concentraciones de PM2.5 de incendios de GEOS-Chem (resolución 2°×2.5°) y análisis en dos etapas con quasi-Poisson pooled por meta-análisis de efectos aleatorios. Un incremento de 10 µg/m³ en PM2.5 de incendios se asoció con aumentos del 1.65% en ingresos por todas causas, 5.09% por causas respiratorias y 1.10% por causas cardiovasculares en los 0–1 días tras la exposición. Los efectos son especialmente altos en niños ≤4 años (4.88%) y personas ≥80 años (3.70%). El 0.53% de todos los ingresos por todas causas son atribuibles al PM2.5 de incendios, equivalente a 35 casos por 100,000 residentes anuales. Los municipios del norte, sur y centro-oeste presentan las tasas atribuibles más altas.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (40,'P1-040','10.1016/s2542-5196(21)00200-x','2026-04-18','Chen, G. et al.','Mortality risk attributable to wildfire-related PM2·5 pollution: a global time series study in 749 locations',2021,'The Lancet Planetary Health','Realiza un estudio de series temporales global en 749 ciudades de 43 países (2000–2016) para evaluar la asociación entre la exposición a corto plazo a PM2.5 de incendios forestales (estimado con GEOS-Chem a resolución 0.25°×0.25°) y la mortalidad por todas causas, cardiovascular y respiratoria, usando modelos quasi-Poisson y meta-análisis de efectos aleatorios. Los RR de mortalidad asociados con cada incremento de 10 µg/m³ en el promedio de 3 días de PM2.5 de incendios fueron 1.019 (todas causas), 1.017 (cardiovascular) y 1.019 (respiratoria). El 0.62% de muertes por todas causas, 0.55% cardiovascular y 0.64% respiratoria son anualmente atribuibles a la exposición aguda a PM2.5 de incendios. Destaca que la exposición a corto plazo a PM2.5 de incendios forestales aumentó el riesgo de mortalidad, con variación geográfica regional y necesidad de acción urgente para reducir los riesgos de salud por incendios crecientes.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (41,'P1-041','10.1088/1755-1315/717/1/012036','2026-04-18','Purnomo, E. et al.','Observed Data of Forest Fire Hotspots effects on Respiratory Disorder by Arc-GIS in Riau Province, Indonesia',2021,NULL,'Demuestra que los aspectos de calidad del aire derivados de incendios forestales en Indonesia se asocian con una amplia gama de desenlaces adversos de salud, incluyendo problemas respiratorios, usando software GIS para crear zonas en la provincia de Riau, Indonesia. Los datos muestran que el mayor hotspot de incendios fue en 2015 (12,854) y el menor en 2017 (527), siendo también el año 2017 el de menor número de casos de trastornos respiratorios (371,044). Los hallazgos evidencian que el humo tiene un efecto negativo significativo en el aumento de problemas respiratorios. Señala que las predicciones de humo y neblina son herramientas efectivas aunque desafiantes para desarrollar, útiles como predicciones de salud pública y para formular políticas adecuadas, pero sus incertidumbres inherentes limitan su adopción generalizada.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (42,'P1-042','10.1097/ee9.0000000000000124','2026-04-18','Casey, J. et al.','Wildfire particulate matter in Shasta County, California and respiratory and circulatory disease-related emergency department visits and mortality, 2013-2018',2021,'Environmental Epidemiology','Evalúa los efectos del Carr Fire de 2018 y temporadas de incendios previas en el condado de Shasta, California, sobre visitas a urgencias y mortalidad por enfermedades respiratorias y circulatorias (2013–2018), usando estimaciones espacio-temporales de PM2.5 de incendio por imputación múltiple e imputación y modelos de series temporales controlados por tendencia temporal y temperatura. En todos los ZCTAs del condado, no se detectó asociación entre PM2.5 alto de incendio y visitas ED o mortalidad. En los ZCTAs de valle (más bajos, con peor calidad del aire general), el PM2.5 alto de incendio se asoció con un aumento del 14.6% en visitas ED respiratorias en la misma semana. El Carr Fire pareció aumentar las visitas ED respiratorias en un 27% sobre lo esperado. Concluye que los estudios de impacto deben continuar evaluando los efectos de los incendios en poblaciones altamente expuestas.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (43,'P1-043','10.1080/09603123.2019.1673883','2026-04-18','Pothirat, C. et al.','The short-term associations of particular matters on non-accidental mortality and causes of death in Chiang Mai, Thailand: a time series analysis study between 2016-2018',2021,'International Journal of Environmental Health Research','Determina la asociación entre incrementos diarios de PM10 y PM2.5 con mortalidad no accidental diaria y causas de muerte en Chiang Mai, Tailandia (2016–2018), donde las quemas abiertas, agrícolas y forestales son las principales fuentes de partículas durante la estación seca, usando modelos lineales generalizados con distribución de Poisson. PM10 y PM2.5 se asociaron con mortalidad no accidental diaria en diferentes días de lag (RR ajustado de 1.009–1.018 por cada 10 µg/m³ de incremento en PM10 y 1.016 para PM2.5). Las causas de muerte asociadas con PM10 y PM2.5 en diferentes lags fueron EPOC, enfermedad coronaria y sepsis. Concluye que PM10 y PM2.5 se asocian con mortalidad no accidental diaria, siendo las principales causas de muerte EPOC, enfermedad coronaria y sepsis.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (44,'P1-044','10.1186/s12940-020-00646-2','2026-04-18','Kiser, D. et al.','Particulate matter and emergency visits for asthma: A time-series study of their association in the presence and absence of wildfire smoke in Reno, Nevada, 2013-2018',2020,'Environmental Health: A Global Access Science Source','Cuantifica la diferencia en la asociación de PM2.5, PM10-2.5 y PM10 con visitas por asma en Reno, Nevada (2013–2018), entre días con y sin presencia de humo de incendios forestales, usando modelos aditivos generalizados ajustados por factores confusores, con exclusión de días de humo con PM sobre el máximo observado en días sin humo para controlar posible no linealidad. La calidad del aire fue afectada por humo de incendios 188 días entre 2013 y 2018. La presencia de humo de incendios aumentó la asociación de un incremento de 5 µg/m³ en PM2.5 con visitas por asma en 6.1% (promedio diario) y 6.8% (promedio de tres días). Similarmente, la presencia de humo aumentó la asociación de PM10 con visitas por asma en 5.5% y 7.2% para promedios diarios y de tres días, respectivamente. Concluye que el PM de incendios es más peligroso que el PM de otras fuentes para pacientes con asma.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (45,'P1-045','10.1186/s12940-020-00629-3','2026-04-18','Mueller, W. et al.','Ambient particulate matter and biomass burning: An ecological time series study of respiratory and cardiovascular hospital visits in northern Thailand',2020,'Environmental Health: A Global Access Science Source','Recopila datos de contaminantes del aire ambiente (PM10, PM2.5, CO, O₃, NO₂) de monitores terrestres y visitas ambulatorias hospitalarias diarias en Tailandia (2014–2017) para realizar un análisis ecológico de series temporales sobre enfermedades respiratorias crónicas, cardiopatía isquémica y enfermedad cerebrovascular, identificando días de quema de biomasa por percentiles 90 y 95 de PM10. Hubo variación intraanual significativa en PM10, con concentraciones más altas en marzo, coincidiendo con el pico de quema de biomasa. Los IRR entre PM10 diario y visitas por EPOC (IRR=1.020) y enfermedad cerebrovascular (IRR=1.020) fueron más elevados el mismo día de exposición; no se observó asociación significativa con cardiopatía isquémica. Ajustar por CO tendía a aumentar las estimaciones de efecto. No encontró evidencia de relación exposición-respuesta con PM10 en días de quema de biomasa.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (46,'P1-046','10.1513/annalsats.201902-150oc','2026-04-18','Leibel, S. et al.','Increase in pediatric respiratory visits associated with Santa ana wind–driven wildfire smoke and PM2.5 levels in San Diego County',2020,'Annals of the American Thoracic Society','Cuantifica y examina los efectos del Incendio Lilac (diciembre 2017) en San Diego County sobre la utilización de atención de salud pediátrica en el Rady Children\'s Hospital (2011–2017), usando series temporales interrumpidas como análisis principal para comparar las visitas respiratorias observadas vs. el contrafactual, complementado con análisis espacial descriptivo de la distribución geográfica de visitas en relación al perímetro del incendio y el patrón de vientos Santa Ana. El incendio se asoció con 16.0 visitas respiratorias excesas por día en urgencias; los niños de 0–5 años tuvieron la mayor cantidad absoluta de exceso y los de 6–12 años el mayor incremento relativo. Los cinco ZCTAs con mayor desviación estándar de visitas ajustadas por edad estaban ubicados en dirección del viento del incendio. Concluye que los incendios impulsados por vientos SAW afectan la salud pediátrica en una distribución geográfica predecible por el patrón de viento.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (47,'P1-047','10.1016/j.atmosenv.2019.117029','2026-04-18','Ebisu, K. et al.','Age-specific seasonal associations between acute exposure to PM2.5 sources and cardiorespiratory hospital admissions in California',2019,'Atmospheric Environment','Explora las asociaciones entre exposición a corto plazo a constituyentes químicos y fuentes de PM2.5, y los ingresos hospitalarios cardiovasculares y respiratorios en California (2002–2009), integrando datos de 1,679,094 ingresos con datos de especiación química y estimaciones de PM2.5 por fuente en ocho sitios usando Factorización de Matriz Positiva, con regresión de Poisson de series temporales estratificada por edad y modelos de interacción estacional. Las cinco fuentes comúnmente identificadas fueron quema de biomasa, suelo, nitrato de amonio secundario, sulfato de amonio secundario y emisiones vehiculares. Un incremento en emisiones vehiculares se asoció con mayor riesgo de ingresos cardiovasculares en adultos mayores (1.32%) y respiratorios en niños (3.58% en lag 2). Los estimados de riesgo para PM2.5 total y emisiones vehiculares en ingresos respiratorios fueron más altos en temporada cálida en niños. Las fuentes más tóxicas varían por grupo etario y estación, lo que tiene implicaciones para intervenciones específicas.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (48,'P1-048','10.1021/acs.est.9b02660','2026-04-18','Jiang, X. et al.','Modeling Wildland Fire-Specific PM2.5 Concentrations for Uncertainty-Aware Health Impact Assessments',2019,'Environmental Science and Technology','Desarrolla una estrategia de calibración en dos pasos bajo consideración de incertidumbres de predicción para PM2.5 específico de incendios forestales con el modelo CMAQ, aplicada en el este de EE.UU. en 2014, evaluando el rendimiento de calibración con tres métodos de validación cruzada y realizando un análisis de impacto en salud basado en las predicciones calibradas. La estrategia consistente en ajustar las salidas de CMAQ con observaciones terrestres no-incendio y luego estimar el componente específico de incendio mejoró consistentemente la precisión de predicción (R² de 0.47–0.64 en validación cruzada). El análisis de impacto en salud identificó regiones con exceso de ingresos hospitalarios respiratorios por eventos de incendios, cuantificando la incertidumbre propagada desde múltiples componentes de la función de impacto. Concluye que el enfoque de calibración proporciona estimaciones confiables de PM2.5 específico de incendios y cargas de salud para apoyar el desarrollo de políticas.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (49,'P1-049','10.1590/1414-431x20188130','2026-04-18','Machin, A. et al.','Effects of exposure to fine particulate matter in elderly hospitalizations due to respiratory diseases in the South of the Brazilian Amazon',2019,'Brazilian Journal of Medical and Biological Research','Desarrolla un estudio ecológico de series temporales sobre los datos de hospitalizaciones por enfermedades respiratorias en personas mayores de 60 años residentes en Cuiabá, Brasil (2012), integrando concentraciones de PM2.5 y CO estimadas por modelamiento matemático, temperatura mínima, humedad relativa e incendios forestales, usando el modelo de regresión lineal generalizado de Poisson con lags de 0 a 7 días. En 2012 se evaluaron 591 hospitalizaciones, con concentración promedio de PM2.5 de 15.7 µg/m³ y CO de 144.2 ppb. Se observaron asociaciones significativas entre la exposición a estos contaminantes y las hospitalizaciones en lags 3 y 4. Un incremento de 3.5 µg/m³ de PM2.5 se asoció con un aumento del 31.8% en el riesgo de hospitalización. El costo para el sistema de salud fue más de US$96,000 para 188 hospitalizaciones adicionales atribuibles.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (50,'P1-050','10.1029/2018gh000142','2026-04-18','Lipner, E. et al.','The Associations Between Clinical Respiratory Outcomes and Ambient Wildfire Smoke Exposure Among Pediatric Asthma Patients at National Jewish Health, 2012–2015',2019,'GeoHealth','Investiga retrospectivamente las asociaciones entre la exposición a humo de incendios forestales y medidas de función pulmonar (FEV1) y control del asma (ACT/CACT) en pacientes pediátricos con asma (4–21 años, n=1,404 para FEV1, n=395 para ACT/CACT) en National Jewish Health, Denver, Colorado (2012–2015), usando modelos de efectos mixtos con estimación del PM2.5 de incendios por polígonos satelitales de NOAA combinados con kriging de monitores de tierra. En niños de 12–21 años, el PM2.5 de incendios se asoció con menor FEV1 al día siguiente pero mayor FEV1 dos días después. No se encontraron asociaciones entre PM2.5 de incendios y FEV1 en niños más pequeños ni entre PM2.5 de incendios y el control del asma en ningún grupo de edad. Especula que el uso de medicación de rescate por los niños mayores podría disminuir los síntomas respiratorios causados por el humo de incendios, explicando la recuperación al segundo día.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (51,'P1-051','10.1145/3217804.3217946','2026-04-18','Sachdeva, S. et al.','Using social media to predict air pollution during California wildfires',2018,NULL,'Demuestra que datos de redes sociales (Twitter) pueden servir como fuente de datos complementaria para estimar la contaminación por partículas de humo de incendios forestales en California, evaluando si el modelo desarrollado para el incendio King Fire de 2014 mantiene buen rendimiento cuando se extiende a nivel estatal para múltiples incendios durante toda una temporada. Los resultados muestran que el modelo previo sigue proporcionando buenas estimaciones cuando se extiende a toda California para varios incendios en una temporada completa. Añadir la información semántica contenida en los tweets al modelo predictivo aumentó significativamente la precisión del modelo, indicando una confluencia de datos sociales y espacio-temporales. El modelo es especialmente valioso en regiones remotas donde escasean los monitores físicos de calidad del aire.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (52,'P1-052','10.1007/s11356-017-0860-y','2026-04-18','Ramakreshnan, L. et al.','Haze and health impacts in ASEAN countries: a systematic review',2018,'Environmental Science and Pollution Research','Revisión sistemática de la literatura sobre los impactos en salud física y psicológica de los episodios de neblina en países de la ASEAN, seleccionando 20 estudios revisados por pares de 384 artículos recuperados de seis bases de datos electrónicas interdisciplinarias. No puede generalizarse sobre síntomas físicos reportados en todos los estudios revisados, excepto por malestar en la garganta. Se encontró evidencia consistente de mayor morbilidad respiratoria, especialmente asma, siendo niños y adultos mayores los grupos más vulnerables. No es posible llegar a una conclusión consensuada sobre morbilidad cardiovascular por escasez de estudios y limitación geográfica. Algunos estudios de modelamiento muestran aumento de tasas de mortalidad respiratoria por exposición estacional a neblina. La evidencia sobre riesgo de cáncer es inconsistente y las emisiones industriales y vehiculares también juegan roles importantes, no solo la neblina.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (53,'P1-053','10.1080/10962247.2017.1315348','2026-04-18','Hong, K. et al.','Seasonal ambient particulate matter and population health outcomes among communities impacted by road dust in British Columbia, Canada',2017,'Journal of the Air and Waste Management Association','Evalúa las asociaciones entre diferentes medidas de exposición diaria a PM (PM10, PM2.5, PM10-2.5 y fracciones ajustadas) y dos indicadores de salud poblacional —dispensaciones de salbutamol y mortalidad no accidental— en siete comunidades de la Columbia Británica, Canadá, afectadas por polvo vial (2003–2015), usando regresión de Poisson en series temporales estratificadas por tres estaciones: humo residencial de madera en invierno, polvo vial en primavera y humo de incendios en verano. Un incremento en PM10-2.5 se asoció con un 3.6% de aumento en mortalidad no accidental durante la temporada de polvo vial, reducido a 3.1% tras ajuste por PM2.5; no hubo efecto de la fracción gruesa sobre dispensaciones de salbutamol en ninguna estación. Un incremento en PM2.5 se asoció con un 2.7% de aumento en dispensaciones durante la temporada de incendios. Los resultados sugieren impactos diferenciales de las distintas fracciones de PM por estación, con asociación robusta entre la fracción gruesa y la mortalidad no accidental en temporadas de polvo vial.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (54,'P1-054','10.1080/1369118x.2016.1218528','2026-04-18','Sachdeva, S. et al.','Social media approaches to modeling wildfire smoke dispersion: spatiotemporal and social scientific investigations',2017,'Information Communication and Society','Evalúa si el contenido generado por usuarios en redes sociales puede usarse como fuente de datos complementaria para medir la contaminación del aire por humo de incendios forestales, caso del incendio King Fire de 2014 en California. La frecuencia de tweets diarios en un área de 40,000 km² fue un predictor significativo de los niveles de PM2.5, más allá de la variación diaria y geográfica. Estos resultados sugieren que las redes sociales pueden ser una herramienta valiosa para medir los impactos de calidad del aire de incendios forestales, particularmente en ausencia de datos de estaciones de monitoreo físico. El análisis semántico del contenido de los tweets también proveyó información sobre las dimensiones socio-psicológicas del fuego, el humo y su impacto sobre las personas en áreas afectadas.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (55,'P1-055','10.1289/ehp271','2026-04-18','Krall, J. et al.','Associations between source-specific fine particulate matter and emergency department visits for respiratory disease in four U.S. cities',2017,'Environmental Health Perspectives','Determina cómo varía la composición química del PM2.5 entre ciudades según fuentes primarias y estima asociaciones entre PM2.5 específico por fuente y visitas a urgencias por enfermedades respiratorias en cuatro ciudades de EE.UU., usando imputación de fuentes para estimar concentraciones diarias de PM2.5 por fuente y modelos de regresión de Poisson en series temporales. PM2.5 de quema de biomasa, vehículos diésel, vehículos de gasolina y polvo fue similar en composición química entre ciudades; carbón y fuentes metálicas variaron entre ciudades. Se encontró cierta evidencia de asociaciones positivas de visitas ED respiratorias con PM2.5 de quema de biomasa; las asociaciones con PM2.5 diésel y gasolina fueron frecuentemente imprecisas o consistentes con el valor nulo. Entre las fuentes evaluadas, el PM2.5 de quema de biomasa se asoció más fuertemente con la salud respiratoria. Introduce un enfoque para comparar composiciones químicas de PM2.5 por fuente entre ciudades.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (56,'P1-056','10.1097/ede.0000000000000556','2026-04-18','Liu, J. et al.','Wildfire-specific fine particulate matter and risk of hospital admissions in urban and rural counties',2017,'Epidemiology',') Estima concentraciones diarias de PM2.5 atribuibles directamente a incendios forestales (PM2.5 específico de incendios) en el oeste de EE.UU. (561 condados, 2004–2009) usando un modelo de transporte químico global, define oleadas de humo (≥2 días consecutivos con PM2.5 específico de incendio >20 µg/m³) y estima el riesgo de ingresos hospitalarios cardiovasculares y respiratorios en beneficiarios de Medicare durante días de oleada de humo vs. días comparadores sin humo, usando un modelo lineal mixto generalizado. Aproximadamente 46 millones de personas de todas las edades estuvieron expuestas a al menos una oleada de humo (2004–2009); 5 millones de ellas son beneficiarios de Medicare (≥65 años). Se encontró un incremento del 7.2% en riesgo de ingresos respiratorios durante días de oleada con PM2.5 específico de incendio >37 µg/m³. No se observó asociación para PM2.5 ≤37 µg/m³ ni para ingresos cardiovasculares. Los efectos respiratorios del PM2.5 específico de incendios podrían ser más fuertes que los del PM2.5 de otras fuentes.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (57,'P1-057','10.1016/j.envres.2016.07.038','2026-04-18','Requia, W. et al.','Mapping distance-decay of cardiorespiratory disease risk related to neighborhood environments',2016,'Environmental Research','Cuantifica el efecto de decaimiento con la distancia (distance-decay) de riesgos de enfermedades cardiorrespiratorias relacionados con 28 aspectos del vecindario en el Distrito Federal, Brasil, usando regresión cuantílica y modelamiento SIG para crear mapas de riesgo. Un incremento de 2,500 m en longitud de autopistas se asoció con un 46% más de enfermedades cardiorrespiratorias; 46,000 vehículos ligeros en circulación (buffer ≤500 m de residencias) se asociaron con 6 ingresos hospitalarios por enfermedades cardiorrespiratorias. Las áreas verdes intraurbanas se asociaron con menos ingresos hospitalarios. Las personas que viven a ≤500 m del punto más cercano de un incendio forestal son más propensas a tener enfermedades cardiorrespiratorias que aquellas que viven a >500 m. Sugiere que el enfoque puede mejorar las políticas de salud pública en países menos desarrollados.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (58,'P1-058','10.1016/j.envres.2016.06.012','2026-04-18','Reid, C. et al.','Differential respiratory health effects from the 2008 northern California wildfires: A spatiotemporal approach',2016,'Environmental Research','El estudio examina los efectos en la salud respiratoria y cardiovascular asociados a PM2.5 durante el complejo de incendios forestales del norte de California en verano de 2008. Utiliza un modelo de exposición espacio-temporal basado en machine learning GBM  que integra AOD satelital del satélite GOES, salidas del modelo WRF-Chem y variables meteorológicas para estimar PM2.5 diario por código postal. Aplica ecuaciones de estimación generalizada de Poisson (GEE) para estimar riesgos relativos de hospitalizaciones y visitas a urgencias. Encuentra asociaciones significativas entre PM2.5 y asma (hospitalización y urgencias) y EPOC (urgencias), con efectos diferenciales por sexo, edad y nivel socioeconómico.','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (59,'P1-059','10.3109/08958378.2016.1145771','2026-04-18','Adetona, O. et al.','Review of the health effects of wildland fire smoke on wildland firefighters and the public',2016,'Inhalation Toxicology','Revisa la literatura sobre los efectos en salud del humo de incendios forestales en bomberos de incendios forestales y el público general en EE.UU., usando cinco bases de datos principales para identificar componentes del humo con mayor potencial de daño, mecanismos de toxicidad y efectos de salud asociados. Los eventos respiratorios medidos en estudios de series temporales (incidencias de mortalidad, ingresos hospitalarios, visitas a urgencias y síntomas en pacientes con asma y EPOC) son los efectos de salud más frecuentemente asociados con la exposición comunitaria al humo de incendios forestales. Estudios recientes también determinan asociaciones entre la exposición aguda al humo de incendios y desenlaces de salud cardiovascular, principalmente asociados con PM2.5 ambiente. Los efectos de exposiciones crónicas en bomberos de incendios forestales permanecen en gran medida desconocidos. Señala brechas en el conocimiento sobre efectos de la mezcla compleja de contaminantes del humo.','P1','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (60,'P1-060','10.1007/s11356-014-3916-2','2026-04-18','Linares, C. et al.','Influence of advections of particulate matter from biomass combustion on specific-cause mortality in Madrid in the period 2004–2009',2015,'Environmental Science and Pollution Research','El estudio evalúa el efecto de advecciones de materia particulada por combustión de biomasa sobre la mortalidad diaria por causa específica en Madrid. Utiliza datos de estaciones terrestres de calidad del aire (PM2.5, PM10, O3, NO2) y registros de mortalidad por causas naturales, respiratorias y circulatorias. Aplica regresión de Poisson autorregresiva estratificando por días con y sin advección de biomasa. Encuentra que PM10 (no PM2.5) se asocia con mayor mortalidad natural en días con advección, con efecto más pronunciado en mayores de 75 año','P1','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (61,'P2-001','10.1093/ije/dyag017','2026-04-19','Han C. et al.','Health impacts of a short-lived, small-scale wildfire in South Korea',2026,'International Journal of Epidemiology',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (62,'P2-002','10.1093/ije/dyaf169','2026-04-19','Phung V.L.H. et al.','Effects of smoke haze on respiratory clinic visits in Central Kalimantan, Indonesia according to different haze characteristics',2025,'International Journal of Epidemiology','La investigación evaluó el efecto de la neblina de humo (smoke haze) sobre las visitas diarias a centros de atención primaria (puskesmas) por enfermedades respiratorias en dos subdivisiones de Kalimantan Central, Indonesia (Palangka Raya City y Pulang Pisau Regency) entre 2015 y 2019, período que incluyó dos episodios mayores de neblina. Se utilizó un diseño de caso-cruzado estratificado por espacio-tiempo con un modelo de regresión condicional quasi-Poisson, considerando diferentes definiciones de día de neblina (con/sin actividad de fuego, duración). Se estimó un aumento del 36.6% (IC95%: 10.2%-69.3%) en el riesgo de visitas respiratorias en Pulang Pisau durante días de neblina, y del 74.4% (IC95%: 18.9%-164.6%) cuando la neblina estaba asociada a fuegos activos (fire-haze). Los efectos fueron más pronunciados con duraciones prolongadas (≥15 días), pero no se observaron asociaciones significativas en Palangka Raya City, excepto una reducción del riesgo en duraciones largas.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (63,'P2-003','10.1029/2024gh001317','2026-04-19','Flood V.A. et al.','Assessing the Impact of Wildfire Emissions on the Seasonal Cycle of CO and Emergency Room Visits in Alberta and Ontario, Canada',2025,'GeoHealth','Se examinó si el cambio en el ciclo estacional del monóxido de carbono (CO) atribuido a emisiones de incendios forestales (identificado por Buchholz et al., 2022) se asocia con cambios en visitas a urgencias por enfermedades cardiovasculares y respiratorias en Alberta y Ontario, Canadá, entre 2004 y 2019. Se utilizaron mediciones satelitales de CO (MOPITT) y un espectrómetro FTIR terrestre en Toronto para comparar pre-2012 (2004–2011) y post-2012 (2012–2019), detectando un nuevo pico estacional centrado en agosto en el período más reciente. Mediante un análisis de diferencias en diferencias (DiD) con CO como métrica de exposición, se calculó el cambio en admisiones mensuales por 100,000 habitantes asociado a un incremento de 1 ppb de XCO. Se encontraron aumentos significativos en cinco de 18 pares enfermedad-provincia: hipertensión-ON (β₃=1.88), cardiopatía isquémica-ON (0.50), arritmia-ON (0.12), arritmia-AB (0.48) y asma-ON (0.31). Los autores concluyen que el CO satelital es una métrica prometedora de exposición a humo, particularmente para efectos a larga distancia.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (64,'P2-004','Sin DOI (conferencia ACRS)','2026-04-19','Taweepornwattanakul K.; Takeuchi W.','High-Resolution PM2.5 Modeling and Respiratory Disease Correlation in Chiang Mai Using Himawari-9 and Ground Observations',2025,'ACRS Conference Proceedings','Los autores desarrollan un marco para estimar PM2.5 superficial en Chiang Mai (norte de Tailandia, valle montañoso) durante 2023, integrando reflectancia TOA del satélite geoestacionario Himawari-9, recuperación de AOD mediante modelo radiativo 6S y variables meteorológicas ERA5 con Random Forest como modelo predictivo. Los modelos estratificados por temporada lograron buen desempeño (R²=0.82 en temporada de quema febrero–abril; R²=0.76 en meses no-haze), aunque la validación rolling time-series anual mostró fuerte no-estacionariedad (R² cercano a cero). Las estimaciones mensuales de PM2.5 se correlacionaron con admisiones hospitalarias por asma y EPOC con retrasos significativos de hasta dos meses (R² ajustado ≈0.97). Los autores advierten que el R² alto está probablemente inflado por el tamaño muestral pequeño (12 meses) y la agregación mensual gruesa, y concluyen que los satélites geoestacionarios pueden ser útiles para monitoreo de calidad del aire con relevancia sanitaria pero requieren calibración estacional y datos multi-anuales.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (65,'P2-005','10.1080/09603123.2025.2579084','2026-04-19','Walters M.K.; Ward T.J.','Respiratory health outcomes of children and adolescents exposed to wildfire smoke: a systematic review',2025,'International Journal of Environmental Health Research',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (66,'P2-006','10.1001/jamanetworkopen.2025.7956','2026-04-19','Vega S.L. et al.','Wildfire Smoke Exposure and Cause-Specific Hospitalization in Older Adults',2025,'JAMA Network Open','La cohorte retrospectiva analizó la asociación entre exposición a PM2.5 específico de humo de incendios y hospitalizaciones por 13 causas en adultos mayores (≥65 años) de 11 estados del oeste de EE.UU. entre 2006 y 2016 (temporada de incendios mayo–octubre). Se incluyeron 10,369,361 beneficiarios de Medicare Fee-for-Service con 4.7 millones de hospitalizaciones no programadas, vinculadas con estimaciones diarias a nivel de condado de PM2.5 de humo derivadas de machine learning (Childs et al. 2022). Se utilizaron modelos de regresión lineal con rezago distribuido (lag 0–7 días) y splines cúbicos naturales para permitir asociaciones no lineales, ajustando por temperatura, festivos y efectos fijos de año, condado, condado-mes y día de semana. Los resultados mostraron curvas concentración-respuesta para hospitalizaciones respiratorias planas <25 μg/m³, crecientes entre 25–40 μg/m³ y plateau >40 μg/m³, con un incremento promedio significativo de 2.40 hospitalizaciones por 100,000 (IC 95%: 0.17; 4.63) al pasar de 0 a 40 μg/m³. Para cardiovasculares la asociación fue similar pero no significativa (2.61; IC 95%: −0.09; 5.30), y no se observaron asociaciones para las otras 11 causas.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (67,'P2-007','10.3390/atmos15121470','2026-04-19','Braggio J.T.','Remote Sensing Technologies Quantify the Contribution of Ambient Air Pollution to Asthma Severity and Risk Factors',2024,'Atmosphere','Esta revisión bibliográfica sistemática evaluó 61 estudios publicados entre 2009 y 2023 que utilizaron sensores remotos (satelitales) para cuantificar la contribución del verdor (NDVI), la contaminación del aire (AOD-PM2.5, PM10, NO2, O3) y el humo de incendios forestales sobre el asma y otros resultados respiratorios. Los datos incluyeron 198 outcomes específicos de más de 13 millones de participantes, principalmente de Estados Unidos, Italia, China y Canadá. Los resultados mostraron que los outcomes respiratorios fueron significativamente menores en entornos de verdor (efecto protector) y mayores en contaminación del aire e incendios, con diferencias significativas entre países en desarrollo y desarrollados. La exposición prenatal e infantil a AOD-PM2.5 se asoció con mayor incidencia de asma infantil y retrasos en el desarrollo pulmonar. Se identificaron factores de riesgo como edad, género, ambientales, geográficos y psicológicos, y se propuso un modelo fisiológico descriptivo del asma y guías para intervenciones poblacionales.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (68,'P2-008','10.1007/s10661-024-13323-5','2026-04-19','Siregar S. et al.','Association between long-term PM2.5 exposure and mortality on Sumatra Island: Indonesian Family Life Survey (IFLS) 2000-2014',2024,'Environmental Monitoring and Assessment','La cohorte retrospectiva evaluó la asociación entre la exposición a largo plazo (2000-2014) a PM2.5 y la mortalidad por todas las causas naturales, enfermedades cardiovasculares y respiratorias en 2,374 adultos ≥40 años de la Isla de Sumatra, Indonesia, utilizando datos de la Indonesian Family Life Survey (IFLS). La exposición a PM2.5 se estimó a partir de mediciones satelitales de AOD (1×1 km²) mediante un modelo de predicción. Se utilizó regresión de Cox ajustada por edad, sexo, IMC, educación, nivel socioeconómico, tabaquismo, área de residencia, diabetes e hipertensión. Por cada incremento de 10 µg/m³ en PM2.5, la mortalidad por causas naturales aumentó un 10% (HR=1.10; IC95%: 1.03–1.17), por causas cardiovasculares un 17% (HR=1.17; IC95%: 1.05–1.25) y por causas respiratorias un 19% (HR=1.19; IC95%: 1.04–1.36). Los niveles de PM2.5 en Sumatra excedieron los estándares de la OMS y la US-EPA.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (69,'P2-009','10.3390/ijerph21060675','2026-04-19','Ribeiro M.R. et al.','Amazon Wildfires and Respiratory Health: Impacts during the Forest Fire Season from 2009 to 2019',2024,'International Journal of Environmental Research and Public Health','El análisis ecológico evaluó la asociación entre incendios forestales, variables meteorológicas (temperatura, precipitación, humedad relativa) y hospitalizaciones por enfermedades respiratorias en la Amazonía Legal brasileña entre 2009 y 2019. Se registraron 1,438,322 incendios, de los cuales 1,218,606 (85%) ocurrieron entre agosto y diciembre (temporada de incendios). Durante esa temporada se registraron 566,707 hospitalizaciones respiratorias en los grupos vulnerables de 0–14 años y ≥60 años. Se utilizaron modelos de ecuaciones simultáneas (estimación por mínimos cuadrados ordinarios) mostrando que condiciones más secas, altas temperaturas y baja precipitación incrementan los incendios, y que estos se asocian con hospitalizaciones respiratorias a una tasa de 22 hospitalizaciones por cada 1,000 incendios mensuales. Los resultados destacan la urgencia de políticas ambientales y de salud para mitigar los efectos de los incendios en la Amazonía.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (70,'P2-010','10.1029/2023gh000991','2026-04-19','Barkoski J. et al.','Data Linkages for Wildfire Exposures and Human Health Studies: A Scoping Review',2024,'GeoHealth','Esta revisión de alcance (scoping review) evaluó 83 artículos publicados hasta julio de 2022 que vinculan exposiciones a incendios forestales con efectos en la salud humana, con el objetivo de identificar fuentes de datos de exposición y salud, describir cómo se combinan y señalar brechas y oportunidades. La mayoría de los estudios se centraron en resultados respiratorios (54%) y cardiovasculares (26%), con menos estudios sobre salud perinatal, salud mental, cáncer y otras condiciones. La fuente de datos de salud más común fue la administrativa (registros hospitalarios, 36%), seguida de encuestas y bases gubernamentales. La exposición más estudiada fue el PM2.5 (70% de los estudios), estimado principalmente desde redes de monitoreo terrestre (52%) y datos satelitales (35%). Se identificaron limitaciones como la falta de datos de salud en tiempo real, cobertura espacial insuficiente para estudiar efectos a largo plazo, y la escasa caracterización de mezclas complejas de contaminantes del humo (COV, HAP) y de otras vías de exposición (agua, suelo, alimentos). La revisión destaca la necesidad de mejorar la integración y accesibilidad de datos, así como de desarrollar registros de salud específicos para incendios.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (71,'P2-011','10.1126/sciadv.adj7264','2026-04-19','Chen C. et al.','Exploring spatial heterogeneity in synergistic effects of compound climate hazards: Extreme heat and wildfire smoke on cardiorespiratoryhospitalizations in California',2024,'Science Advances','La investigación examinó los efectos sinérgicos del calor extremo y el humo de incendios forestales sobre las hospitalizaciones cardiorrespiratorias en California entre 2006 y 2019, utilizando datos satelitales y de monitoreo de alta resolución a nivel de Área de Tabulación de Códigos Postales (ZCTA). Se emplearon diseños de caso-cruzado y de emparejamiento intracomunitario con modelos bayesianos jerárquicos espaciales para estimar la heterogeneidad espacial de los efectos sinérgicos. Se encontró un efecto sinérgico positivo a nivel estatal (RERI=0.04, IC95%: 0.01–0.06) y una fuerte heterogeneidad espacial, con mayores sinergias en el norte montañoso, el valle central y áreas metropolitanas costeras. Las comunidades con menor nivel educativo, menor cobertura de seguro de salud, menores ingresos, menor cobertura de árboles, mayor densidad poblacional y mayor proporción de minorías raciales/étnicas experimentaron efectos sinérgicos significativamente mayores. Los resultados subrayan la necesidad de incorporar peligros compuestos y justicia ambiental en las políticas de adaptación climática.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (72,'P2-012','10.1186/s12940-023-00998-5','2026-04-19','Dhingra R. et al.','Wildfire smoke exposure and early childhood respiratory health: a study of prescription claims data',2023,'Environmental Health A Global Access Science Source','La cohorte retrospectiva investigó la asociación entre la exposición al humo de incendios forestales durante el desarrollo (períodos prenatales y postnatales tempranos) y el primer uso de medicamentos respiratorios de prescripción en 182,387 lactantes nacidos en 60 MSAs de seis estados del oeste de EE.UU. (2010–2016). Se vincularon datos de reclamaciones de IBM MarketScan con datos de días de humo derivados del producto NASA/NOAA HMS a nivel de MSA, estimando exposición promedio semanal para trimestres gestacionales y dos períodos postnatales de 12 semanas. Mediante modelos de Cox de efectos mixtos ajustados por sexo, estación y año de nacimiento, con intercepto aleatorio por MSA, la exposición postnatal se asoció con uso más temprano de medicamentos para vías respiratorias superiores (P1: HR=1.094, IC 95%: 1.005–1.191; P2: HR=1.108, IC 95%: 1.016–1.209). Las asociaciones gestacionales mostraron efectos protectores aparentes para medicamentos respiratorios inferiores y antiinflamatorios sistémicos, posiblemente por sesgo de nacido vivo.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (73,'P2-013','10.3390/atmos14101491','2026-04-19','Tornevi A. et al.','Potential Health Impacts from a Wildfire Smoke Plume over Region Jamtland Harjedalen, Sweden',2023,'Atmosphere','El análisis técnico evaluó el impacto potencial en la salud de una exposición hipotética al humo de incendios forestales sobre la ciudad de Östersund, Suecia, utilizando datos modelados de PM2.5 del modelo de transporte químico MATCH durante el episodio de incendios de 2018. Se construyeron dos escenarios desplazando la exposición real que afectó a la localidad de Sveg (escenario I) y al máximo de la pluma (escenario II) hacia la población de Östersund (63,227 habitantes). La exposición acumulada ponderada por población durante los nueve días más intensos alcanzó 207 µg/m³·días en el escenario II. Usando funciones exposición-respuesta de la literatura, se estimó que el mayor efecto sería en visitas de urgencia por asma, con 13 casos adicionales (vs. 12 esperados) en el escenario II. Los impactos fueron menores debido a la población pequeña, la corta duración y el aumento moderado de PM2.5. Se destaca la importancia de prepararse para futuros eventos dado el aumento esperado de incendios en el norte de Europa.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (74,'P2-014','10.1029/2023gh000802','2026-04-19','de Souza Fernandes Duarte E. et al.','Fire-Pollutant-Atmosphere Components and Its Impact on Mortality in Portugal During Wildfire Seasons',2023,'GeoHealth','Se analizó la correlación entre componentes fuego-contaminante-meteorológicos y la mortalidad cardiorrespiratoria en Portugal continental durante las temporadas de incendios de 2011–2020 (junio–octubre, con área quemada >1,000 ha). Se utilizaron datos de área quemada, PM10, PM2.5, CO, NO2, O3, temperatura, humedad relativa, velocidad del viento, AOD y tasas de mortalidad por enfermedades del sistema circulatorio (CSD), respiratorio (RSD), neumonía (PNEU), EPOC y asma (ASMA). Se aplicó Análisis de Componentes Principales (PCA) para crear dos índices: Interacción Contaminante-Quema (PBI) y Interacción Atmosférico-Contaminante (API). El PBI se correlacionó fuertemente con contaminantes y área quemada; el API con temperatura, humedad y O3. El clustering K-means dividió los datos en dos grupos: Cluster 1 (meses más fríos/húmedos, mayor NO2) y Cluster 2 (meses más cálidos/secos, mayores PM10, PM2.5, CO, O3). La regresión lineal por componentes principales reveló correlaciones significativas (p<0.05) en el Cluster 2 entre PBI/API y mortalidad por RSD, PNEU, COPD y CSD, indicando que los meses más cálidos, secos y contaminados están asociados con el aumento de la mortalidad cardiorrespiratoria.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (75,'P2-015','10.1073/pnas.2218210120','2026-04-19','Pullabhotla H.K. et al.','Global biomass fires and infant mortality',2023,'Proceedings of the National Academy of Sciences','El análisis global cuantificó el impacto de los incendios de biomasa (forestales, agrícolas y de pastizales) en la mortalidad infantil mediante el emparejamiento de datos de más de 2 millones de nacimientos de encuestas DHS (2004–2018) con área quemada satelital y dirección del viento. Se utilizó un diseño de regresión con efectos fijos para aislar el efecto de la exposición a incendios en dirección upwind (barlovento) versus downwind (sotavento), controlando por características del niño, la madre, el hogar y el clima. Los resultados muestran que cada km² adicional de área quemada en dirección upwind dentro de 30 km se asocia con un aumento del 2.1% en la mortalidad infantil (1.06 muertes adicionales por 1,000 nacidos vivos, IC 95%: 0.017–2.10), mientras que la exposición downwind no tiene efecto. Se estima que los incendios de biomasa contribuyen con aproximadamente 130,000 muertes infantiles anuales a nivel global (2004–2018), de las cuales el 75% ocurren en África. Reducciones alcanzables del área quemada podrían evitar más de 70,000 muertes infantiles al año.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (76,'P2-016','10.1016/j.joclim.2023.100219','2026-04-19','Smith M.L.; Chi G.','Spatial proximity to wildfires as a proxy for measuring PM2.5: A novel method for estimating exposures in rural settings',2023,'Journal of Climate Change and Health','La investigación examinó si la proximidad espacial a incendios forestales puede servir como un proxy simple para la exposición a PM2.5 en entornos rurales, utilizando datos de Alaska (2007–2017). Se asignó exposición anual a incendios mediante buffers de 5 a 70 millas alrededor de centros poblados, utilizando datos de incendios del Alaska Interagency Coordination Center y población del Alaska Bureau of Labor and Statistics. La prevalencia de asma en adultos se obtuvo del BRFSS para 11 regiones del Behavioral Health System (BHS) de Alaska. Se encontró una correlación positiva y significativa entre la población expuesta a incendios (dentro de radios específicos) y la prevalencia de asma, siendo la correlación más fuerte dentro de las 25 millas (r=0.94). El estudio concluye que la proximidad a incendios es un proxy útil para estimar exposición al humo en áreas rurales sin monitoreo directo de PM2.5.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (77,'P2-017','10.3390/fire6040159','2026-04-19','Schweizer D. et al.','Using a Statistical Model to Estimate the Effect of Wildland Fire Smoke on Ground Level PM2.5 and Asthma in California, USA',2023,'Fire','Se analizó el efecto del humo de incendios forestales sobre las concentraciones de PM2.5 en superficie y las visitas a salas de emergencia por asma en California (2008–2015), utilizando datos de monitores de PM2.5 y detección remota de humo del sistema HMS (NOAA). Se aplicaron modelos estadísticos (regresión logística y modelo semiparamétrico logit con splines) para estimar la probabilidad de exceder umbrales de PM2.5 y la asociación con visitas por asma. Los resultados muestran que la presencia de humo de alta densidad aumenta significativamente el odds de que PM2.5 supere 35 µg/m³ (OR=114, IC 95%: 87–150). Las visitas por asma aumentan con PM2.5 en días sin humo (OR=1.3 para PM2.5=60 vs. 10 µg/m³), pero durante episodios de humo de incendios no se observa asociación significativa, posiblemente por conductas de evitación (quedarse en casa, filtros de aire, mascarillas). Los OR son máximos cuando PM2.5 supera 35 µg/m³ durante múltiples días consecutivos (OR=1.38, IC 95%: 1.21–1.57 con 3 días).','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (78,'P2-018','10.1073/pnas.2309325120','2026-04-19','Wen J. et al.','Quantifying fire-specific smoke exposure and health impacts',2023,'Proceedings of the National Academy of Sciences','Los autores desarrollaron un método para cuantificar la exposición acumulada a PM2.5 de humo de incendios forestales a nivel de incendio individual y sus impactos en salud, combinando cicatrices de quemaduras satelitales (MODIS/GlobFire), trayectorias de parcelas de aire del modelo HYSPLIT y estimaciones diarias de PM2.5 de humo (Childs et al. 2022) para EE.UU. continental (abril 2006–diciembre 2020). Se atribuyó PM2.5 a incendios específicos usando suma ponderada por distancia inversa de puntos de trayectoria, y se estimaron visitas excedentes a urgencias por asma mediante funciones concentración-respuesta lineales. El incendio Bugaboo (Georgia, 2007) generó el mayor número de visitas por asma (1,407, IC 95%: 1,295–1,518). La correlación entre visitas por asma y área quemada fue moderada (ρ=0.29). El 87% del PM2.5 de humo provino de incendios fuera del condado y el 60% de fuera del estado. La proporción de PM2.5 de incendios transfronterizos aumentó dramáticamente en el oeste de EE.UU. entre 2006–2010 y 2016–2020.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (79,'P2-019','10.1038/s41597-022-01488-y','2026-04-19','Swanson A. et al.','Daily 1 km terrain resolving maps of surface fine particulate matter for the western United States 2003-2021',2022,'Scientific Data','Se desarrollaron mapas diarios de PM2.5 en superficie a 1 km de resolución para el oeste de EE.UU. (2003–2020) utilizando regresión geográficamente ponderada (GWR) ajustada con observaciones de estaciones de calidad del aire (EPA AQS), datos de AOD del sensor MODIS y variables meteorológicas del reanálisis CFSR. Para capturar los impactos de aire estancado e inversiones térmicas, se incluyeron una capa estática de \'potencial de smog\' (que integra topografía y fuentes de emisión) y una capa dinámica de \'intensidad de smog\'. La precisión del modelo fue R²=0.66 en validación cruzada LOOCV. Los datos AOD mejoran el modelo en verano y otoño (temporada de incendios), mientras que los términos de estancamiento capturan la dinámica espaciotemporal de PM2.5 en valles montañosos, especialmente en invierno. Este producto es útil para estudios de exposición y salud en regiones montañosas del oeste de EE.UU. donde las estaciones de monitoreo son escasas.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (80,'P2-020','10.1097/ede.0000000000001539','2026-04-19','Sheridan P. et al.','Using the Generalized Synthetic Control Method to Estimate the Impact of Extreme Weather Events on Population Health',2022,'Epidemiology',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (81,'P2-021','10.1111/pai.13872','2026-04-19','Da Silva Sena C.R. et al.','Reduction in forced vital capacity in asthmatic children on days with bushfire smoke exposure in the Australian 2019/2020 bushfire',2022,'Pediatric Allergy and Immunology','La investigación evaluó el efecto de la exposición al humo de incendios forestales durante la temporada 2019–2020 en Australia sobre la función pulmonar de niños asmáticos. Se analizaron datos de 129 niños de 4 a 16 años atendidos en una clínica ambulatoria de asma (John Hunter Children\'s Hospital, NSW) entre enero 2019 y abril 2020, con 212 visitas y espirometrías válidas. La exposición a PM2.5 se estimó mediante IDW desde estaciones gubernamentales, y se definieron días de incendio cuando el PM2.5 superaba el percentil 95 (2010–2018) con confirmación visual satelital. Mediante modelos de efectos mixtos ajustados, se encontró reducción de 4.75% en FVC% predicho (IC 95%: −8.98 a −0.51; p=0.028) en días de incendio, parcialmente reversible con broncodilatador. Por cada µg/m³ de PM2.5, la FVC disminuyó 0.19% (p=0.002). Es el primer estudio con espirometría en niños asmáticos del incendio australiano 2019–2020.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (82,'P2-022','10.1136/jech-2021-218229','2026-04-19','Shirangi A. et al.','Exposure to fine particulate matter (PM2.5) during landscape fire events and the risk of cardiorespiratory emergency department attendances: A time-series study in Perth, Western Australia',2022,'Journal of Epidemiology and Community Health',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (83,'P2-023','10.1016/j.rse.2022.112890','2026-04-19','Vu B.N. et al.','Application of geostationary satellite and high-resolution meteorology data in estimating hourly PM2.5 levels during the Camp Fire episode in California',2022,'Remote Sensing of Environment','Se desarrolló un modelo de Random Forest ponderado con sobremuestreo SMOTE para estimar concentraciones horarias de PM2.5 durante el episodio del Camp Fire en California (octubre–noviembre 2018). Se combinaron datos de monitores regulatorios (EPA AQS) y sensores de bajo costo calibrados (PurpleAir) con datos del satélite geoestacionario GOES-16 (AOD, detección de aerosoles y focos de calor), variables meteorológicas de alta resolución (HRRR, 3 km) y variables de uso de suelo y topografía. El modelo completo (AQS+PurpleAir+SMOTE) logró OOB R²=0.92 (RMSE=10.44 µg/m³) y CV espacial y temporal R²=0.84 y 0.85. PurpleAir aumentó las observaciones en >500% y SMOTE redujo la subestimación en PM2.5 alto. Es el primer estudio que integra sensores de bajo costo y datos satelitales geoestacionarios para estimación horaria de PM2.5 en un episodio de incendio forestal.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (84,'P2-024','10.3390/rs14010069','2026-04-19','Campanharo W.A. et al.','Hospitalization due to fire-induced pollution in the Brazilian legal amazon from 2005 to 2018',2022,'Remote Sensing','El análisis estimó el efecto causal de la contaminación generada por incendios sobre las hospitalizaciones respiratorias en la Amazonía Legal Brasileña (AJB), usando un panel balanceado municipal-mensual de 805 municipios (2005–2018, n=118,335 observaciones). Para identificar el efecto causal del AOD sobre hospitalizaciones, se usaron variables instrumentales (área quemada MODIS, velocidad y dirección del viento ERA5 y sus interacciones) estimadas mediante mínimos cuadrados en dos etapas (2SLS) con efectos fijos (estado, año, mes). Un aumento del 1% en AOD aumenta las hospitalizaciones respiratorias totales en 0.14% por municipio-mes. El 5% de las hospitalizaciones respiratorias (≈822 casos/mes) son atribuibles a la contaminación por incendios. Los efectos son positivos para asma y adultos mayores, pero negativos para niños pequeños (posible confusión estacional). El enfoque demuestra el potencial de combinar teledetección y econometría para evaluar impactos causales de incendios en salud.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (85,'P2-025','10.1029/2021gh000457','2026-04-19','O\'Dell K. et al.','Estimated Mortality and Morbidity Attributable to Smoke Plumes in the United States: Not Just a Western US Problem',2021,'GeoHealth','La evaluación de impacto en salud (HIA) cuantificó la mortalidad y morbilidad por asma atribuibles al humo de incendios de paisaje (forestales, prescritos y agrícolas) en EE.UU. (2006–2018) a resolución de 15×15 km, usando PM2.5 de humo basado en observaciones (kriging EPA AQS + plumas HMS), funciones CR de meta-análisis (Borchers Arriagada 2019) para morbilidad aguda y GEMM para mortalidad crónica. Se estimaron urgencias por asma (1,300–5,900/año), hospitalizaciones por asma (300–1,400/año), mortalidad crónica (6,300 muertes/año, IC: 4,800–7,800) y DALYs por PM2.5 (~231,000/año) y HAPs (~309/año). Aunque los grandes incendios ocurren en el oeste, el 74% de la mortalidad y el 75% de la morbilidad por asma atribuibles al humo ocurren fuera del oeste por mayor densidad poblacional. La morbilidad predomina en primavera (35%) y verano (57%).','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (86,'P2-026','10.1029/2020gh000349','2026-04-19','Hahn M.B. et al.','Wildfire Smoke Is Associated With an Increased Risk of Cardiorespiratory Emergency Department Visits in Alaska',2021,'GeoHealth','La investigación evaluó la asociación entre PM2.5 de humo de incendios forestales (WFS PM2.5) y visitas de urgencias cardiorrespiratorias en tres centros poblacionales de Alaska (Anchorage, Fairbanks y Matanuska-Susitna Valley) durante las temporadas de incendios 2015–2019. El WFS PM2.5 se estimó combinando monitores terrestres (Alaska DEC) con plumas de humo satelitales (NOAA HMS): días de incendio definidos cuando PM2.5 superó 1 DE sobre la media mensual de largo plazo Y el monitor estaba a ≤50 km de una pluma. Mediante diseño caso-cruzado estratificado por tiempo con modelos de lag simple y distribuido (hasta lag 5), se encontró que 10 µg/m³ de WFS PM2.5 aumentó el riesgo de urgencias por asma (OR lag 0=1.13, IC: 1.10–1.16), con efectos más pronunciados en pueblo nativo de Alaska (OR=1.16), mujeres (OR=1.13) y adultos mayores (OR=1.15). Las poblaciones rurales de Matanuska-Susitna mostraron patrón de retraso en la búsqueda de atención cardiovascular. Es el primer estudio epidemiológico de WFS y salud en Alaska.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (87,'P2-027','10.1016/j.scitotenv.2020.142923','2026-04-19','Uttajug A. et al.','Association between PM10 from vegetation fire events and hospital visits by children in upper northern Thailand',2021,'Science of the Total Environment',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (88,'P2-028','10.3390/ijerph18073538','2026-04-19','Nguyen H.D. et al.','The summer 2019-2020 wildfires in east coast australia and their impacts on air quality and health in New South Wales, Australia',2021,'International Journal of Environmental Research and Public Health','Estudio que analiza el episodio de incendios del \'Black Summer\' 2019–2020 en la costa este de Australia y su impacto sobre la calidad del aire y la salud en NSW. Usa el modelo meteorológico-químico WRF-Chem con emisiones FINN, datos de monitoreo en superficie y satélites (MODIS, CALIPSO, MERRA-2) para simular la dispersión de PM2.5, CO y AOD. Combina concentraciones modeladas con tasas de incidencia y funciones concentración-respuesta para estimar muertes prematuras y hospitalizaciones respiratorias y cardiovasculares por SA4: 247 (IC: 89–409) muertes prematuras, 437 (IC: 81–984) hospitalizaciones cardiovasculares y 1,535 (IC: 493–2,087) hospitalizaciones respiratorias en NSW entre el 1/11/2019 y el 8/01/2020.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (89,'P2-029','10.1029/2020gh000330','2026-04-19','Magzamen S. et al.','Differential Cardiopulmonary Health Impacts of Local and Long-Range Transport of Wildfire Smoke',2021,'GeoHealth','El análisis evaluó la asociación entre PM2.5 de humo de incendios forestales (WFS PM2.5) y la morbilidad y mortalidad cardiopulmonar en el corredor urbano Front Range de Colorado (2010–2015). Se estimó el WFS PM2.5 mediante kriging de monitores EPA AQS a grilla 15×15 km, restando la mediana estacional de días sin humo identificados con plumas HMS. Mediante diseño caso-cruzado estratificado por tiempo con modelos de lag simple (0–5 días) y lag distribuido ajustados por temperatura y ozono, se encontró que 10 µg/m³ de WFS PM2.5 aumentó hospitalizaciones respiratorias en lag 3 (asma OR=1.26 IC: 1.11–1.43; EPOC OR=1.15; bronquitis aguda OR=1.37) y cardiovasculares (IHD lags 2–3 OR≈1.09). Mortalidad por paro cardíaco: lag 0 OR=2.93 (IC: 1.11–7.74). Hallazgo diferencial: humo local 2012 mostró asociación inversa con asma (OR=0.72, posible efecto de evacuación); transporte de largo alcance 2015 mostró aumento significativo (OR=1.46). Primer estudio en demostrar efectos diferenciales de humo local vs. transportado en EE.UU.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (90,'P2-030','10.1073/pnas.2011048118','2026-04-19','Burke M. et al.','The changing risk and burden of wildfire in the United States',2021,'Proceedings of the National Academy of Sciences','Este artículo de perspectiva cuantifica la creciente contribución del humo de incendios forestales a la contaminación por PM2.5 en EE.UU. y sus implicaciones para la salud, el cambio climático y las políticas de gestión. Usando un modelo estadístico que relaciona datos satelitales de plumas de humo y actividad de incendios con mediciones de monitores terrestres (EPA AQS) entre 2006–2018, se estima que los incendios han contribuido hasta el 25% del PM2.5 total a nivel nacional y hasta el 50% en regiones del oeste. La exposición a humo es mayor en condados con mayor proporción de población blanca (inverso al gradiente de PM2.5 total). Se proyecta que la mortalidad atribuible al humo inducido por cambio climático podría acercarse a los aumentos proyectados en mortalidad por temperatura. ~50 millones de hogares en la interfaz urbano-forestal (WUI), aumentando 1 millón cada 3 años. Discute mejoras en cuantificación de exposición, funciones dosis-respuesta específicas para humo e intervenciones como quemas prescritas.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (91,'P2-031','10.1016/j.scitotenv.2020.141621','2026-04-19','Mendez-Espinosa J.F. et al.','Air quality variations in Northern South America during the COVID-19 lockdown',2020,'Science of the Total Environment','Se analizaron los cambios en la calidad del aire durante el confinamiento por COVID-19 en Bogotá y Medellín (Colombia) entre febrero y junio de 2020, usando mediciones en superficie de PM10, PM2.5 y NO2 (redes SDA y SIATA), datos satelitales (TROPOMI/Sentinel-5P para NO2, FIRMS/MODIS para incendios activos, CAMS para carbono orgánico) y trayectorias HYSPLIT. Durante el confinamiento estricto las concentraciones de NO2, PM10 y PM2.5 disminuyeron 60%, 44% y 40% (corto plazo) y 50%, 32% y 9% (largo plazo vs. 2015–2019). La quema de biomasa regional aumentó el PM2.5 en ~20 µg/m³ durante el confinamiento estricto; una intrusión de polvo sahariano elevó el PM10 hasta 85–168 µg/m³. Políticas de movilidad equivalentes al confinamiento relajado podrían acercar las concentraciones anuales a las guías de la OMS, pero se requiere gestionar las quemas de biomasa regionales.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (92,'P2-032','10.1021/acs.est.0c03761','2026-04-19','Cleland S.E. et al.','Estimating Wildfire Smoke Concentrations during the October 2017 California Fires through BME Space/Time Data Fusion',2020,'Environmental Science and Technology','Se estimaron concentraciones diarias promedio de PM2.5 a 1 km de resolución durante los incendios de California en octubre 2017, fusionando tres fuentes mediante Bayesian Maximum Entropy (BME): monitores permanentes (EPA AQS FRM/FEM) y temporales (CARB/WFAQRP, E-BAM), CMAQ corregido por sesgo con el método CAMP, y PM2.5 derivado de AOD satelital MODIS (modelo de efectos mixtos). Se evaluaron cuatro variantes BME. El mejor método (fusión Obs+CC-CMAQ+Sat-PM2.5) alcanzó R²=0.713. Agregar estaciones temporales aumentó el R² un 36%. Se estimó que ~65,000 personas fueron expuestas a PM2.5 ≥150.5 µg/m³ y 16 millones a PM2.5 >35 µg/m³. La fusión de múltiples fuentes supera significativamente a cualquier fuente individual.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (93,'P2-033','10.1097/ee9.0000000000000114','2026-04-19','Aguilera R. et al.','Respiratory hospitalizations and wildfire smoke: a spatiotemporal analysis of an extreme firestorm in San Diego County, California',2020,'Environmental Epidemiology','La investigación evaluó la variación espaciotemporal de hospitalizaciones respiratorias en el condado de San Diego durante los incendios de octubre 2007 (impulsados por vientos Santa Ana). Se usó un diseño intra-comunidad (within-community matched design) a nivel de código postal (ZIP code), comparando hospitalizaciones en los 5 días expuestos (22–26 oct) con la mediana de 4 días control (mismo día de la semana, 2 semanas antes y después). Un modelo jerárquico bayesiano espacial (BHM) aumentó la precisión de las estimaciones. Los mayores excesos de hospitalización se concentraron en ZIP codes cubiertos por el humo y a sotavento de los perímetros de incendio, siguiendo la evolución espaciotemporal de las plumas. El exceso total representó el 30% de las hospitalizaciones respiratorias del condado. El análisis se replicó con los incendios de 2003 y se validó con pruebas de falsificación en años sin incendios (2000 y 2004).','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (94,'P2-034','10.1038/s41370-020-0210-x','2026-04-19','Gan R.W. et al.','The association between wildfire smoke exposure and asthma-specific medical care utilization in Oregon during the 2013 wildfire season',2020,'Journal of Exposure Science and Environmental Epidemiology',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (95,'P2-035','10.1029/2020gh000270','2026-04-19','Anenberg S.C. et al.','Using Satellites to Track Indicators of Global Air Pollution and Climate Change Impacts: Lessons Learned From a NASA-Supported Science-Stakeholder Collaborative',2020,'GeoHealth','Este artículo de comentario describe la colaboración del equipo \'Indicators Tiger Team\' de la NASA HAQAST (2018–2020), que reunió a ~20 investigadores y organizaciones de la sociedad civil (Lancet Countdown, GBD, State of Global Air, C40 Cities, entre otras) para desarrollar indicadores globales de contaminación del aire y cambio climático basados en satélites. Los indicadores desarrollados incluyen: exposición directa a incendios forestales (MODIS, Lancet Countdown), frecuencia de tormentas de polvo, conteos de pólenes, espacio verde urbano (MODIS NDVI), concentraciones de NO2 y carga de asma pediátrica (OMI, TROPOMI), concentraciones de ozono troposférico (fusión BME + modelos), y mortalidad por PM2.5 urbano (250 ciudades, 0.1°×0.1°). El artículo comparte lecciones aprendidas: la producción participativa de conocimiento genera información más accionable pero requiere tiempo y flexibilidad; aún se necesitan mediciones en superficie para validar satélites; y la colaboración sostenida después del financiamiento sigue siendo un desafío.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (96,'P2-036','10.13181/mji.oa.204390','2026-04-19','Burhan E.; Mukminin U.','A systematic review of respiratory infection due to air pollution during natural disasters',2020,'Medical Journal of Indonesia','Esta revisión sistemática evaluó la asociación entre la exposición a contaminación del aire durante desastres naturales (incendios forestales y erupciones volcánicas) e infecciones respiratorias. Se buscaron estudios en PubMed, EBSCOhost y Google Scholar (últimos 10 años, humanos, inglés); de 2,820 artículos iniciales se seleccionaron 6 (4 sobre incendios, 2 sobre erupciones volcánicas). La contaminación elevada (PM2.5 10–70 µg/m³, AOD >5 veces límites tolerables) se asoció consistentemente con mayor frecuencia de IRA, neumonía, bronquitis y bronquiolitis. Los resultados para IVR superiores fueron heterogéneos. Los mecanismos incluyen deterioro de la función de macrófagos alveolares por partículas, facilitando infecciones bacterianas. Concluye que los desastres naturales aumentan la contaminación por encima de las guías OMS y que la contaminación juega un papel importante en IRA, especialmente en poblaciones con alta exposición.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (97,'P2-037','10.1007/s11869-019-00771-z','2026-04-19','Johnson A.L. et al.','Particulate matter modelling techniques for epidemiological studies of open biomass fire smoke exposure: a review',2020,'Air Quality Atmosphere and Health','Esta revisión sistemática identificó y evaluó las técnicas de modelado espacial utilizadas para estimar concentraciones de PM2.5 o PM10 de humo de incendios de biomasa en estudios epidemiológicos. Se incluyeron 28 estudios que emplearon cinco categorías de técnicas: modelos de dispersión (21 estudios), regresión de uso de suelo (LUR, 8), sensores remotos satelitales (2), interpolación espacial (3) y modelos combinados (5). Los modelos combinados (blended) que integran múltiples técnicas mostraron las mejores validaciones (R² hasta 0.85) y las asociaciones más fuertes con efectos en salud respiratoria. La mayoría de estudios se concentran en EE.UU., Canadá y Australia (78%), con escasa representación de regiones de alta carga de incendios como África subsahariana, Sudeste Asiático y Sudamérica. Los modelos combinados tienen potencial para facilitar investigación en regiones subrepresentadas con escasa cobertura de monitores.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (98,'P2-038','10.1016/j.envint.2019.105151','2026-04-19','Stowell J.D. et al.','Associations of wildfire smoke PM2.5 exposure with cardiorespiratory events in Colorado 2011-2014',2019,'Environment International','Se evaluó la asociación entre la exposición a PM2.5 de humo de incendios forestales y las visitas a emergencias y hospitalizaciones por eventos cardiorrespiratorios agudos en Colorado, EE.UU., durante las temporadas de incendios (mayo–agosto) de 2011–2014. Se usó un modelo de exposición de alta resolución (1 km, CV-R²=0.81) que combina MAIAC AOD, CMAQ y monitores terrestres con Random Forest, separando PM2.5 de humo del PM2.5 de fondo. Se aplicó un diseño caso-cruzado estratificado por tiempo con regresión logística condicional (ventana 3 días respiratorio, 2 días cardiovascular). Por cada 1 µg/m³ de PM2.5 de humo: asma OR=1.081 (IC: 1.058–1.105), enfermedad respiratoria combinada OR=1.021 (IC: 1.012–1.031). Sin asociaciones para cardiovascular ni PM2.5 de fondo. Efectos más fuertes en niños y adultos; adultos mayores sin asociación significativa.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (99,'P2-039','10.1088/1755-1315/373/1/012008','2026-04-19','Hanafi N.H. et al.','Analysis of transported pollution and haze-related diseases via HYSPLIT Trajectory Modelling in the urbanized area of Johor, Malaysia',2019,'IOP Conference Series Earth and Environmental Science','Se analizó la relación entre la contaminación por bruma (haze) de transporte de largo alcance (incendios en Sumatra y Kalimantan) y enfermedades relacionadas con mala calidad del aire (conjuntivitis, URTI y asma) en dos clínicas de Johor, Malasia, durante 2015. Se usaron datos mensuales de morbilidad ambulatoria y el API de estaciones CAQM. Se aplicó HYSPLIT (forward trajectories, 240 h, 10 días, desde Sumatra y Kalimantan Occidental a 100, 500 y 1000 m AGL) para simular el transporte de partículas. En septiembre los vientos permanecieron por debajo de 2000 m AGL, acumulando PM sobre la Península Malaya con API=96–100 (zona no saludable) y mayor número de casos de conjuntivitis, URTI y asma. En otros meses los vientos se dispersaron a >2500 m AGL con menor impacto en salud. Se concluye que la baja altura y estabilidad del viento en septiembre son los determinantes clave de la acumulación de PM y los episodios de bruma.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (100,'P2-040','10.1093/ije/dyz022','2026-04-19','Chakrabarti S. et al.','Risk of acute respiratory infection from crop burning in India: Estimating disease burden and economic welfare from satellite and national health survey data for 250 000 persons',2019,'International Journal of Epidemiology','La investigación cuantificó la asociación entre la quema agrícola de residuos de cultivos (ACRB) e IRA en India, usando datos de 252,539 individuos de la encuesta DLHS-4 (2013–2014) fusionados con datos satelitales MODIS/FIRMS. GLM mutuamente ajustados estimaron RR. Vivir en un distrito con ACRB intensa (≥100 incendios/día) se asoció con RR=2.99 (IC: 2.77–3.23); niños <5 años RR=3.65. Otros factores: congestión vehicular (RR=1.96), drenaje abierto (RR=1.91), cocina con biomasa (RR=1.73). El 14.4% de los casos de IRA fueron atribuibles a ACRB. Eliminar la quema de residuos evitaría 149,000 DALYs/año, valorados en US$1,529 millones en 5 años. Los estados del sur de India (sin ACRB) sirvieron como comparadores.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (101,'P2-041','10.1016/j.jenvman.2017.08.018','2026-04-19','Parthum B. et al.','Benefits of the fire mitigation ecosystem service in The Great Dismal Swamp National Wildlife Refuge, Virginia, USA',2017,'Journal of Environmental Management',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (102,'P2-042','10.1002/2017gh000073','2026-04-19','Gan R.W. et al.','Comparison of wildfire smoke estimation methods and associations with cardiopulmonary-related hospital admissions',2017,'GeoHealth','Se compararon tres métodos de estimación de exposición a PM2.5 de humo de incendios forestales (WRF-Chem, kriging de monitores terrestres y GWR que combina WRF-Chem, AOD satelital MODIS y kriging) y evaluó sus asociaciones con hospitalizaciones cardiorrespiratorias en Washington, EE.UU., durante la temporada de incendios julio–octubre 2012. Se usó un diseño caso-cruzado estratificado por tiempo con regresión logística condicional (26,835 admisiones). Por 10 µg/m³ de PM2.5 de humo (GWR): asma OR=1.076 (IC: 1.019–1.136), EPOC OR=1.084 (IC: 1.026–1.145), todos respiratorios OR=1.052 (IC: 1.025–1.080). Para EPOC, WRF-Chem no mostró asociación significativa (OR=0.986). No se observaron asociaciones cardiovasculares consistentes. La elección del método de estimación impacta las conclusiones; GWR (R²=0.66) y kriging (R²=0.69) superaron a WRF-Chem (R²=0.25).','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (103,'P2-043','10.1016/j.atmosenv.2016.09.049','2026-04-19','Yuchi W. et al.','Blending forest fire smoke forecasts with observed data can improve their utility for public health applications',2016,'Atmospheric Environment','La investigación evaluó si la fusión de pronósticos de PM2.5 de humo de incendios forestales con estimaciones empíricas basadas en observaciones mejora su utilidad para salud pública en British Columbia, Canadá, durante las temporadas de incendios de 2014 y 2015. Se compararon seis métricas: modelo empírico BCCDC (EM, 5×5 km, integra monitores + satélites), pronósticos FireWork (FW, 10 km, 48 h) y BlueSky (BS, 4 km, 60 h), y cuatro combinaciones de fusión (EM+FW, EM+BS, FW+BS, EM+FW+BS). GEE modelaron la asociación con visitas por asma (n=74,341) y dispensaciones de salbutamol (n=227,191) en 88 LHAs. Los modelos fusionados siempre superaron a los individuales. EM+FW fue la mejor combinación: RR=1.11 (IC: 1.09–1.13) por 1 DE de PM2.5 para visitas por asma; NRMSE=2.10%, r=0.79 vs. observaciones.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (104,'P2-044','10.1016/j.envres.2014.10.015','2026-04-19','Liu J.C. et al.','A systematic review of the physical health impacts from non-occupational exposure to wildfire smoke',2015,'Environmental Research',NULL,'P2','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (105,'P2-045','10.1080/10962247.2015.1032445','2026-04-19','Haikerwal A. et al.','Impact of smoke from prescribed burning: Is it a public health concern?',2015,'Journal of the Air and Waste Management Association','Este artículo de revisión y discusión técnica examina el impacto de las quemas prescritas (PB) de reducción de combustible forestal sobre la calidad del aire (PM2.5) y sus potenciales efectos en salud pública en Australia y contextos de clima templado. Se sintetizan datos de estudios de caso australianos (Tasmania, Victoria, Australia Occidental) incluyendo un estudio propio en el Valle de Yarra, Victoria (abril 2013, 2 sitios a ~9 km). Concentraciones máximas diarias de 56 µg/m³ y horarias de 222 µg/m³ — hasta 15 veces por encima del estándar australiano (25 µg/m³). Se concluye que, dado que los efectos adversos de PM2.5 de incendios forestales se observan a concentraciones similares a las de las quemas prescritas, estas últimas representan una preocupación de salud pública. Se necesita más investigación específica y desarrollo de modelos de predicción y alertas para comunidades expuestas.','P2','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (106,'P3-001','10.1016/j.scitotenv.2017.12.086','2026-06-04','Cascio W.E. et al.','Wildland fire smoke and human health',2018,'Science of the Total Environment','Las revisiones sistemáticas concluyen que existe una asociación positiva entre la exposición al humo de incendios forestales o al PM2.5 de incendios y la mortalidad por todas las causas, así como la morbilidad respiratoria (asma, EPOC, bronquitis, neumonía). La evidencia sobre efectos cardiovasculares es mixta e inconclusa. Las poblaciones más susceptibles incluyen personas con enfermedades respiratorias o cardiovasculares, adultos mayores, niños y mujeres embarazadas. Se concluye que se requiere mayor investigación poblacional, clínica y ocupacional, y que se necesitan mejores modelos de exposición, pronóstico del humo y comunicación de riesgo para motivar conductas protectoras en poblaciones de alto riesgo.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (107,'P3-002','10.1016/j.chemosphere.2021.131351','2026-06-04','Dimitriadis C. et al.','Exposure to mine fire related particulate matter and mortality: A time series analysis from the Hazelwood Health Study',2021,'Chemosphere','El incendio de la mina de carbón a cielo abierto de Morwell (Australia, 2014) cubrió áreas cercanas con humo durante 6 semanas. Mediante modelos de series temporales con PM2.5 modelado (CSIRO), se evaluó el riesgo de mortalidad durante los primeros 30 días del incendio y en los 6 meses siguientes. Durante el período del incendio se observó mayor riesgo de muerte por lesiones en Morwell; en los 6 meses posteriores se detectó mayor mortalidad por todas las causas y por cardiopatía isquémica, especialmente en hombres y residentes de 80 años o más. No se encontró asociación con mortalidad respiratoria ni cardiovascular durante el período activo del incendio.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (108,'P3-003','10.1029/2025GH001510','2026-06-04','Aguilera R. et al.','Effects of Multiple Wildfire Smoke Pollutants (PM2.5, PM10, and Ozone) on Respiratory and Cardiovascular Hospitalizations in California (2006–2019)',2025,'GeoHealth','En California (2006–2019), se cuantificó la contribución de los incendios forestales a las concentraciones de PM10 y O3 usando un marco de modelado estadístico (R² 0,68–0,89), y se evaluaron sus impactos a corto plazo sobre hospitalizaciones respiratorias y cardiovasculares. Los efectos del humo de incendios sobre distintos desenlaces y regiones fueron heterogéneos: el PM2.5 de incendios fuera del verano se asoció con admisiones respiratorias, mientras que el PM10 de incendios se asoció con hospitalizaciones cardiovasculares durante todo el año. Se concluye que enfocar el análisis exclusivamente en PM2.5 subestima la carga sanitaria del humo de incendios.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (109,'P3-004','10.1016/j.envint.2016.11.018','2026-06-04','Salimi F. et al.','Ambient particulate matter, landscape fire smoke, and emergency ambulance dispatches in Sydney, Australia',2017,'Environment International','En la región metropolitana de Sídney (2004–2015), se evaluó la relación entre el PM2.5 ambiental total y el PM2.5 específico de humo de incendios de paisaje (LFS) con los despachos de ambulancia de emergencia (EAD) por problemas cardiorrespiratorios. Mediante regresión cuasi-Poisson diaria, se encontró que aumentos de 10 µg/m³ en PM2.5,all se asociaron con problemas respiratorios (RR 1,03), paro cardiorrespiratorio (RR 1,03) y dolor torácico (RR 1,01) el mismo día; el PM2.5,LFS se asoció con problemas respiratorios el mismo día (RR 1,04) y con \'otros problemas cardíacos\' a lag 2 días (RR 1,05). Los despachos de ambulancia por problemas respiratorios se proponen como un desenlace sensible para la vigilancia casi en tiempo real de exposiciones a PM2.5.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (110,'P3-005','10.1088/2752-5309/ac9b7e','2026-06-04','Rau A. et al.','Nationwide assessment of ambient monthly fine particulate matter (PM2.5) and the associations with total, cardiovascular and respiratory mortality in the United States',2023,'Environmental Research: Health','Se realizó un estudio ecológico de la asociación entre PM2.5 mensual (media) y mortalidad total, cardiovascular y respiratoria en 698 condados de EE.UU. (1999–2018), usando un modelo de dos etapas (Poisson sobredispersa por condado + metaanálisis de efectos aleatorios). Por cada 10 µg/m³ de PM2.5 mensual, la mortalidad total aumentó un 1,1% (IRR 1,011), la cardiovascular un 1,4% (IRR 1,014) y la respiratoria un 1,6% (IRR 1,016). Los subgrupos más afectados fueron adultos mayores, varones, minorías no negras y comunidades socialmente vulnerables, con marcada heterogeneidad regional. El intervalo mensual de exposición, actualmente no regulado, representa un nuevo desafío para las políticas de salud pública.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (111,'P3-006','10.1016/j.envint.2025.109955','2026-06-04','Letellier N. et al.','Using generalized random forests to characterize vulnerability to adverse health outcomes following wildfire smoke exposure in California',2025,'Environment International','En California (2006–2019), se aplicó un diseño caso-cruzado estratificado por tiempo con Generalized Random Forest (GRF) para identificar perfiles de vulnerabilidad comunitaria ante PM2.5 específico de incendios en 1.773 ZCTAs y 15 cuencas atmosféricas. Por 10 µg/m³ de PM2.5 de incendios (media móvil 2 días), las hospitalizaciones/urgencias por enfermedades respiratorias aumentaron un 1,4% (OR 1,014), sin asociación cardiovascular. El GRF identificó la edad (0–14 años), el sexo femenino, la etnia hispana, la prevalencia de aire acondicionado y el índice de disimilitud racial negro/blanco como los principales modificadores del efecto, con perfiles de vulnerabilidad que variaron fuertemente entre cuencas atmosféricas.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (112,'P3-007','10.1016/j.envint.2019.04.033','2026-06-04','Reid C.E. et al.','Associations between respiratory health and ozone and fine particulate matter during a wildfire event',2019,'Environment International','Durante un incendio intenso en el norte de California en 2008, se crearon mapas diarios de superficie de PM2.5 y O3 mediante machine learning y se vincularon con conteos de hospitalizaciones y urgencias respiratorias a nivel de código postal. Mediante ecuaciones de estimación generalizadas (GEE) Poisson, se encontró que el PM2.5 se asoció robustamente con exacerbaciones de asma y EPOC (RR urgencias asma 1,112 por 10 µg/m³), incluyendo las infecciones respiratorias agudas (ICD-9 460–465); el O3 fue significativo solo en modelos univariados y se confundió al ajustar por PM2.5. El PM2.5 superó 35 µg/m³ en 4.976 días-código postal, mientras que el O3 raramente excedió su norma.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (113,'P3-008','10.1016/j.chemosphere.2020.126667','2026-06-04','Guo Y. et al.','The association of coal mine fire smoke with hospital emergency presentations and admissions: Time series analysis of Hazelwood Health Study',2020,'Chemosphere','Se evaluó el impacto del humo del incendio de la mina de carbón Hazelwood (Australia, 2014) sobre las presentaciones de emergencia y admisiones hospitalarias en las 15 SA2 del Valle de Latrobe, usando datos diarios de enero 2009 a junio 2015 y un GAMM quasi-Poisson con efectos aleatorios por SA2. Comparado con períodos sin incendio, se encontraron mayores riesgos de urgencias y admisiones por causas respiratorias (asma, EPOC) y por todas las causas durante el período del incendio. Las asociaciones entre PM2.5 diario y urgencias para todas las causas, EPOC y asma aparecieron a partir de 2 días de exposición acumulada; las admisiones por enfermedades cerebrovasculares y respiratorias, el mismo día. Por cada 10 µg/m³ de PM2.5 acumulado 0–7 días: urgencias respiratorias RR 1,14 (1,02–1,29) y urgencias por EPOC RR 1,39 (1,06–1,83).','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (114,'P3-009','10.1016/j.scitotenv.2017.10.270','2026-06-04','Vaidyanathan A. et al.','Developing an online tool for identifying at-risk populations to wildfire smoke hazards',2018,'Science of the Total Environment','El CDC está desarrollando una herramienta web integrada en la plataforma NEPHTN que combina pronósticos operacionales de concentraciones de humo en tiempo real con índices de vulnerabilidad social (SVI) y tasas de salud de línea base, para identificar comunidades en riesgo durante episodios de incendios forestales. Se realizó un estudio piloto con 11 incendios en el oeste de EE.UU. (2008–2013) que demostró la factibilidad técnica de integrar bases de datos heterogéneas y documentó la disponibilidad variable de datos de salud por jurisdicción. La herramienta, aún en desarrollo en el momento de la publicación, busca reducir el tiempo de respuesta de los sistemas de salud pública y fortalecer la preparación ante emergencias relacionadas con el humo.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (115,'P3-010','10.1097/ALN.0000000000004344','2026-06-04','Marsh B.J. et al.','Wildfire Smoke Exposure Is Associated with Adverse Respiratory Events under General Anesthesia in At-risk Pediatric Patients',2022,'Anesthesiology','Se evaluó la asociación entre la exposición al humo de incendios forestales (AQI>100 en los 14 días previos al procedimiento) y los eventos respiratorios adversos bajo anestesia general en 625 pacientes pediátricos en el UCSF (incendios Camp Fire 2018 y August Complex 2020), mediante un estudio de cohorte retrospectivo doble con regresión binomial. En niños con enfermedad de vía aérea reactiva, el riesgo de eventos respiratorios adversos aumentó un 50% durante períodos de aire no saludable (RR 1,50; IC95% 1,04–2,17; p=0,032), con modificación de efecto estadísticamente significativa (RR 1,56; p=0,041) y NNH de 5,5. En niños sin ese antecedente no se encontró efecto. Se concluye que la calidad del aire deficiente por humo de incendios debe considerarse un factor de riesgo adicional para posponer cirugías electivas en este subgrupo.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (116,'P3-011','10.1055/a-2542-8711',NULL,'Münzel T. et al.','Health Effects of Wildfires; [Gesundheitliche Auswirkungen von Waldbränden]',2025,'Deutsche Medizinische Wochenschrift','La creciente frecuencia e intensidad de los incendios forestales, agravada por el cambio climático, genera contaminación severa por PM2.5 que puede transportarse a grandes distancias, aumentando el riesgo de enfermedades cardiovasculares y respiratorias, especialmente en grupos vulnerables (niños, embarazadas, personas con enfermedades preexistentes y adultos mayores). A nivel mundial, las emisiones de incendios forestales se asocian con cientos de miles de muertes prematuras anuales. Se destacan como medidas protectoras los sistemas de alerta temprana, los filtros de aire y el uso de mascarillas, aunque persisten lagunas de conocimiento sobre los componentes específicos de los contaminantes y su interacción con factores ambientales. Se subraya la necesidad de investigación longitudinal y medidas globales de protección climática.','P3','Media','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (117,'P3-012','10.1038/s41598-025-13257-z','2026-06-04','Gonçalves A.C. et al.','Additive effect of wildfires on hospital admission in the Pantanal wetland, Brazil',2025,'Scientific Reports','El Pantanal brasileño —mayor humedal continuo del mundo— experimenta incendios forestales severos que generan picos de hospitalizaciones. Se aplicó un modelo lineal generalizado (GLM) de Poisson con DLNM, usando datos diarios del DataSUS, focos activos de FIRMS/MODIS y calidad del aire de MERRA-2/OMI para 21 municipios del Pantanal (2010–2019). Por cada incremento de 10 focos activos de incendio acumulado en 10 días, el riesgo de hospitalizaciones respiratorias aumentó un 23,2% (IC 1,224–1,240) y el de hospitalizaciones cardiovasculares un 22,4%; en el período 2015–2019 de mayor actividad ígnica, los efectos fueron más pronunciados (+33,8% y +29,3%, respectivamente). La topografía plana rodeada de montañas genera un efecto de \'trampa\' que acumula el humo y amplifica la exposición.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (118,'P3-013','10.1016/j.envpol.2018.12.085','2026-06-04','Johnson A.L. et al.','Fine particulate matter exposure and medication dispensing during and after a coal mine fire: A time series analysis from the Hazelwood Health Study',2019,'Environmental Pollution','Se evaluó la asociación entre la exposición prolongada al PM2.5 del incendio de mina de carbón Hazelwood (Australia, 2014, 7 semanas) y los medicamentos dispensados para condiciones respiratorias, cardiovasculares y psiquiátricas en cinco localidades del Valle de Latrobe (2013–2016), mediante análisis de series temporales Poisson con DLNM. Por cada 10 µg/m³ de PM2.5 del incendio, la dispensación de medicamentos respiratorios aumentó un 25% (IC95% 19–32%) y los cardiovasculares un 10% (7–13%) y psiquiátricos un 12% (8–16%), con lag de 3–7 días para respiratorios y 3–6 días para cardiovasculares y psiquiátricos. Las asociaciones fueron más consistentes y fuertes que las reportadas para incendios forestales, posiblemente por la mayor duración de la exposición.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (119,'P3-014','10.1016/j.envres.2016.08.003','2026-06-04','Kollanus V. et al.','Effects of long-range transported air pollution from vegetation fires on daily mortality and hospital admissions in the Helsinki metropolitan area, Finland',2016,'Environmental Research','Se examinó la asociación entre la exposición a corto plazo a PM2.5 transportado a larga distancia desde incendios de vegetación y la mortalidad diaria (no-accidental, cardiovascular, respiratoria) y las hospitalizaciones (cardiovasculares y respiratorias) en el área metropolitana de Helsinki (2001–2010), identificando 72 días de episodios de humo mediante mediciones en estaciones de fondo y el modelo NAAPS. Mediante regresión Poisson de series temporales con el diseño equivalente a caso-cruzado, en los días de humo el PM2.5 se asoció con mayor mortalidad cardiovascular a lag 3 (+12,4% por 10 µg/m³, p=0,054 en la población total; +13,8% mismo día en ≥65 años, p=0,06) e indicios de mayor hospitalización por EPOC/asma a lag 2 (+15,8%, p=0,09). No se detectó asociación con mortalidad no-accidental ni hospitalizaciones cardiovasculares.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (120,'P3-015','10.3389/fpubh.2021.499309','2026-06-04','Henderson S.B. et al.','Staying Ahead of the Epidemiologic Curve: Evaluation of the British Columbia Asthma Prediction System (BCAPS) During the Unprecedented 2018 Wildfire Season',2021,'Frontiers in Public Health','El sistema BCAPS (British Columbia Asthma Prediction System) genera pronósticos diarios del impacto del humo de incendios en dispensaciones de inhaladores de salbutamol para 16 áreas de salud de BC usando un modelo de random forest (5 módulos: PM2.5 histórico, indicador de salud histórico, pronóstico de PM2.5 por FireWork+OSSEM, modelo de salud y visualización). Durante la temporada de incendios de 2018 (la más extrema en la historia de BC; PM2.5 medio provincial 22,0 µg/m³), los pronósticos de dispensaciones mostraron fuerte concordancia con las observaciones (IOA ponderado 0,95; 71% de pronósticos dentro del ±20% del observado), a pesar de que los pronósticos de PM2.5 subestimaron las concentraciones más extremas. El desempeño fue mejor en áreas de mayor población y exposiciones moderadas.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (121,'P3-016','10.1016/j.jaip.2024.12.004','2026-06-04','Balmes J.R. et al.','The Effect of Wildfires on Asthma and Allergies',2025,'Journal of Allergy and Clinical Immunology: In Practice','El cambio climático es el principal motor del aumento en frecuencia e intensidad de los incendios forestales, y el humo de incendios —mezcla compleja de gases y PM2.5— está anulando las mejoras en calidad del aire logradas por las transiciones energéticas. La exposición al PM2.5 de incendios se asocia robustamente con exacerbaciones de asma (RR 1,10 por 10 µg/m³) y EPOC, y puede ser hasta 10 veces más dañina para la salud respiratoria infantil que el PM2.5 de otras fuentes. Las estrategias de adaptación incluyen mascarillas N95, espacios de aire limpio, sistemas de alerta y gestión forestal; las comunidades marginadas, indígenas y de bajos ingresos soportan las mayores cargas de exposición. Se enfatiza la necesidad de investigar los mecanismos de daño epitelial y las intervenciones comunitarias para los grupos más vulnerables.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (122,'P3-017','10.1016/j.atmosenv.2018.01.002','2026-06-04','Latif M.T. et al.','Impact of regional haze towards air quality in Malaysia: A review',2018,'Atmospheric Environment','La neblina transfronteriza en Malaysia y el Sudeste Asiático, originada principalmente en quemas de turba y agricultura de tala-y-quema en Sumatra y Kalimantan (Indonesia), es un fenómeno recurrente modulado por el ENSO, que explica el 50–75% de la variabilidad interanual del PM10 local. La composición del PM durante los episodios está dominada por aerosoles inorgánicos secundarios (SO₄²⁻, NH₄⁺) y levoglucosano como marcador de quema de biomasa. Los episodios de neblina se asocian con un aumento del 19% en la mortalidad respiratoria y con mayor hospitalización por IRA alta, asma, EPOC y rinitis, siendo los niños y adultos mayores los grupos más afectados; el costo hospitalario anual se estimó en ~USD 91.000. Se proponen como medidas clave la mejora del pronóstico, la coordinación regional (Acuerdo ASEAN sobre Contaminación Transfronteriza) y la reducción de quemas.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (123,'P3-018','10.3390/ijerph120606710','2026-06-04','McLean K.E. et al.','An evaluation of the British Columbia asthma monitoring system (BCAMS) and PM2.5 exposure metrics during the 2014 forest fire season',2015,'International Journal of Environmental Research and Public Health','El sistema BCAMS rastreó la exposición al humo de incendios forestales y los desenlaces de salud por asma (visitas médicas y dispensaciones de salbutamol) durante la temporada de incendios de 2014 en British Columbia (Canadá), usando el algoritmo PHIDO para identificar excursiones (días con recuentos anormales sobre el percentil 95 o 99,9). La sensibilidad del umbral de PM2.5 ≥25 µg/m³ para predecir excursiones fue del 71,4% para visitas médicas y del 85,7% para dispensaciones de salbutamol, con especificidades ~90%; la mayoría de las excursiones (57–71%) se asociaron con PM2.5 ≥10 µg/m³. El sistema BCAMS alertó con mayor frecuencia cuando las exposiciones eran relativamente altas, y los pronósticos de humo (BlueSky, FireWork) mostraron sensibilidades <40%, lo que subraya la necesidad de datos de salud en tiempo real.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (124,'P3-019','10.1016/j.envres.2020.110402','2026-06-04','Gao C.X. et al.','Impact of exposure to mine fire emitted PM2.5 on ambulance attendances: A time series analysis from the Hazelwood Health Study',2021,'Environmental Research','Se evaluó el impacto del humo del incendio de la mina de carbón Hazelwood (Australia, 2014, ~6 semanas) sobre las asistencias de ambulancia en el Valle de Latrobe (julio 2010 – marzo 2015), usando GAM binomial negativo con modelos de lag distribuido (0–20 días) y efectos aleatorios por SA2. Por cada 10 µg/m³ de PM2.5 del incendio (lag 0–20 días), las asistencias por causas respiratorias aumentaron un 42% (IC95% 14–76%) y todas las asistencias un 7% (0–14%); durante los 30 días del incendio, el riesgo respiratorio aumentó un 47% (19–81%). No se encontraron asociaciones significativas para causas cardiovasculares ni lesiones.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (125,'P3-020','10.1007/978-3-031-52670-1_40',NULL,'Halem M. et al.','Towards a Dynamic Data Driven Wildfire Digital Twin (WDT): Impacts on Deforestation, Air Quality and Cardiopulmonary Disease',2024,'Lecture Notes in Computer Science (including subseries Lecture Notes in Artificial Intelligence and Lecture Notes in Bioinformatics)','Sin acceso al texto completo (PDF no disponible). Resumen no extraíble.','P3','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (126,'P3-021','10.1249/JSR.0000000000001237',NULL,'Phillips S. et al.','Poor Air Quality Due to Wildfire Smoke and Sports Participation: Case Study of the Special Olympics State Summer Games',2025,'Current Sports Medicine Reports','Sin acceso al texto completo (PDF no disponible). Resumen no extraíble.','P3','Alta','Completo','Sin_acceso');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (127,'P3-022','10.3390/fire7080277','2026-06-04','Khanmohammadi S. et al.','Data-Driven PM2.5 Exposure Prediction in Wildfire-Prone Regions and Respiratory Disease Mortality Risk Assessment',2024,'Fire','Se desarrollaron modelos de machine learning (SVR, MLP, Random Forest, XGBoost, NGBoost) para predecir concentraciones de PM2.5 a partir de variables meteorológicas y de humedad de combustible en Wagga Wagga, Australia (2019–2020), durante la temporada de incendios. NGBoost fue el mejor modelo (RMSE=23,4; MAE=8,0); la radiación solar, la humedad de combustible y la temperatura fueron las variables más influyentes. En una segunda fase, se modeló la mortalidad por EPOC y cáncer de pulmón a nivel global (GBD 1990–2019) usando edad, sexo, tipo de contaminación y año: la contaminación ambiental fue el principal predictor de mortalidad por EPOC, mientras que la edad fue más importante para el cáncer de pulmón.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (128,'P3-023','10.1146/annurev-med-052422-020909','2026-06-04','Gould C.F. et al.','Health Effects of Wildfire Smoke Exposure',2024,'Annual Review of Medicine','Esta revisión con meta-análisis de efectos aleatorios (REML, n estudios incluidos) sintetiza la evidencia sobre los efectos a corto plazo del PM2.5 de incendios en mortalidad y morbilidad. Por cada 1 µg/m³ de PM2.5 de incendios: mortalidad por todas las causas +0,15% (IC95% 0,01–0,28%); hospitalizaciones respiratorias +0,25% (0,09–0,52%); visitas a emergencias respiratorias +0,36% (0,19–0,53%); los efectos cardiovasculares fueron inconsistentes. La heterogeneidad entre estudios fue alta (I² 79–93%) excepto para hospitalizaciones cardiovasculares (44%). Se concluye que los efectos son positivos y significativos para mortalidad y morbilidad respiratoria, y que se requieren datos de alta resolución espaciotemporal específicos de incendios para mejorar las estimaciones causales.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (129,'P3-024','10.3390/rs12244074','2026-06-04','Roux E. et al.','Toward an early warning system for health issues related to particulate matter exposure in brazil: The feasibility of using global pm2.5 concentration forecast products',2020,'Remote Sensing','Se evaluó la factibilidad de utilizar pronósticos globales de PM2.5 del CAMS (horizonte 4 días) para construir un sistema de alerta temprana de enfermedades respiratorias agudas severas (SARD) en Brasil. Mediante regresión lineal múltiple (selección por AIC) para remover el efecto confusor de variables meteorológicas y correlación de Pearson/Spearman entre los residuos de PM2.5 y SARD (2017–2019), se encontraron correlaciones positivas significativas en varias regiones (ej. Maranhão: ρ=0,52, p<0,01), excepto en el Sur donde la relación mejoró al considerar la tasa de pruebas negativas. Se concluye que es factible desarrollar un sistema de alerta temprana basado en pronósticos CAMS, aunque se requiere definir umbrales locales y mejorar la delimitación de las áreas de exposición.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (130,'P3-025','10.1016/j.scitotenv.2024.176543','2026-06-04','Chen C. et al.','The temporal trend and disparity in short-term health impacts of fine particulate matter in California (2006–2019)',2024,'Science of the Total Environment','Se examinaron las tendencias temporales en la relación entre PM2.5 diario y cuidados agudos circulatorios y respiratorios en 192 ZCTAs de California (2006–2019), usando modelos bayesianos jerárquicos de dos etapas. Por cada 10 µg/m³ de PM2.5 (lag 0–2 días), los cuidados agudos circulatorios aumentaron un 0,56% (IC95% 0,17–0,96%) y los respiratorios un 2,61% (2,29–2,94%); ambas asociaciones aumentaron significativamente del primer al segundo período (2013–2019 vs. 2006–2012). Se identificaron disparidades importantes por edad (≥65 años), raza/etnia (asiáticos no hispanos) y exposición a incendios extremos, con los mayores aumentos temporales en las áreas sin incendios extremos.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (131,'P3-026','10.1289/EHP12238','2026-06-04','Ziou M. et al.','Contrasting Health Outcomes following a Severe Smoke Episode and Ambient Air Pollution in Early Life: Findings from an Australian Data Linkage Cohort Study of Hospital Utilization',2023,'Environmental Health Perspectives','Se vincularon registros de nacimientos, visitas a emergencias y hospitalizaciones de niños nacidos en el Valle de Latrobe (Australia, 2012–2015) para evaluar las asociaciones entre la exposición prenatal e infantil al PM2.5 del incendio Hazelwood y al PM2.5 ambiental de fondo. La exposición prenatal al PM2.5 del incendio se asoció con urgencias por alergias/rash (OR 1,34 por 240 µg/m³); la exposición infantil, con urgencias respiratorias (OR 1,37) e infecciones respiratorias (OR 1,39) mediante comparación IPW con propensity score. El PM2.5 ambiental de fondo a niveles bajos (<6,5 µg/m³) también se asoció con mayor uso de servicios de salud. Los efectos difirieron entre la etapa prenatal y la infantil, señalando distintos períodos críticos de susceptibilidad.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (132,'P3-027','10.1371/journal.pmed.1004613','2026-06-04','Chen L. et al.','Wildfire-related PM2.5 and respiratory transmitted disease among Chinese children and adolescents from 2008 to 2019: A retrospective study',2025,'PLOS Medicine','Se investigó la asociación entre la exposición a corto plazo a PM2.5 de incendios forestales y la incidencia/mortalidad de enfermedades respiratorias transmitidas en niños y adolescentes chinos de 4–24 años (501 ciudades, 2008–2019; 6.089.271 casos), usando un diseño caso-cruzado con DLNM (lag 0–28 días). Por cada 5 µg/m³ de PM2.5 de incendios (lag 0–28), la incidencia de enfermedades respiratorias transmitidas aumentó un 6,8% (IC95% 5,0–8,7%), con efectos por enfermedad: influenza +28,6%, sarampión +13,6%, rubéola +12,6%; el efecto del PM2.5 no relacionado con incendios fue solo +1,2%. Aunque el PM2.5 de incendios representa solo el 2,7% del total, contribuye al 10,8% de los casos atribuibles a PM2.5 (y hasta el 29,7% en regiones de baja exposición habitual).','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (133,'P3-028','10.1016/j.jped.2024.11.006','2026-06-04','Rizzo L.V. et al.','Wildfire smoke and health impacts: a narrative review',2025,'Jornal de Pediatria','Esta revisión narrativa (2014–2024) sintetiza las características del humo de incendios forestales y sus impactos sistémicos en adultos y niños. El humo contiene PM en múltiples fracciones, gases tóxicos (CO, NOx, VOCs, PAHs) y puede causar estrés oxidativo, inflamación, daño al ADN y modificaciones epigenéticas en los sistemas respiratorio, cardiovascular y neurológico. Los niños son especialmente vulnerables por sus vías aéreas más pequeñas y pulmones en desarrollo; las infecciones respiratorias bajas representan el 36% de la mortalidad atribuible a PM2.5 de incendios. Se destaca la necesidad de mejorar los sistemas de alerta temprana, fortalecer la preparación de los sistemas de salud y promover campañas de comunicación de riesgo.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (134,'P3-029','10.1186/s12940-016-0146-8','2026-06-04','Alman B.L. et al.','The association of wildfire smoke with respiratory and cardiovascular emergency department visits in Colorado in 2012: A case crossover study',2016,'Environmental Health: A Global Access Science Source','Se investigó la relación entre el PM2.5 modelado con WRF-Chem y las visitas a emergencias/hospitalizaciones por outcomes respiratorios y cardiovasculares durante los incendios forestales de Colorado en 2012 (5 junio – 6 julio), usando un diseño caso-cruzado con regresión logística condicional. Se encontraron asociaciones positivas entre PM2.5 y asma/sibilancias (OR 1,04 por 5 µg/m³, lag 0) y EPOC (OR 1,05), así como con infección respiratoria alta (OR 1,02; ICD-9 460–465); los efectos fueron más fuertes en mayores de 65 años (asma lag 0–1–2: OR 1,29). Los resultados cardiovasculares fueron consistentemente nulos.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (135,'P3-030','10.1016/j.scitotenv.2025.180656','2026-06-04','Rumi M.J.U. et al.','Invisible hazards of ultrafine particles (UFPs) from Wildland-Urban Interface (WUI) fire smoke as emerging public health risks: A critical review of transformation dynamics from emission sources, exposure pathways, and vulnerable population to WUI fire toxicants',2025,'Science of the Total Environment','Esta revisión crítica sintetiza el conocimiento sobre partículas ultrafinas (UFP, <100 nm) emitidas por incendios en la interfaz urbano-forestal (WUI). Los UFP dominan numéricamente el humo (77–90%, hasta 1,25×10⁵ partículas/cm³) pero representan solo el 5–15% de la masa de PM2.5; contienen PAHs, metales pesados y PFAS, y su envejecimiento fotoquímico incrementa la toxicidad. Los UFP causan estrés oxidativo e inflamación sistémica, con aumento del 87% en prevalencia de asma y mayor riesgo cardiovascular, neurológico y cancerígeno, con impactos desproporcionados en comunidades de bajos ingresos, indígenas y bomberos. Se requieren protocolos estandarizados de monitoreo, nuevos estándares basados en número de partículas y mayor investigación sobre la toxicidad de UFPs de combustibles mixtos.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (136,'P3-031','10.1016/j.envint.2025.109513','2026-06-04','Xu K. et al.','Long-term exposure to smoke PM2.5 and COPD caused mortality for elderly people in the contiguous United States',2025,'Environment International','Se evaluó el efecto de la exposición a largo plazo a PM2.5 de humo de incendios forestales sobre la mortalidad por EPOC en 59,3 millones de adultos mayores de 65 años en EE.UU. continental (2008–2016; Medicare + National Death Index), usando modelos de Cox tiempo-dependiente con exposición acumulada en los 12 meses previos. Por cada 1 µg/m³ de smoke PM2.5, la mortalidad por EPOC aumentó un 9,2% (HR 1,092; IC95% 1,088–1,097), frente al 0,5% del PM2.5 no relacionado con incendios. El efecto fue marcadamente mayor en regiones de bajo riesgo de incendio (+40,4% por 1 µg/m³) que en regiones de alto riesgo (+3,9%), lo que sugiere mayor vulnerabilidad de poblaciones no acostumbradas a la exposición o mayor toxicidad del humo envejecido.','P3','Alta','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (137,'P3-032','10.1016/j.techsoc.2025.102843','2026-06-04','Rautela K.S. et al.','Modelling health implications of extreme PM2.5 concentrations in Indian sub-continent: Comprehensive review with longitudinal trends and deep learning predictions',2025,'Technology in Society','Se analizó la contaminación por PM2.5 en India (1980–2023) usando el reanálisis MERRA-2 y datos del GBD 2021, definiendo cuatro índices de extremos (MPM2.5, PM2.5D, MAPM2.5, PM2.599p) y aplicando regresión lineal y redes neuronales convolucionales (CNN) para predecir la mortalidad por estado, género y enfermedad. La regresión lineal mostró correlaciones moderadas entre PM2.5 y mortalidad por trastornos neurológicos y enfermedades respiratorias crónicas (R² 0,18–0,21), y débiles para infecciones respiratorias (R² 0,07–0,09); el modelo CNN denso mejoró sustancialmente la predicción (R² 0,84–0,96). Se identificó una marcada disparidad norte-sur, con concentraciones de PM2.5 en la llanura Indo-Gangética más del doble que en el sur entre 1980–1990 y 2010–2020.','P3','Media','Completo','Disponible');
INSERT INTO `ARTICULO` (`id`,`codigo`,`doi`,`fecha_extraccion`,`autores`,`titulo`,`anio`,`revista`,`resumen`,`cadena`,`prioridad`,`estado`,`acceso_pdf`) VALUES (138,'P3-033','10.1109/ICCCES62661.2026.11437157',NULL,'Alam S. et al.','AI-Enhanced Prediction of Respiratory Irritation From Biomass Combustion Byproducts: An Integrative Machine Learning Framework for Sustainable Bioenergy Systems',2026,'Proceedings of 5th International Conference on Communication, Computing and Electronics Systems, ICCCES 2026','Se presenta un modelo dual de machine learning (Random Forest + LSTM) para pronosticar los riesgos respiratorios de la exposición a bioaerosoles en áreas rurales dependientes de biomasa, integrando datos ambientales de monitoreo (PM2.5, NOx, VOCs) con datos clínicos (biomarcadores inflamatorios) en tiempo real. El análisis de importancia de características identificó los óxidos de nitrógeno como el predictor más relevante, confirmando la conexión mecanística entre la combustión incompleta y la inflamación respiratoria. El Random Forest mostró mejor interpretabilidad con bajo sesgo de predicción, mientras que la LSTM capturó con mayor fidelidad las dinámicas temporales de exposición; el marco integrador propone oportunidades para la implementación de tecnologías de cocina limpia y estrategias de procesamiento de biomasa.','P3','Alta','Completo','Sin_acceso');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (1,'Análisis espacial explícito mediante autocorrelación espacial global y local (Moran\'s I y LISA) con matriz de pesos de contigüidad tipo queen, identificando clusters HH/LL y outliers HL/LH. Mapeo coroplético por municipio con clasificación de Sturges. Estratificación por biomas (Amazonía, Cerrado, Pantanal), tipos climáticos Köppen (Am, Aw) y 16 territorios de salud. No usa kriging, GWR ni clustering basado en machine learning.','Series temporales mensuales. Función de correlación cruzada (CCF) entre variables ambientales (predictores) y de salud (respuesta) con identificación de lags principales. Tendencias de largo plazo evaluadas con prueba no paramétrica de Mann-Kendall y pendiente de Theil-Sen. Bootstrapping con 1000 remuestreos para intervalos de confianza. Estratificación estacional: estación seca (mayo–septiembre) vs húmeda (octubre–abril).','Software R (paquetes: trend para Mann-Kendall, boot para bootstrapping). Sistema de información geográfica (SIG) para integración de datasets ambientales y de salud.','Ecológico exploratorio espacio-temporal con datos agregados a escala municipio-mes. Diseño descriptivo sin modelamiento causal multivariado; los autores justifican explícitamente la no aplicación de regresión panel por ausencia de datos consistentes de confusores (tabaquismo, contaminación intradomiciliaria, vacunación, nivel socioeconómico) a nivel municipal para todo el período.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (2,'Análisis ecológico espacio-temporal a nivel SA2 (460 comunidades). Asignación de exposición desde grilla 0.25° a SA2 mediante ponderación poblacional. Moran\'s I sobre residuos del modelo para verificar autocorrelación espacial residual (resultó baja). Mapeo coroplético de tasas atribuibles por comunidad. No usa kriging, GWR, LISA ni clustering como método principal; el componente espacial se gestiona vía meta-análisis comunidad por comunidad.','Series temporales diarias, modelo dos etapas, lags simples (lag 0–7) y acumulados (lag 0–7), quasi-Poisson con splines naturales para tendencia y estacionalidad.','R 4.4.2 (paquetes dlnm, mixmeta); GEOS-Chem (modelo de transporte químico); machine learning para modelado de WS-PM2.5; simulaciones Monte Carlo (n=1000).','Series temporales ecológicas, diseño dos etapas (community-specific + meta-análisis de efectos aleatorios).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (3,'Distribución espacial de días de co-exposición por ZCTA (1,772 áreas); asignación de calor desde grilla GRIDMET 4 km al centroide poblacional de cada ZCTA. Mapeo coroplético de heterogeneidad espacial en California bajo 8 definiciones de evento. Análisis de subgrupos geográficos implícito pero no modelado formalmente (limitación reconocida por los autores).','Series temporales diarias temporada cálida (mayo–septiembre); diseño caso-cruzado estratificado por tiempo (time-stratified bidirectional); lags 0 y 1.','R 4.1.0 (paquetes: survival para regresión logística condicional, msm para método delta en IC de RERI); GRIDMET (reanálisis meteorológico a 4 km); modelo ensemble de Aguilera et al. (2023) para WS-PM2.5; modelo de Rothfusz adaptado por NWS para heat index.','Caso-cruzado estratificado por tiempo (time-stratified case-crossover).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (4,'CE4','CE4','CE4','CE4');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (5,'Clasificación espacial por proximidad a zona de quema (buffer de 20 km) a nivel de census tract; mapeo de exposición por grupos; análisis de sensibilidad con buffer alternativo de 10 km; extrapolación a toda la población asegurada del condado. No usa kriging, GWR, Moran\'s I, LISA ni clustering — el análisis espacial se gestiona mediante categorías discretas de proximidad.','Series temporales interrumpidas (ITS) en dos etapas diarias; modelo híbrido Prophet-XGBoost para tendencia contrafactual; período de entrenamiento nov 2022–ene 2025; período de evaluación 7–20 enero 2025; simulaciones Monte Carlo (n=1000) para IC empíricos. División train/test ~70/30 con 8 folds de validación cruzada temporal; tuneo de hiperparámetros con espacio space-filling de 100 combinaciones.','R 4.4.1 (tidymodels, tidyverse, modeltime, timetk); Python 3.12.2; Prophet (Facebook); XGBoost; gridMET (datos meteorológicos a 4 km²); vigilancia de aguas residuales LACDPH.','Estudio de cohorte con series temporales interrumpidas (ITS) en dos etapas; diseño de respuesta rápida con datos de registros electrónicos de salud (EHR).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (6,'Modelamiento espacialmente continuo a 12 km de resolución (dominio CONUS EPA 12US1); distribución espacial de IRR a nivel de condado; identificación de condados de mayor riesgo sin monitoreo AQS; mapas de incertidumbre espacial de emisiones y meteorología. No usa kriging, GWR, Moran\'s I, LISA ni clustering — el análisis espacial deriva de simulaciones determinísticas de transporte químico-atmosférico en grilla regular.','Análisis episódico de 3 días (6–8 junio 2023) con simulación numérica horaria. Período completo de simulación: 1 mayo–15 junio 2023, con las primeras dos semanas como spin-up. Series temporales de PM2.5 horarias downscaleadas; comparación pre/post episodio para validación. Análisis de incertidumbre temporal por variación de emisiones y meteorología.','WRF v4.5.2 (Weather Research & Forecasting); CMAQ v5.4 (Community Multiscale Air Quality); BenMAP-CE v1.5.8 (EPA Environmental Benefits Mapping and Analysis Program); SMOKE v4.9 (emisiones antropogénicas); MCIP v5.4; Python/R para análisis estadístico; Zaratan HPC cluster (U. Maryland); BEIS v4.0 (Biogenic Emissions Inventory System, integrado inline en CMAQ); mecanismo químico CB6r5 (Carbon Bond 6 Mechanism Revision 5); WACCM (Whole Atmosphere Community Climate Model) para condiciones de frontera.','Estudio episódico de modelamiento regional; diseño de escenarios (runs con/sin emisiones de incendios); análisis de sensibilidad con múltiples combinaciones de emisiones y meteorología; validación contra datos administrativos de urgencias. Diseño factorial 2×2: dos datasets de emisiones (CAMS, QFED) × dos drivers meteorológicos (FNL, NAM) = 4 sensibilidad + 2 control sin emisiones de incendio = 6 simulaciones totales.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (7,'Análisis ecológico a nivel de condado (San Francisco County, CA). Se utilizan datos agregados por condado, sin análisis de gradiente espacial ni comparación entre múltiples áreas geográficas. No se emplean controles sintéticos en el método principal.','Series Temporales Interrumpidas (Interrupted Time Series, ITS) de dos etapas (two-stage ITS). En la primera etapa se entrenan modelos solo con datos pre-evento; en la segunda se generan predicciones contrafactuales para el periodo post-evento. No se utiliza grupo de control externo. División de datos: entrenamiento (2009-01-01 a 2016-11-07) + prueba (2016-11-08 a 2018-11-07) + post-evento (2018-11-09 a 2018-12-31). Validación cruzada de ventana expandida con 5 folds secuenciales (ventana inicial 2.9 años + ventana de validación de 12 meses no-superpuesta).','R v4.4.0 con paquetes tidymodels y modeltime. Algoritmos evaluados: ARIMA (Box-Jenkins), NNETAR (red neuronal feed-forward de una capa oculta con función sigmoidea), Prophet (Facebook) + XGBoost híbrido. Moving Block Bootstrap (MBB) para IC empíricos con 1,000 iteraciones. Datos meteorológicos PRISM y GRIDMET. Código y datos completos disponibles en GitHub: https://github.com/benmarhnia-lab/Two_Stage_ML_ITS.','Estudio longitudinal cuasiexperimental con ITS de dos etapas usando datos diarios (2009–2018). Periodos: entrenamiento (ene 2009 – nov 2016), prueba (nov 2016 – nov 2018) y post-evento (nov–dic 2018). Se estima el exceso de hospitalizaciones por el incendio de 2018 comparando las observadas con las contrafactuales predichas.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (8,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (9,'Buffer de 20 km alrededor de monitores EPA para delimitar la población de estudio; asignación del monitor más cercano al domicilio geocodificado de cada paciente; delimitación de cuenca aérea (air basin) de Reno/Sparks.','Modelos de rezago distribuido (Distributed Lag Models, DLM); análisis lag-específico (lag 0–7 días) y acumulado; modelamiento de la respuesta al rezago mediante spline cúbica natural con 3 grados de libertad; control de tendencia de largo plazo y patrón estacional.','R (paquete dlnm); modelo HYSPLIT (NOAA) para dispersión atmosférica; SAS/GRAPH v9.4 (geocodificación con PROC GEOCODE); modelo bayesiano estructural de series temporales (Bayesian Structural Time Series).','Series temporales ecológicas (time series study); análisis de visitas diarias agregadas por grupo diagnóstico y monitor durante las temporadas de incendios (julio–septiembre) 2012–2019.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (10,'No se realizó análisis espacial explícito (como kriging, GWR, clustering o buffers). El estudio trabaja con agregados provinciales y compara 9 provincias, pero no modela la componente espacial (no hay matrices de distancia, autocorrelación espacial ni interpolación).','Series temporales (longitudinal). Se incluyen:
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (11,'Modelo espacial autorregresivo (SAR) con matriz de pesos espaciales basada en distancia inversa entre ciudades principales; estimación del parámetro autorregresivo espacial (ρ) por máxima verosimilitud; modelo de error espacial (Spatial Errors Model) como análisis de sensibilidad para autocorrelación residual.','Series temporales con lags de 1 y 2 meses entre exposición a PM2.5 de incendios y desenlaces (casos y muertes COVID-19); resolución mensual del análisis (agregación a partir de incidencia diaria acumulada mediante sustracción mes a mes); mes del año incluido como covariable lineal.','R Studio (modelos SAR, errores espaciales, modelos lineales mixtos); QGIS (mapas y análisis SIG); Shiny (aplicación interactiva publicada para visualización pública).','Ecológico (cohorte ecológica) con condados como unidades de análisis');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (12,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se incluyen 30 unidades de salud pública (PHU) como estratos en modelos condicionales, pero no se modela autocorrelación espacial ni se usan matrices de pesos espaciales.','Series de tiempo interrumpidas (ITS) controladas con año 2022 como serie de control; análisis caso-cruzado estratificado por tiempo (time-stratified case–crossover); lags de 0 a 7 días; extensión a 14 días para enfermedad isquémica del corazón','R versión 4.3.0','Cuasi-experimental: series de tiempo interrumpidas controladas (controlled ITS) + caso-cruzado estratificado por tiempo; triangulación epidemiológica con dos fuentes de datos independientes');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (13,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (14,'Análisis descriptivo espacial a nivel de país/territorio (201 países), regiones GBD y superregiones; mapas de tasas de mortalidad atribuible (AMR) con ArcGIS. No se aplica kriging, GWR ni clustering espacial formal — la variación geográfica se resume mediante agregación jerárquica por regiones GBD y grupos de ingreso.','Series temporales diarias en primera etapa (2267 comunidades, 2000–2019); regresión lineal sobre log-transformación de métricas anuales para estimar tendencias temporales (% cambio por año); análisis de dos décadas (2000–09 vs. 2010–19).','R versión 4.0.2; ArcGIS Desktop versión 10.1; GEOS-Chem v.12.0.0 (modelo de transporte químico) acoplado con Global Fire Emissions Database (GFED) v.4.1s para estimación de exposición.','Evaluación de impacto en salud (Health Impact Assessment, HIA) global; dos etapas: (1) meta-análisis de regresiones de series temporales para estimar relaciones exposición–respuesta a corto plazo; (2) estimación de mortalidad atribuible por país/año aplicando esas relaciones con datos de mortalidad del GBD 2019');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (15,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se comparan distritos afectados (AOD >0.75) vs control (AOD ≤0.75) en dos islas (Sumatra y Kalimantan), pero no se modela autocorrelación espacial ni se usan matrices de pesos.','Series temporales con datos mensuales (enero 2015 - abril 2016). Se definen dos períodos: durante incendios (junio-octubre 2015) y después (noviembre 2015 - abril 2016). Se usa modelo ANCOVA (alternativa a DID) con variable de resultado pre-incendio como control. También se presentan estimaciones DID como robustez. Se incluyen dummies mensuales (efectos fijos de tiempo).','Google Earth Engine (GEE) para procesamiento de AOD desde productos MODIS; ArcGIS para mapas. El software estadístico para los modelos ANCOVA/DID no se reporta explícitamente en el artículo','Ecológico longitudinal con datos de panel a nivel distrital. Cuasi-experimental utilizando la ocurrencia de incendios como un tratamiento natural. Modelo ANCOVA (análisis de covarianza) y DID como robustez.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (16,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (17,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (18,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers espaciales). Los análisis se realizan por separado para cinco distritos y luego se agrupan mediante metaanálisis de efectos aleatorios. Se calcula heterogeneidad entre ubicaciones (I², Q, τ²) pero no se modela autocorrelación espacial.','Series temporales con datos diarios. Se examinan lags acumulativos de 0-1, 0-2, 0-3 y 0-4 días. Se ajusta por tendencia a largo plazo (spline natural con 3 df por año), estacionalidad, temperatura con B-spline (33° y 66° percentiles para temperaturas bajas y altas), días festivos, indicador de brote H1N1 2009, cambio en sistema de reporte post-2012, y días de la semana.','R versión 4.0.4 (paquetes: splitr para trayectorias HYSPLIT, meta para metaanálisis); Python para automatización de identificación de días con quema de biomasa.','Ecológico (series temporales) con análisis de dos etapas: (1) regresión quasi-Poisson por distrito; (2) metaanálisis de efectos aleatorios para agrupar estimaciones. Se incluye interacción entre indicador de día de quema y PM10 no-biomasa.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (19,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Es un estudio de un solo distrito/ciudad (Lampang). No se comparan múltiples ubicaciones ni se modela autocorrelación espacial.','Series temporales con datos diarios (enero 2014 - diciembre 2017). Se examinan lags simples (lag0, lag1, lag2, lag3, lag4) y lags acumulativos promedio móvil (lag01, lag02, lag03, lag04). Se controla por tendencia a largo plazo y estacionalidad usando spline natural de tiempo (7 df por año).','No reportado. Se menciona el uso de GLM con splines naturales, pero no se especifica el paquete estadístico.','Ecológico (series temporales) con regresión de Poisson usando GLM y splines naturales. Se analizan datos agregados de visitas hospitalarias diarias por enfermedades respiratorias.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (20,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). El análisis espacial se limita a la agrupación geográfica de resultados por país, región UN y nivel de GDP mediante metaanálisis de efectos aleatorios. No se modela autocorrelación espacial ni se usan matrices de pesos espaciales entre ubicaciones.','Series temporales con datos diarios (períodos superpuestos 2000-2016). Se examina efecto acumulativo de lag 0-2 días (promedio móvil de exposición en día actual y dos días anteriores). Se ajusta por tendencia a largo plazo y estacionalidad con spline natural de tiempo (8 df por año), temperatura media en lag 0-2 días (spline natural con 3 df), y día de la semana.','R versión 4.2.2 (paquetes: dlnm para distributed lag models, mixmeta para metaanálisis de efectos mixtos)','Ecológico (series temporales) de dos etapas: (1) regresión quasi-Poisson con distributed lag model para cada ubicación; (2) metaanálisis de efectos aleatorios para agrupar estimaciones a nivel país, región y global. Se usó best linear unbiased predictions para países con pocas ubicaciones.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (21,'CE4','CE4','CE4','CE4');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (22,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers espaciales en modelos). Se utilizaron buffers circulares de 100 km y 75 km alrededor del distrito para contar incendios (totales y en dirección del viento) y se crearon cuñas de viento (90° de ancho) para el análisis upwind, pero no se modeló autocorrelación espacial ni se usaron matrices de pesos.','Series temporales con datos diarios (2012-2020). Se examinaron lags individuales de 0 a 7 días y lag acumulativo 0-1 días. Se usaron modelos distribuidos no lineales penalizados (P-splines) para temperatura (lag hasta 21 días) y lluvia (lag hasta 7 días). Se controló tendencia a largo plazo y estacionalidad con spline natural de 7 df por año, y día de la semana.','R versión 4.2.0; RStudio; paquetes: buffeRs (v0.31), splines (v4.2.0), mgcv (v1.8-40), dlnm (v2.4.7)','Ecológico (series temporales) con regresión quasi-Poisson y modelos de lag distribuido penalizado (P-splines). Se incluyó offset logarítmico por población-anual en riesgo.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (23,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se usaron cuencas atmosféricas (air basins) como unidad de análisis, agregando datos de ZCTA mediante promedio ponderado por población. Se excluyeron 4 cuencas sin eventos de humo. No se modeló autocorrelación espacial ni se usaron matrices de pesos.','Series temporales con datos diarios (junio-diciembre 2016-2019). Se examinaron lags simples (0,1,2,7,10,14 días) y acumulativos (0-1, 0-2 días). Se ajustó por tendencia estacional con spline cúbico natural (2-4 df por año según qAIC), temperatura aparente en lag 0, día de semana y días festivos.','R versión 4.2.1 (paquete mixmeta para metaanálisis); SAS versión 9.4 para limpieza de datos de salud.','Ecológico (series temporales) de dos etapas: (1) regresión quasi-Poisson por cuenca atmosférica; (2) metaanálisis de efectos aleatorios para combinar estimaciones. Se usó offset logarítmico de población.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (24,'CE4','CE4','CE4','CE4');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (25,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers espaciales). Se agregaron datos de censos a nivel de condado y se analizaron 11 condados por separado con modelos GAM, luego se agruparon mediante metaanálisis de efectos aleatorios. No se modeló autocorrelación espacial entre condados.','Series temporales con datos diarios (2010-2020). Se examinaron lags 0,1,2 días y promedio móvil de 11 días. Se ajustó por tendencia estacional con spline cúbico cíclico de día del año (1-365/366), año (2010 como referencia), día de semana, y se usó offset logarítmico de población.','R versión 4.0.5 (paquetes: mgcv para GAM, meta para metaanálisis, sf para espacial, ggplot2, ggmap, patchwork)','Ecológico (series temporales) con modelos GAM de regresión binomial negativa. Metaanálisis de efectos aleatorios (inverse variance method) para agrupar estimaciones de 11 condados. Se evaluó interacción entre presencia de humo (variable binaria) y período pandemia (indicador binario desde 5/mar/2020).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (26,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers en modelos). Los análisis se realizaron por separado en 510 regiones inmediatas (unidades geográficas brasileñas) y luego se agruparon mediante metaanálisis de efectos aleatorios. Se presentan mapas de distribución espacial de pérdidas económicas atribuibles, pero no se modeló autocorrelación espacial ni se usaron matrices de pesos.','Series temporales con datos diarios (2000-2016). Se examinaron lags de 0, 1 y 2 días. Se controló por tendencia a largo plazo y estacionalidad usando spline natural con 7 df por año, temperatura media (3 df), humedad relativa (3 df), y día de la semana. Se usó modelo quasi-Poisson.','R versión 3.6.2 (paquete mixmeta versión 1.0.8 para metaanálisis y meta-regresión)','Ecológico (series temporales) de dos etapas: (1) regresión quasi-Poisson por región inmediata; (2) metaanálisis de efectos aleatorios para agrupar a nivel nacional. Se usó meta-regresión para evaluar modificación por sector económico. Se calcularon pérdidas económicas usando valor estadístico de la vida (VSL) ajustado por edad.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (27,'No se realizó análisis espacial explícito (no kriging, GWR, clustering). Se usaron códigos postales (zip codes) como unidad de análisis, agregando desde celdas CMAQ de 12×12 km² mediante intersección de áreas ponderadas. No se modeló autocorrelación espacial ni matrices de pesos. Se utilizó interpolación por distancia inversa ponderada (IDW) para variables meteorológicas y ozono.','Series temporales con datos diarios para calibración (2016). Para análisis de salud: datos mensuales (agosto, octubre, noviembre). Se examinaron efectos de PM2.5 de incendios en hospitalizaciones mensuales usando modelo ZINB. No se evaluaron lags intra-mensuales por agregación mensual de datos de salud. Se controló por tendencia estacional mediante variables seno/coseno del día del año.','No reportado explícitamente. Se mencionan: random forest (RF), gradient boosting machine (GBM), feed-forward deep neural networks (DNN) y GLM para ensemble. Se usó grid search para hiperparámetros. Probablemente R o Python.','Estudio de calibración de exposición + análisis de efectos en salud. Para calibración: ensemble de machine learning. Para efectos en salud: modelo de regresión Zero-Inflated Negative Binomial (ZINB) con datos mensuales agregados por código postal, con offset poblacional.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (28,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers espaciales). Se compararon dos grupos de municipios (casos: productores de caña; controles: no productores) mediante prueba de Mann-Whitney. No se modeló autocorrelación espacial. Se presentó mapa de localización geográfica de municipios. Los propios autores reconocen como limitación la imposibilidad de espacializar la influencia de focos de calor sobre los agravos respiratorios.','Series temporales con datos mensuales (2008-2018). Se analizó el comportamiento estacional de hospitalizaciones y focos de calor mediante gráficos de serie histórica y distribución mensual. No se utilizaron modelos con lags ni se estimaron retardos. No se controló por tendencia a largo plazo ni estacionalidad mediante splines (solo descripción gráfica).','No reportado. Se utilizó prueba no paramétrica de Mann-Whitney y correlación de Pearson. Software estadístico no especificado.','Ecológico de series temporales con enfoque comparativo (casos vs controles). Se compararon tasas de hospitalización entre municipios productores de caña (expuestos a quema de biomasa) y no productores (no expuestos). También se analizó correlación entre focos de calor y hospitalizaciones.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (29,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Los análisis se realizaron por separado en 510 regiones inmediatas (unidades geográficas brasileñas) y luego se agruparon mediante metaanálisis de efectos aleatorios. Se presentan mapas de distribución espacial de PM2.5 y tasas de mortalidad, pero no se modeló autocorrelación espacial ni se usaron matrices de pesos.','Series temporales con datos diarios (2000-2016). Distributed lag model con lag de 0 a 14 días (seleccionado por comparación con lags máximos 7, 10, 14 días). Función cross-basis: lineal para PM2.5, spline cúbico natural para lag con 4 df. Se ajustó por promedios móviles de 21 días de temperatura (spline 3 df), 7 días de humedad relativa (spline 3 df), día de semana, días festivos, y spline de tiempo con 7 df por año.','R versión 3.6.1 (paquetes: dlnm para distributed lag model, mvmeta para metaanálisis y meta-regresión)','Ecológico (series temporales) de dos etapas: (1) regresión quasi-Poisson por región inmediata con distributed lag model; (2) metaanálisis de efectos aleatorios para agrupar a nivel nacional. Se calcularon fracciones atribuibles, muertes atribuibles y tasas atribuibles por millón.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (30,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (31,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se incluyeron efectos fijos de condado (20 condados) para controlar heterogeneidad espacial no observada, pero no se modeló autocorrelación espacial ni se usaron matrices de pesos. Se presentó mapa de ubicación de condados.','Series temporales con datos diarios (1 febrero a 31 diciembre 2020). Promedios móviles para capturar efectos retardados basados en período de incubación de COVID-19: lags 0-7, 0-14, 0-21 días. Término autoregresivo de primer orden (casesit-1) para controlar autocorrelación. Efectos fijos de día (dayt). No se usaron splines para tiempo.','R versión 3.5.2 (paquetes: mgcv para GAM, plm para FGLS)','Ecológico (series temporales) con dos enfoques: (1) Generalized Additive Models (GAM) con distribución gaussiana y función de enlace logarítmica, con splines para temperatura, precipitación y velocidad del viento; (2) Feasible Generalized Least Squares (FGLS) como análisis de sensibilidad. Efectos fijos de condado y día.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (32,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se analizaron 8 provincias por separado y luego se agruparon mediante metaanálisis. Se presentó mapa de ubicación de estaciones de monitoreo, pero no se modeló autocorrelación espacial ni se usaron matrices de pesos espaciales.','Series temporales interrumpidas (ITS) con datos diarios para enero-abril (temporada de quemas) de 2014-2018. Variable binaria para la prohibición (antes/después de mayo 2016). Ajuste por tendencia temporal estacional con spline cúbico natural del día de temporada (2 df). Se incluyeron día de semana, días festivos y temperatura con promedio móvil de 3 días (spline 3 df). No se evaluaron lags de contaminantes porque la exposición es la política.','R versión 3.5.1 (paquetes: tsModel, metafor)','Ecológico de series temporales interrumpidas (cuasi-experimental) con metaanálisis para agrupar estimaciones provinciales. Modelo quasi-Poisson para sobredispersión. Control negativo: enfermedades gastrointestinales (K00-K99).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (33,'No realizado (no se utilizó kriging, GWR, clustering, buffers, ni modelos de autocorrelación espacial). El análisis se realizó a nivel de ciudad (Calgary) utilizando promedios de estaciones de monitoreo.','Series temporales con datos diarios (1 agosto - 30 septiembre 2015). Se definieron tres períodos: pre-incendio (1-23 agosto), durante incendio (24-31 agosto), post-incendio (1-30 septiembre). Se evaluaron lags de 0 a 5 días y promedio móvil de 3 días; mejor ajuste con lag2 (promedio de PM2.5 del día anterior y del mismo día). Se utilizaron años control 2014 y 2016.','R versión 3.4.2','Cuasi-experimental (series temporales interrumpidas) con regresión quasi-Poisson y modelo aditivo generalizado (GAM). Se comparó el año del incendio (2015) con años control (2014, 2016) mediante ratio de riesgos relativos (RRR).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (34,'Clustering no supervisado mediante algoritmo k-means (distancia euclidiana) para agrupar municipios del Estado de Pará según coordenadas geográficas de focos de calor. Método del codo (elbow method) para determinar k=10 clusters. Se seleccionaron dos clusters para comparación: cluster 1 (alta frecuencia de incendios) y cluster 4 (baja frecuencia). No se utilizó kriging, GWR ni buffers.','Series temporales mensuales (2015-2019) para hospitalizaciones respiratorias e incendios. Lag de 6 meses identificado mediante función de correlación cruzada (cross-correlation). Modelo ARIMAX (Auto-regressive Integrated Moving Average with Exogenous variable) para evaluar la contribución de incendios (variable exógena) en hospitalizaciones respiratorias, controlando autocorrelación serial. Diferenciación (d=1) para estacionariedad en cluster 1.','No reportado. Se utilizaron técnicas de KDD y machine learning (k-means, ARIMAX). Software no especificado explícitamente.','Estudio ecológico retrospectivo con enfoque de descubrimiento de conocimiento (KDD). Clustering no supervisado (k-means) para identificar grupos de municipios con alta y baja exposición a incendios, seguido de series temporales (ARIMAX) y análisis de riesgo de mortalidad (Incidence Rate Ratio).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (35,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (36,'CE1','CE1','CE1','CE1');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (37,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se compararon dos regiones (Santiago y Valparaíso) por separado, pero no se modeló autocorrelación espacial ni se usaron matrices de pesos. Se utilizó el número de incendios como variable independiente a nivel regional agregado.','Series temporales con datos mensuales (enero 2010 a diciembre 2013). No se evaluaron lags intra-mensuales porque los datos están agregados por mes. Modelo GAM con splines para ajustar por estacionalidad (función de suavizado f(t;λ)). No se incluyeron lags específicos de exposición.','R, paquete mgcv (función GAM)','Ecológico de series temporales con comparación geográfica (dos regiones). Modelo aditivo generalizado (GAM) mixto con distribución Poisson para estimar riesgos relativos, ajustando por PM10, número de incendios, temperatura, precipitación, población y función de suavizado temporal.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (38,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers en el análisis principal). Se estratificó por 5 regiones brasileñas y se incluyeron términos espaciales en el modelo (latitud, longitud, estado, variable binaria para municipios capitales). Metaanálisis de efectos aleatorios para agrupar estimaciones regionales a nivel nacional. No se modeló autocorrelación espacial entre municipios.','Series temporales con datos diarios (2008-2018). Diseño caso-cruce estratificado por tiempo (time-stratified case-crossover) con emparejamiento por día de semana, mes y año. Se evaluaron promedios móviles de 1 a 5 días. El diseño case-crossover controla estacionalidad y tendencias mediante el emparejamiento (sin necesidad de splines para tiempo).','R (paquete Survival, función clogit para regresión logística condicional); metaanálisis con efectos aleatorios.','Caso-cruce estratificado por tiempo (time-stratified case-crossover) con regresión logística condicional. Cada caso (día de hospitalización) emparejado con 3-4 días control (mismo día de semana, mes, año). Ajustado por otros contaminantes, variables meteorológicas, topográficas y espaciales.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (39,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se estratificó por 5 regiones brasileñas y se usó metaanálisis de efectos aleatorios para agrupar estimaciones municipales a nivel regional y nacional. No se modeló autocorrelación espacial ni se usaron matrices de pesos.','Series temporales con datos diarios (2000-2015). Se evaluaron lags simples de 0 a 7 días y promedios móviles acumulativos de 0-1 a 0-7 días. Lag 0-1 (promedio móvil de 2 días) como el de mejor ajuste. Ajuste por tendencia a largo plazo y estacionalidad con spline natural de tiempo con 7 df por año.','R (paquete mvmeta para metaanálisis y meta-regresión)','Ecológico (series temporales) de dos etapas: (1) regresión quasi-Poisson por municipio (1814 municipios); (2) metaanálisis de efectos aleatorios para agrupar a nivel regional y nacional. Meta-regresión para comparar subgrupos (sexo, edad, región).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (40,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se analizaron 749 ciudades individualmente y luego se agruparon por país, región WHO y nivel de GDP mediante metaanálisis de efectos aleatorios. No se modeló autocorrelación espacial entre ciudades. Se presentó mapa mundial con niveles máximos de PM2.5 de incendios.','Series temporales con datos diarios (períodos superpuestos 2000-2016 según ciudad). Se evaluaron lags simples de 0 a 7 días y promedios móviles acumulativos (lag 0-1, 0-2, etc.). Se seleccionó lag 0-2 días (promedio móvil de 3 días) como el de mejor ajuste. Ajuste por tendencia a largo plazo y estacionalidad con spline natural de tiempo con 7 df por año.','R versión 4.0.1 (paquete mvmeta para metaanálisis)','Ecológico (series temporales) de dos etapas: (1) regresión quasi-Poisson por ciudad (749 ciudades en 43 países); (2) metaanálisis de efectos aleatorios para agrupar a nivel global, nacional, por región WHO y por nivel de GDP.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (41,'Mapeo de zonas con Arc-GIS. Se crearon capas temáticas clasificando distritos según nivel de hotspots (bajo <42, moderado 43-137, alto >137) y según casos de trastornos respiratorios. No se utilizaron métodos de interpolación espacial (kriging), clustering estadístico avanzado, GWR ni buffers de distancia.','Comparación anual (2014-2018) de número de hotspots y casos de trastornos respiratorios. No es un análisis de series temporales con lags diarios; los datos son agregados por año. No se evalúan lags entre exposición y respuesta.','Arc-GIS (para mapeo y zonificación); Microsoft Excel (para organización de datos)','Ecológico descriptivo con análisis espacial básico. Se comparan visualmente mapas de hotspots y trastornos respiratorios por distrito y por año. No se realiza modelamiento estadístico de asociación.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (42,'No se realizó análisis espacial explícito (no kriging, GWR, clustering, buffers). Se agregaron datos de 36 ZCTAs del condado, primero para todas y luego restringido a 11 ZCTAs de valle (baja altitud). No se modeló autocorrelación espacial ni se usaron matrices de pesos espaciales.','Series temporales con datos semanales (2013-2018, 314 semanas). Modelo Box-Jenkins transfer function para controlar autocorrelación (tendencias, ciclos, persistencia). Se evaluó exposición en la misma semana (lag 0), semana siguiente (lag 1) y dos semanas después (lag 2). Para el Carr Fire también se usó la misma semana. No se evalúan lags en días.','No reportado. Se usó spatiotemporal multiple imputation para exposición y Box-Jenkins transfer function models. Software no especificado explícitamente.','Ecológico (series temporales) con modelos Box-Jenkins transfer function. Se analizó la asociación entre semanas con alta concentración de PM2.5 de incendios (≥5.5 µg/m³, promedio semanal) y visitas a emergencias y mortalidad. Se controló por temperatura y autocorrelación.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (43,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (44,'No aplica (no se realizó análisis espacial como kriging, GWR, clustering espacial o buffers). Se utilizó una ponderación por distancia (radio de 5 km desde cada monitor al domicilio del paciente) para estimar exposición poblacional, pero no es un análisis espacial estadístico.','Series temporales con correlación cruzada, lags (0, 0–2, 0–6 días), autocorrelación (ACF, PACF), términos autorregresivos (lags 1–10 de visitas).','R (paquetes: mgcv, mgcv.helper, TSA); SAS 9.4','Ecológico de series temporales (time-series ecological study)');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (45,'No aplica (no se realizó análisis espacial como kriging, GWR, clustering espacial o buffers). Se asignó a cada provincia el valor medio diario de los monitores dentro de sus límites, pero sin métodos geoestadísticos explícitos.','Series temporales con lags (0 a 5 días, individuales y acumulativos), uso de splines cúbicos (7 nudos por año) para ajustar estacionalidad y tendencia, términos autorregresivos implícitos mediante escalamiento de errores estándar (Pearson Chi-squared-based dispersion).','Stata versión 15','Ecológico de series temporales (ecological time series analysis)');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (46,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (47,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (48,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (49,'No aplica. No se realizó análisis espacial (kriging, GWR, clustering espacial, buffers). El estudio es puramente temporal a nivel de ciudad.','Series temporales con lags de 0 a 7 días, regresión de Poisson, ajuste por días de la semana, feriados y tendencia (número de días desde el inicio del período).','Statistica v.7 (StatSoft, USA)','Ecológico de series temporales (ecological time-series study)');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (50,'Kriging ordinario (ordinary kriging) para interpolar PM2.5 de monitores terrestres a una cuadrícula de 15×15 km. Posteriormente, concentraciones a nivel de código postal (ZIP code) mediante promedio ponderado por población y área de solapamiento entre celdas y códigos postales. No se utilizaron GWR, clustering espacial ni buffers (salvo para asignar monitores de ozono y meteorología).','Series temporales con lags distribuidos (lag 0 a lag 3 para FEV1). Para ACT/CACT se usaron promedios en ventanas de 0–33 días (y subventanas 0–7 y 8–33). Modelos de efectos mixtos con intercepto aleatorio por sujeto. Ajuste por mes calendario, edad (spline natural con 3 df), temperatura y precipitación (lags 0 y 1), ozono y PM2.5 sin humo (lags 0–3).','R versión 3.3.2 (paquetes: nlme para lme, MASS para glmmPQL)','Estudio de cohorte retrospectivo con medidas repetidas (retrospective cohort study)');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (51,'Agregación espacial mediante bounding boxes (cuadrícula variable de aproximadamente 3,800 mi² por celda, basada en grados de latitud/longitud). 38 celdas para cubrir California. No se utilizan Kriging, GWR, clustering espacial ni buffers.','Series temporales diarias. Modelo de efectos mixtos con corrección de autocorrelación mediante proceso autorregresivo (AR) en los residuos.','R (implementación de Structural Topic Model — STM, y modelo lineal de efectos mixtos)','Estudio predictivo y correlacional utilizando datos crowdsourced (redes sociales) combinados con datos de monitores terrestres. No es un diseño epidemiológico clásico.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (52,'CE4','CE4','CE4','CE4');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (53,'No se realizó análisis espacial (kriging, GWR, clustering, buffers). Los datos de contaminantes se asignaron a partir de una estación de monitoreo central por comunidad (resolución LHA — local health area). No se utilizaron métodos geoestadísticos.','Series temporales diarias (2003–2015). Modelos de regresión de Poisson con ajuste por año/mes (categórico), día de la semana, feriados. Lags evaluados: mismo día (lag 0), promedios móviles 0–1 días y 0–4 días en sensibilidad. Estratificación por tres estaciones mutuamente excluyentes: invierno (humo de leña: octubre–enero), primavera (polvo de caminos: marzo–abril), verano (humo de incendios: julio–agosto). Metaanálisis de efectos aleatorios para estimación agrupada.','R (programación estadística)','Ecológico de series temporales (time-series ecological study) con siete comunidades en Columbia Británica, Canadá. Dos etapas: modelos por comunidad + metaanálisis de efectos aleatorios.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (54,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (55,'No se realizó análisis espacial como kriging, GWR, clustering o buffers. Se utilizó un monitor urbano por ciudad (Atlanta, Birmingham, St. Louis, Dallas). La comparación de perfiles de fuentes entre ciudades se basó en diferencias normalizadas (nRMSD) y correlaciones, pero no es un análisis espacial de interpolación o modelado de superficies.','Series temporales diarias con lags de 0 a 3 días. Modelos de regresión de Poisson sobredispersa con ajuste por tendencias temporales (splines cúbicos de tiempo, 1 df/mes), día de la semana, feriados, estación, temperatura máxima (lag 0) y mínima (lags 1–2), punto de rocío (lags 0–2), e interacciones estación × temperatura, estación × día de semana, estación × feriados. No se usaron promedios móviles por datos cada tercer día en tres ciudades.','No reportado explícitamente. Modelos estadísticos de Poisson con splines y pruebas chi-cuadrado. Probable R, SAS o Stata.','Ecológico de series temporales con datos de cuatro ciudades de EE.UU. No hay segunda etapa de metaanálisis formal; se comparan resultados entre ciudades con pruebas de heterogeneidad.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (56,'Agregación espacial: datos de modelo GEOS-Chem en grilla de 0.5°×0.67° (~50×75 km) convertidos a nivel de condado mediante promedio ponderado por área. No se utilizaron Kriging, GWR, clustering espacial ni buffers. Se compararon áreas urbanas/rurales pero sin técnicas geoestadísticas.','Series temporales con definición de \'smoke wave\' (≥2 días consecutivos con PM2.5 de incendios >20 µg/m³). Se analizó solo el mismo día (lag 0). Diseño de casos emparejados (matched analysis) comparando días con smoke wave vs días sin smoke wave (hasta 3 emparejamientos por día, dentro de una ventana de ±7 días, principalmente en otro año). Se ajustó por año y temperatura. No se usaron lags acumulativos.','R versión 2.15.0','Estudio ecológico de series temporales con emparejamiento (matched case–control design sobre días). Se compararon tasas de admisión hospitalaria en días con smoke wave vs días sin smoke wave emparejados por condado, año y estacionalidad.');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (57,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (58,'Modelo de predicción de exposición espaciotemporal basado en machine learning (Generalized Boosting Model — GBM). Variables espaciales: coordenadas X e Y, elevación, tipos de uso de suelo en 1 km, densidad de tráfico, AOD del satélite GOES. Exposición asignada al centroide ponderado por población de cada código postal (ZCTA). No se usaron Kriging, GWR, clustering ni buffers como métodos principales, pero el modelo incorporó información espacial explícita.','Series temporales diarias con promedio móvil de los dos días anteriores (lags 1 y 2, excluyendo el mismo día). Se evaluaron tres períodos: pre-incendios (6 mayo–19 junio), durante incendios (20 junio–31 julio), post-incendios (1 agosto–15 septiembre). Spline cúbico natural de fecha juliana con 3 df para tendencia temporal. Indicadores de día de semana y feriados.','R versión 2.15.3 (paquetes para GEE, GBM). ArcGIS 10.1 para asignación espacial.','Ecológico de series temporales con ecuaciones de estimación generalizadas (GEE) de Poisson. Se evaluó interacción entre PM2.5 y período (antes/durante/después de incendios).');
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (59,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P1` (`idArticulo`,`analisis_espacial`,`analisis_temporal`,`software`,`diseno_estudio`) VALUES (60,'No reportado (análisis a escala de ciudad, sin desagregación espacial interna)','Series temporales diarias; análisis de lags 0 a 4 días para PM2.5 y PM10; estratificación por días con y sin advección de biomasa; lag 1 de la variable dependiente incluido para corrección de autocorrelación.','SPSS v22; Stata/SE 11.2','Ecológico de series temporales.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (61,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (62,'PM10 (<10 μm), estimado a partir de AOD satelital. Fire hotspot counts como proxy de actividad de fuego. No se analizan PM2.5, CO, NO2 ni AOD directamente (AOD es insumo para estimar PM10).','Datos satelitales (AERONET AOD, Himawari-8 AHI). No se usan estaciones terrestres ni sensores IoT. ERA5-Land para temperatura y humedad relativa (covariables, no contaminantes).','AERONET (AOD); Himawari-8 Advanced Himawari Imager (AHI) para estimación de PM10; NASA FIRMS / MODIS para conteos diarios de focos de calor activo por subdivisión.','Puskesmas (centros de salud primaria públicos) de Kalimantan Central. Datos manuscritos transcritos a formato digital. 6 puskesmas incluidas. No se usan hospitales.','ERA5-Land: temperatura media diaria y punto de rocío (para derivar humedad relativa). Albedo (para ajustar AOD, ecuación 2).','Población general que acude a puskesmas por problemas respiratorios. Sin restricción etaria. Palangka Raya City (293,457 hab.) y Pulang Pisau Regency (134,499 hab.).','Subdivisión administrativa de segundo nivel (city y regency). Puskesmas agrupadas por subdivisión.','Diaria (visitas respiratorias, PM10, focos de calor).','Indonesia — Provincia de Central Kalimantan. Subdivisiones: Palangka Raya City y Pulang Pisau Regency.','2015-07 a 2019-12 (global). Por puskesmas: Kereng Bangkirai 2015-07/2017-07; Menteng 2015-07/2019-12; Tangkiling 2017-01/2019-12; Bereng 2015-07/2019-12; Bukit Rawi 2016-01/2019-12; Pulang Pisau 2015-07/2017-09.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (63,'CO (monóxido de carbono): XCO (column-averaged dry-air mole fraction, ppb) de MOPITT y columna total CO del FTIR. PM2.5 mencionado solo en discusión comparativa. No se analizan PM10, NO2, AOD ni O3.','Datos satelitales (MOPITT v9 L3 TIR-NIR producto mensual) como fuente principal. Estación FTIR terrestre en TAO (University of Toronto, 43.66°N, 79.4°W, 174 msnm) con código SFIT4 — usada como validación independiente. No se usan estaciones de superficie de CO ni reanálisis para contaminantes; solo se aplicó detrending norteamericano (−0.57%/año, Buchholz et al., 2021).','MOPITT (Measurements of Pollution in the Troposphere) en satélite Terra (NASA/CSA) — producto v9 L3 TIR-NIR mensual conjunto, huella 22×22 km. MODIS (área quemada) — solo en figura suplementaria A4 para asociación visual con actividad de fuego, no fuente principal. NOAA HMS — mencionado solo en discusión comparativa, no usado.','CIHI National Ambulatory Care Reporting System (NACRS) — admisiones diarias a urgencias agregadas a mensuales por código ICD-10 y zona sanitaria. No es exclusivamente IRA: 9 grupos CV/respiratorios (hipertensión, cardiopatía isquémica, arritmia, falla cardíaca, cerebrovascular, neumonía, IRAB, EPOC, asma — Tabla A1). Datos sin estratificación por edad/sexo; celdas <5 suprimidas (reemplazadas por 4).','Población por zona sanitaria de AHS (Alberta Health Services) y PHO (Public Health Ontario) — para normalizar admisiones por 100,000. Área quemada MODIS (julio–septiembre 2004–2019) para Canadá y Continental USA — solo figura suplementaria. Tendencia de fondo CO de −0.57%/año (Buchholz et al., 2021) para detrending. Tabla ICD-10 siguiendo Hahn (2021) y Magzamen (2021).','Población general de Alberta y Ontario que acude a urgencias por 9 diagnósticos CV/respiratorios. Sin estratificación por edad ni sexo (limitación de datos CIHI agregados). Ontario ~12.9–14.6 millones (2009–2019); Alberta no especificada. Población total de Canadá comparable a California (~40M).','Zona sanitaria sub-provincial: 5 zonas AHS Alberta (North, Edmonton, Central, Calgary, South); 14 zonas PHO LHIN Ontario (Erie St. Clair, South West, Waterloo Wellington, Hamilton-Niagara Haldimand Brant, Central West, Mississauga-Halton, Toronto-Central, Central, Central-East, South-East, Champlain, North-Simcoe-Muskoka, North-East, North-West). Punto único en Toronto para FTIR. No se distingue urbano vs rural por el tamaño de las zonas.','Mensual. Los datos ER originales son diarios pero se agregaron a mensual para el DiD; XCO MOPITT y FTIR son mensuales. Limitación reconocida: imposibilita time-series/caso-cruzado tradicionales.','Canadá — Provincias de Alberta y Ontario. Ciudad de Toronto, ON (TAO FTIR).','Ontario admisiones: 2004-01 a 2019-12 (cerebrovascular e isquémica omitidas pre-2009 por artefacto transición ICD-9 a ICD-10). Alberta admisiones: 2010-01 a 2019-12 (disponibilidad limitada). MOPITT y FTIR Toronto: 2004-01 a 2019-12. Datos 2020 excluidos por anomalías COVID-19. Pre-2012: hasta 2011-12-31; post-2012: desde 2012-01-01.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (64,'PM2.5 (μg/m³) como contaminante de interés (variable dependiente) y AOD a 550 nm como variable intermedia/predictor recuperada del satélite. No se analizan PM10, CO, NO2 ni O3.','Datos satelitales (Himawari-9 AHI) para reflectancia TOA y recuperación de AOD. Reanálisis ERA5 para variables meteorológicas (temperatura, humedad relativa, presión superficial, velocidad del viento, precipitación). Estación de superficie del Pollution Control Department en Chang Phueak, Chiang Mai — único punto de medición directa de PM2.5, usado para entrenamiento y validación. No se usan redes de monitoreo distribuido ni sensores IoT.','Himawari-9 AHI (Advanced Himawari Imager) — canales azul (0.47 μm), rojo (0.64 μm) y SWIR (2.3 μm). MODIS no se utiliza (mencionado solo en introducción comparativa). VIIRS no se utiliza. 6S no es satélite, es modelo radiativo.','Chiang Mai Provincial Health Office — registros mensuales de admisiones hospitalarias para asma, EPOC (enfermedad pulmonar obstructiva crónica), neumonía e influenza. No es específicamente IRA (infecciones respiratorias agudas), pero incluye enfermedades respiratorias crónicas y agudas. No se usan MINSA, postas ni registros clínicos individuales.','ERA5: 5 variables meteorológicas (temperatura, humedad relativa, presión superficial, velocidad del viento, precipitación). Población de Chiang Mai (denominador para normalizar admisiones por 100,000) — fuente no especificada. Estación PCD Chang Phueak (PM2.5 en superficie) para entrenamiento y validación. Modelo radiativo 6S vía interfaz Py6S — para construir tabla de búsqueda (LUT) de AOD. Perfiles de aerosol estacionales: biomass burning para febrero–abril, continental para meses no-haze.','Población general de la provincia de Chiang Mai que requiere hospitalización por enfermedades respiratorias. No se segmenta por edad, género ni grupo vulnerable, aunque se menciona que asma y EPOC son enfermedades crónicas más influenciadas por exposición acumulativa.','Provincial (Chiang Mai Province) para admisiones hospitalarias. Resolución de pixel Himawari-9 (~2 km en banda visible) para reflectancia TOA y AOD. Punto único (estación Chang Phueak) para validación PM2.5. No reportado en km² explícito; sin desagregación por distritos o municipios.','Original: 10 minutos (Himawari-9 AHI). Resampleada a horaria para consistencia con ERA5 y QC. Mensual para promedios de PM2.5, admisiones hospitalarias y análisis exposición-respuesta. No se usa resolución diaria ni semanal en el análisis de salud.','Tailandia — Provincia de Chiang Mai, en el norte del país (región montañosa de valle).','Año único: 2023 (enero–diciembre). Temporada de quema: febrero–abril 2023; no-haze: mayo 2023–enero 2024 (resto del año). Limitación reconocida: dataset de un solo año restringe robustez interanual.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (65,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (66,'Smoke-specific PM2.5 (particulate matter con diámetro aerodinámico <2.5 μm proveniente de humo de incendios).','Estimaciones diarias de PM2.5 de humo a nivel de condado de Childs et al. 2022 — modelo de machine learning entrenado con: ground measurements (monitores), satellite observations y reanalysis data. No se usan estaciones terrestres directamente en el modelo de exposición final del estudio — solo el producto integrado de Childs.','No se especifica el satélite concreto en el texto del artículo; se menciona \'satellite observations\' genéricamente como insumo del producto Childs et al. 2022. No se usan FIRMS, MODIS, VIIRS, Sentinel-5P ni Himawari directamente en este estudio.','Medicare inpatient claims data (US Centers for Medicare & Medicaid Services) — Medicare Provider Analysis and Review file. Hospitalizaciones no programadas (unscheduled inpatient admissions) para beneficiarios Fee-for-Service ≥65 años. Códigos ICD-9-CM e ICD-10-CM clasificados con Clinical Classifications Software (CCS) en 13 categorías de causa nivel 1, más subcausas nivel 3 con >25,000 hospitalizaciones. No es exclusivamente IRA: incluye 13 grupos amplios (cardiovascular, respiratorio, cáncer, lesiones, neuropsiquiátrico, sangre, digestivo, endocrino, genitourinario, infeccioso, musculoesquelético, sistema nervioso, piel).','PRISM (Parameter-elevation Regressions on Independent Slopes Model) — temperatura media diaria a 4 km, agregada a condado mediante promedios ponderados por población. Federal holiday indicator. Tamaño poblacional Medicare Fee-for-Service por condado (peso de regresión).','Adultos mayores (≥65 años) beneficiarios de Medicare Fee-for-Service en 11 estados del oeste de EE.UU. n=10,369,361 individuos: 4,862,826 hombres (46.9%); 5,506,535 mujeres (53.1%); 373,252 negros (3.6%); 420,577 hispanos (4.1%); 8,365,607 blancos (80.7%). Edad media 74.7 años (DE 7.9). 57.97 millones de persona-mes de seguimiento. 4.76 millones de hospitalizaciones no programadas.','Condado (414 condados en 11 estados). Estimaciones de PM2.5 originalmente en grilla de 10 km, agregadas a condado por promedios ponderados por población. Reconocida como limitación: variabilidad intra-condado no capturada.','Diaria (PM2.5 de humo, hospitalizaciones, temperatura). Limitada a temporada de incendios (mayo 1 – octubre 31) en análisis principal; sensibilidad con noviembre–diciembre.','Estados Unidos — 11 estados del oeste contiguos: Arizona, California, Colorado, Idaho, Montana, Nevada, New Mexico, Oregon, Utah, Washington, Wyoming. Análisis secundario solo California para comparación con Heft-Neal et al. 2023.','2006-05 a 2016-10 (solo temporada de incendios mayo–octubre de cada año). Análisis de sensibilidad con noviembre–diciembre.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (67,'PM2.5 (AOD-PM2.5), PM10, PM1, PM2.5-10, PM1-2.5, NO2, O3, SO2, CO, black carbon, materia orgánica, nitratos, amonio, sulfatos. También NDVI/EVI para verdor (exposición protectora, no contaminante). Wildfire smoke como componente adicional al AOD-PM2.5 en el entorno de incendios (AOD-PM2.5+smoke).','No es un estudio primario — sintetiza las fuentes usadas en los 61 estudios revisados. Los estudios primarios usaron: monitores de calidad del aire en superficie, datos satelitales AOD, modelos de land use regression (LUR), modelos jerárquicos bayesianos con kriging de AOD, modelo GEOS-Chem (química atmosférica 3D). Validación AOD-PM2.5 vs monitores: PGR2PER=81.2% (IC 95%: 79.0–83.3%). No se usan sensores IoT.','MODIS (satélites Terra y Acqua, NASA EOS) — principal instrumento en estudios revisados, para NDVI/EVI (greenness), AOD (contaminación) y atributos de incendios. NOAA HMS (Hazard Mapping System) — mencionado en estudios de incendios. NASA FIRMS — mencionado indirectamente. No se usan directamente Sentinel-5P, VIIRS, Landsat ni Himawari en los estudios revisados.','No aplica directamente. Los estudios revisados utilizaron registros hospitalarios (emergency department visits, inpatient hospitalizations), códigos ICD-9-CM (493 asma, 786.07 wheeze) e ICD-10-CM (J45, R06.2), y cuestionarios de autoreporte y proxy (padres/cuidadores). Desenlaces incluidos: asma, sibilancias (wheeze), rinitis alérgica, bronquitis, tos, función pulmonar (FEV1, FVC, FEF), FeNO, uso de medicación de rescate. No es exclusivamente IRA; asma representa 62.6% de los 198 desenlaces específicos.','Bases de datos bibliográficas: PubMed (búsqueda principal, todos los años disponibles) y Google Scholar (enero 2020 – diciembre 2023). Temperatura, humedad, nivel socioeconómico, educación, raza/etnia, ingresos, dieta antioxidante, estrés materno, lactancia materna, tabaquismo ambiental, altitud (mencionada en Xing et al. 2019 en China) y psicología (ansiedad, depresión) — reportados como covariables en estudios primarios.','Población de los 61 estudios primarios revisados: 2,821,393 participantes únicos; 13,725,971 en los 198 desenlaces específicos. Grupos: niños (incluyendo prenatales, infantes, hasta 18–20 años), adultos mayores (65–99 años), mujeres embarazadas, minorías (Black, Hispanic). Distribución por entorno: greenness (46,089), contaminación (13,237,790), incendios (442,092).','No aplica directamente (revisión). Los estudios primarios utilizaron buffers de 100 m, 250 m, 500 m, 1000 m, distritos de salud, condados y códigos postales. La revisión categoriza por país como unidad geográfica principal.','No aplica directamente (revisión). Los estudios primarios usaron resoluciones diaria, mensual y anual. Ventanas críticas de exposición: semanas de gestación (6–22, 16–25, 19–23 semanas), meses postnatales (5.5–11 meses). La revisión agrega a nivel de publicación (2009–2023).','Revisión global. Países representados: EE.UU. (24 estudios, 39.3%), China (8, 13.1%), Canadá (6, 9.8%), Italia (5, 8.2%), Australia (3, 4.9%), México (3, 4.9%), Perú (2, 3.3%), España (2, 3.3%), Taiwán (2, 3.3%), Indonesia (1, 1.6%), Lituania (1, 1.6%), Noruega (1, 1.6%), multinacionales (3, 4.9%). Clasificación: desarrollados (Canadá, Italia, Lituania, Noruega, España, EE.UU.); en desarrollo (China, Indonesia, México, Perú, Taiwán). Nota: Perú aparece con 2 estudios en entorno de contaminación (2 desenlaces SH) — relevante para el contexto andino.','Publicaciones: 2009–2023. Google Scholar: enero 2020 – diciembre 2023 (complementario). PubMed: todos los años disponibles hasta la fecha de búsqueda. Los estudios primarios incluyeron datos desde aproximadamente 2000 hasta 2019.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (68,'PM2.5 (particulate matter con diámetro <2.5 μm) como único contaminante analizado. Concentraciones anuales estimadas vía AOD satelital. No se analizan PM10, CO, NO2, O3 ni SO2.','Datos satelitales AOD de NASA para estimar PM2.5 (instrumento no especificado explícitamente; probablemente MODIS dado el período 2000–2014 y la región). Modelo de predicción AOD→PM2.5 a resolución 1×1 km², procesado con QGIS. No se usan estaciones de monitoreo terrestres de PM2.5, reanálisis atmosférico ni sensores IoT.','NASA AOD satelital — instrumento no especificado explícitamente en el texto. Grilla 1×1 km². Por período (2000–2014) y región probablemente MODIS (Terra/Aqua), pero no declarado. GADM v2.8 como capa cartográfica auxiliar. No se mencionan FIRMS, Himawari, Sentinel ni VIIRS explícitamente.','Indonesian Family Life Survey (IFLS) — Book 3A y 3B. Mortalidad determinada por seguimiento de cuestionarios y registros de defunción, clasificada según ICD-10: A00-R99 (causas naturales), I00-99 (cardiovasculares), J00-47/J80-99 (respiratorias), C34 (cáncer de pulmón), S00-T99 (causas externas). Datos IFLS disponibles públicamente en RAND Corporation. No se usan MINSA, postas ni registros hospitalarios — desenlace es mortalidad, no IRA directamente.','GADM (Global Administrative Areas Database) versión 2.8 para límites administrativos de Indonesia. Datos RAND Corporation (repositorio IFLS). Covariables del IFLS: edad, sexo, IMC, educación (<12 años, ≥12 años), nivel socioeconómico (bajo/medio/alto), tabaquismo (nunca/actual/ex), área de residencia (urbano/rural), diabetes (sí/no), hipertensión (sí/no).','Adultos ≥40 años residentes en la Isla de Sumatra. n=2,374 participantes finales del IFLS-3 (2,409 iniciales menos 15 muertos en el primer año y 20 perdidos). Distribución: 51.6% mujeres, 48.4% hombres; 73.4% entre 40–65 años, 26.6% ≥65 años; 58.4% área rural; 86.2% educación baja. 487 fallecidos durante el seguimiento (460 causas naturales, 197 respiratorias, 144 cardiovasculares, 43 cáncer de pulmón, 27 externas).','1×1 km² (grid cells) para estimación de PM2.5 vía AOD satelital. Los participantes se geocodificaron y se emparejaron con la concentración de PM2.5 correspondiente por ubicación espacial y año.','Anual (promedios anuales de PM2.5 para cada año 2000–2014). El seguimiento de mortalidad es de 14 años (2000–2014).','Indonesia — Isla de Sumatra.','2000-11 a 2014-09 (línea base IFLS-3: noviembre 2000; seguimiento hasta IFLS-5: septiembre 2014). PM2.5 estimado anualmente para cada año del período 2000–2014.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (69,'PM2.5 y otros contaminantes de incendios (CO, partículas, cenizas) mencionados conceptualmente en introducción/discusión como mecanismo de vínculo entre incendios y salud, pero NO medidos ni incluidos como variable en el modelo estadístico. La variable de exposición en el modelo son los focos de incendio (proxy). No se analizan PM10, NO2, O3 ni AOD directamente.','Datos satelitales (MODIS/AQUA_M-T) para focos de incendio. Estaciones meteorológicas automáticas (141 estaciones del INMET — Instituto Nacional de Meteorología de Brasil): temperatura, precipitación y humedad relativa, con datos minuto-a-minuto agregados a promedios horarios mensuales por estado. No se usan reanálisis atmosférico, sensores IoT ni datos de calidad del aire en superficie.','MODIS (Moderate Resolution Imaging Spectroradiometer) a bordo del satélite AQUA_M-T (NASA). Detección de focos de incendio en rango infrarrojo (0.75–1000 μm), pixel nominal 1×1 km. Satélite seleccionado por órbita regular y estable. No se mencionan FIRMS, VIIRS, Sentinel-5P, Himawari ni Landsat.','DATASUS (Departamento de Informática do Sistema Único de Saúde) — datos de morbilidad hospitalaria (hospitalizaciones) por residencia del paciente. Filtros: estados de la Amazonía Legal; grupos etarios (0–14 años y ≥60 años); ICD-10 capítulo X (J00–J99): bronquitis aguda, bronquiolitis, laringitis/traqueitis, faringitis/amigdalitis, asma, bronquiectasia, EPOC/bronquitis crónica, sinusitis, influenza, neumonía, otras enfermedades respiratorias. Datos públicamente disponibles.','INMET — 141 estaciones automáticas para temperatura, precipitación y humedad relativa. IBGE/datos oficiales — extensión territorial y población por estado para calcular tasas (incendios por 1,000 km² y hospitalizaciones por 10,000 hab.). PCA aplicado a las tres variables meteorológicas para generar ejes ortogonales. INPE — Sistema de Monitoramento de Queimadas para datos de incendios.','Residentes de los 9 estados de la Amazonía Legal. Grupos etarios: 0–14 años (desagregado en <1 año, 1–4 años, 5–9 años, 10–14 años) y ≥60 años. Ambos sexos. Total hospitalizaciones período completo: 1,532,228; en temporada de incendios: 566,707. Distribución en temporada: 1–4 años (34%, 192,296), ≥60 años (29%, 164,011), <1 año (18%, 104,391). Ratio H/M mayor en menores de 1 año (1.36) y 1–4 años (1.21).','Nivel estatal (9 estados de la Amazonía Legal) y municipal (para mapas descriptivos). También se utilizó área en km² por estado para calcular tasas de incendios por 1,000 km² y hospitalizaciones por 10,000 hab.','Mensual (agosto a diciembre, 2009–2019). Los datos meteorológicos horarios se promediaron a nivel mensual.','Brasil — Amazonía Legal (Legal Amazon). Estados: Acre (AC), Amapá (AP), Amazonas (AM), Pará (PA), Rondônia (RO), Roraima (RR), Mato Grosso (MT), Tocantins (TO), Maranhão (MA). Superficie total: ~5 millones de km² (60% del territorio brasileño).','2009-01 a 2019-12 (datos completos). Análisis principal restringido a temporada de incendios: agosto–diciembre de cada año (55 estimaciones mensuales totales).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (70,'PM2.5 (el más común, 70% de estudios), PM10, black carbon, CO, NOx, O3, SO2, VOCs, PAHs y metales traza (ej. plomo). También indicadores cualitativos como presencia de humo (smoke polygons) y eventos de incendio.','Redes de monitoreo terrestre: EPA Air Quality System, AirNow, CARB, PurpleAir (crowdsourced/bajo costo). Modelos de pronóstico: CMAQ, AIRPACT-4, HYSPLIT, BlueSky, GEOS-Chem. Sensores personales de partículas. Muestreo ambiental directo: muestras de ceniza, suelo, agua (para PAHs, VOCs, trazas). No se mencionan sensores IoT de forma generalizada excepto PurpleAir y Air Quality Eggs.','MODIS (Terra/Aqua, NASA) — para AOD (estimaciones cuantitativas de PM2.5). NOAA HMS (Hazard Mapping System) — para polígonos de humo (estimaciones cualitativas). Global Fire Emissions Database (GFED). FINN (Fire Inventory from NCAR). No se menciona explícitamente VIIRS, Sentinel-5P ni Himawari.','Datos administrativos hospitalarios (36%): EHR, visitas a urgencias, hospitalizaciones, servicios de emergencias médicas, certificados de nacimiento/muerte. Bases de datos de gobierno (16%): CDC WONDER, NHANES, BRFSS, National Healthcare Cost and Utilization Project, EPA BenMap, CDC Environmental Public Health Tracking Network, CanCHEC. Encuestas de salud (18%): autoreporte de síntomas, evacuación, salud mental. Seguros médicos/claims (7%). Vigilancia epidemiológica (11%): COVID-19, influenza, coccidioidomicosis. Datos de farmacia: dispensaciones de medicamentos para asma/EPOC. Fuentes únicas: Lumosity, Crisis Text Line, SmokeSense (EPA app).','Meteorología: NOAA NCEI, estaciones locales. Datos de población y demografía: American Community Survey, censo. Datos de comportamiento: Google Trends, Twitter, SafeGraph cell phone data, Crisis Text Line, Lumosity. Calidad del aire en interiores: sensores de bajo costo PurpleAir, Air Quality Eggs. Muestras ambientales: agua, ceniza, suelo (PAHs, VOCs, metales).','Población general, niños y adolescentes, adultos mayores, mujeres embarazadas, minorías raciales y grupos socioeconómicamente vulnerables, y pacientes con condiciones preexistentes (asma, EPOC, enfermedades cardiovasculares). También se incluyen estudios con muestras de conveniencia a través de encuestas y aplicaciones móviles.','Código postal (zip code), condado, estado, y buffers espaciales (ej. proximidad a incendios). No se especifica km² de manera uniforme.','Diaria (para exposiciones y visitas a emergencias), mensual, anual. Algunos estudios usaron agregación horaria (para sensores de bajo costo). Los datos de salud con frecuencia eran disponibles con rezago de años, excepto en estudios de vigilancia y encuestas en tiempo real.','Principalmente Estados Unidos y Canadá. También se incluyeron 11 artículos de otras regiones: Brasil, Australia, Finlandia, España, China y otros países. La revisión tuvo un enfoque en América del Norte.','Artículos incluidos publicados entre 1993 y 2022 (hasta 31 de julio de 2022). Los períodos de datos de los estudios primarios varían desde los años 1990 hasta 2021.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (71,'PM2.5 específico de incendios (wildfire-specific PM2.5, μg/m³). También se consideró non-wildfire PM2.5 en análisis de sensibilidad. No se analizaron CO, NO2, O3 ni AOD directamente como variables principales. El calor extremo se definió usando el heat index máximo diario (combinando temperatura máxima y humedad mínima relativa).','PM2.5 total: modelo ensamblado (stacked ensemble, Aguilera et al. 2022) usando monitores EPA AQS, AOD satelital NASA, plumas de humo NOAA HMS, variables meteorológicas GRIDMET y National Land Cover Database. PM2.5 específico de humo: diferencia entre PM2.5 total y PM2.5 no-incendio (estimado con Random Forest encadenado en días sin humo). Índice de calor: temperatura y humedad de reanálisis GRIDMET (4 km). No se usan sensores IoT.','NASA MODIS (AOD) como insumo para el modelo ensamblado de PM2.5 total. NOAA Hazard Mapping System (HMS) para identificación de plumas de humo. No Sentinel-5P, VIIRS, Landsat explícitamente.','California Department of Health Care Access and Information (HCAI) — Patient Discharge Data y Emergency Department Data. Hospitalizaciones no programadas (cardiorrespiratorias) por código ZIP de residencia. Clasificación: circulatorio o respiratorio según diagnóstico primario (códigos en material suplementario). Total: 18,143,419 hospitalizaciones en 995 ZCTAs 2006–2019. Aprobación ética: California CPHS (proyecto 2021-116).','Variables meteorológicas: temperatura y humedad relativa (reanálisis GRIDMET). Para características comunitarias: Decennial Census 2010 y Healthy Places Index (HPI 3.0 y 2.0) incluyendo: educación, seguro de salud, ingresos, tenencia de automóvil, cobertura de dosel arbóreo, densidad poblacional, composición racial/étnica y prevalencia de aire acondicionado por zona climática (16 zonas, Pacific Energy Center). National Land Cover Database (para modelo PM2.5). Crosswalk HUD (análisis de sensibilidad).','Población general de California en ZCTAs con población >1,000 y al menos un día en cada categoría de exposición. Se analizaron 995 ZCTAs (66.8% de la población de California). No se restringió a grupos etarios específicos.','ZCTA (ZIP Code Tabulation Area) — áreas agregadas que representan rutas de servicio postal. Resolución variable por ZCTA. También se usaron 16 zonas climáticas (Pacific Energy Center). PM2.5 modelado a nivel ZCTA desde ensemble con AOD y monitores.','Diaria (daily time-series). Los datos de hospitalización y exposición se agregaron por día-ZCTA.','Estados Unidos — California (todo el estado). 995 ZCTAs incluidas. Zonas de mayor exposición compuesta: norte montañoso y valle central.','2006-01 a 2019-12 (14 años). Período histórico para umbral de calor extremo: julio–agosto 1980–2005.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (72,'Humo de incendios forestales como exposición, medido como días con humo (smoke-day) basado en plumas visibles por satélite (NOAA HMS). Las categorías de humo (leve, medio, denso) corresponden aproximadamente a PM2.5 de 5, 16 y 27 μg/m³ respectivamente, pero el análisis primario usa presencia de cualquier categoría como smoke-day binario. No se miden directamente PM2.5, PM10, CO, NO2, O3 ni AOD.','NOAA HMS (Hazard Mapping System) Fire and Smoke product — plumas de humo visibles via imágenes satelitales, disponible públicamente (EPA Environmental Dataset Gateway). Datos de smoke-days por ZCTA previamente generados por Liu et al. 2017 y reutilizados en este estudio. No se usan estaciones terrestres de monitoreo, reanálisis atmosférico ni sensores IoT.','NASA satellite imagery-based Hazard Mapping System (HMS) Fire and Smoke product. No se mencionan explícitamente MODIS, FIRMS, VIIRS, Sentinel-5P ni Himawari.','IBM MarketScan Commercial Claims and Encounters Research Database — datos de reclamaciones de prescripciones (prescription claims). Primera prescripción en tres categorías: (1) vías respiratorias superiores (ej. cetirizina, mometasona), (2) vías respiratorias inferiores (ej. albuterol sulfato), (3) antiinflamatorios sistémicos (ej. metilprednisolona, prednisolona). Clasificación validada por dos médicos usando Micromedex RedBook y UpToDate. No se usan MINSA, postas ni registros hospitalarios abiertos.','Ingreso medio del hogar por MSA (American Communities Survey 2008–2012) como proxy de SES en análisis de sensibilidad. HUD crosswalk files anuales para asignar ZCTAs a MSAs. Datos de población ZCTA del censo para ponderación de exposición. Códigos ICD-9/ICD-10 para estimar fechas de nacimiento y edad gestacional. Micromedex RedBook — clasificación de medicamentos. No se incorporan covariables meteorológicas.','Lactantes nacidos entre 2010–2016 en seis estados del oeste de EE.UU.: California, Oregon, Washington, Idaho, Montana, Nevada. Con seguro privado continuo y al menos 1 semana de cobertura de prescripción desde el nacimiento. Cohorte completa: n=182,387 (48.8% femenino). Subcohorte con edad gestacional estimable: n=113,154. Distribución GA: <28 semanas (0.2%), 28–36 semanas (4.6%), >36 semanas (57.1%). Solo niños con seguro privado — excluye Medicaid, Medicare y no asegurados.','MSA (Metropolitan Statistical Area) — unidad espacial agregada (~9,600 km² promedio). 60 MSAs en la región de estudio. Exposición originalmente a nivel ZCTA, agregada a MSA mediante ponderación poblacional.','Semanal (average weekly smoke-days) para períodos de exposición (trimestres y ventanas postnatales). El análisis de tiempo hasta el evento se realizó con tiempo en semanas.','Estados Unidos — seis estados del oeste: California, Oregon, Washington, Idaho, Montana, Nevada (60 áreas metropolitanas).','2010-01 a 2016-12 (nacimientos); seguimiento hasta 2018-12. Período de datos de humo: 2010–2016 (exposición prenatal y postnatal temprana).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (73,'PM2.5 (wildfire-generated) como contaminante de interés en el análisis de impacto en salud. MATCH + GFAS también simulan CO, CH4, NOx, NMVOC, SO2, EC, OC y PM10, pero solo PM2.5 se vincula a desenlaces de salud. No se analizan AOD directamente.','Modelo de transporte químico MATCH (SMHI), dominio anidado 4 km y 0.1°. Forzamiento meteorológico: IFS/ECMWF (3 horas). Emisiones de incendios: GFAS (Global Fire Assimilation System, 0.1°×0.1°, diario). Emisiones antropogénicas: CAMS REG AP_v3.1/2016 (dominio europeo) y Nordic WelfAir v5 en 1×1 km² (dominio interno). Cobertura de suelo: Corine Land Cover 2012. Validación: estación PM2.5 Bredkälen y 11 estaciones de visibilidad SMHI. No se usan sensores IoT.','GFAS (Global Fire Assimilation System) — producto diario de emisiones de incendios a 0.1°×0.1°. GFAS utiliza internamente datos de fire radiative power (FRP) de satélites (probablemente MODIS), aunque el instrumento específico no se detalla. No se usan explícitamente FIRMS, MODIS directo, VIIRS, Sentinel-5P ni Himawari. Incertidumbre en estimaciones satelitales de emisiones reconocida como limitación principal (factor ~5 entre productos).','Datos de salud agregados (baselines) del National Board of Health and Welfare de Suecia (2019): mortalidad total 2.9/día/100,000 hab.; hospitalizaciones cardiovasculares 5.5/día/100,000 hab.; hospitalizaciones respiratorias 0.6/día/100,000 hab. Tasa de visitas de emergencia por asma: Tornevi et al. 2021 — 2.10/día/100,000 hab. No se usan datos individuales de pacientes, MINSA ni registros clínicos.','Registro Nacional de Población de Suecia (100×100 m) para exposición ponderada. ERFs publicadas: Chen et al. 2021 (mortalidad, RR=1.021 por 10 μg/m³); Karanasiou et al. 2021 (hospitalizaciones cardiovasculares 3.68% y respiratorias 9.19% por 10 μg/m³); Tornevi et al. 2021 (visitas asma, RR=1.37 por 10 μg/m³). Datos de visibilidad de 11 estaciones meteorológicas SMHI para validación indirecta del modelo.','Población general de Östersund (n=63,227 habitantes al 1 enero 2019), única ciudad de la región Jämtland Härjedalen, Suecia. No se segmenta por edad, género o condición preexistente en los cálculos principales. Se discute la vulnerabilidad de ancianos, niños y personas con enfermedades respiratorias preexistentes como necesidad de investigación futura.','Escenarios construidos sobre la ciudad de Östersund. Resolución del modelo MATCH: 4×4 km (dominio interno). Datos de población: 100×100 m. No se usa nivel de distrito o código postal.','Diaria (daily mean PM2.5 para cálculos de impacto). La exposición se agregó en los nueve días de mayor exposición. MATCH produce simulaciones horarias, aunque los cálculos del HIA usan promedios diarios.','Suecia — región Jämtland Härjedalen. Ciudad de Östersund (lat/lon 63.183/14.667 en escenario I, 63.188/14.658 en escenario II; 63,227 hab.). Municipio de Härjedalen con Sveg (lat/lon 62.035/14.365) como zona de referencia de mayor exposición.','2018-06 a 2018-08 (episodio de incendios). Análisis principal: 9 días de mayor exposición en torno al 15–29 julio 2018. Tasas de línea base: año 2019.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (74,'PM10, PM2.5, CO, NO2, O3 (concentraciones horarias → medias diarias y mensuales en 41 estaciones de fondo). Excedencias mensuales de guías WHO 2021: PM2.5 (>15 µg/m³/24h), PM10 (>45 µg/m³/24h), NO2 (>25 µg/m³/24h). AOD total, BC_AOD y Dust_AOD a 550 nm (reanálisis CAMS/EAC4). Área quemada (ha) como proxy de actividad de incendios.','QualAR/APA (Agencia Portuguesa del Ambiente) — red de 41 estaciones de fondo: PM10, PM2.5, CO, O3, NO2. IPMA (Instituto Portugués del Mar y la Atmósfera) — 43 estaciones meteorológicas: temperatura a 2 m, humedad relativa, velocidad del viento a 10 m. CAMS EAC4 (reanálisis global ECMWF/Copernicus) — AOD total, BC_AOD, Dust_AOD a 550 nm (0.75°, medias mensuales). ICNF (Instituto de Conservación de la Naturaleza y Bosques) — datos mensuales de área quemada 2011–2020.','CAMS EAC4 (Copernicus Atmosphere Monitoring Service, reanálisis global ECMWF) — AOD total, BC_AOD y Dust_AOD a 550 nm, resolución 0.75°. CAMS combina modelos con observaciones in situ y de teledetección mediante asimilación de datos. No se usan directamente MODIS, FIRMS, VIIRS, Sentinel-5P ni Himawari.','INE (Instituto Nacional de Estadística de Portugal) — tasas de mortalidad estandarizadas mensuales por 100,000 habitantes (todas las edades) para Portugal continental. Desenlaces ICD-11: CSD (1B40–BE2Z), RSD (CA00–CB40), PNEU (CA40–CA40.Z), COPD (CA20.Z–CA22.Z), ASMA (CA23–CA23.3). Datos del SIRIC y SICO. No se usan datos de hospitalizaciones ni IRA directamente; el desenlace es mortalidad por causa específica.','Datos de área quemada (ICNF). Datos meteorológicos del IPMA. AOD del CAMS EAC4. No se incluyeron variables socioeconómicas ni de densidad poblacional (discutidos como limitación). Datos y base de datos PBI-API disponibles en Zenodo (zenodo.8086284).','Población general de Portugal continental (todas las edades, ambos sexos). Sin estratificación por edad, sexo ni grupo vulnerable en el análisis principal. Tasa media de mortalidad cardiorrespiratoria en temporada de incendios 2011–2020: CSD 22.67 (±1.0); RSD 7.86 (±0.6); PNEU 3.46 (±0.5); COPD 1.66 (±0.2); ASMA 0.08 (±0.03) — todos en muertes/100,000 hab./mes.','Nacional (Portugal continental agregado). No se usa resolución de distrito, municipio, código postal ni km². Las estaciones de calidad del aire (41) y meteorológicas (43) se usan como medias nacionales. Resolución CAMS: 0.75° (~80 km).','Mensual (concentraciones medias mensuales de contaminantes; medias mensuales meteorológicas; tasas de mortalidad mensuales; área quemada mensual). Solo meses de temporada de incendios (junio–octubre) con área quemada >1,000 ha.','Portugal — Portugal continental (18 distritos administrativos, análisis agregado nacional).','2011-06 a 2020-10 (temporadas de incendios junio–octubre, solo meses con área quemada >1,000 ha, 10 años).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (75,'Área quemada (km²) como proxy integral de emisiones de incendios de biomasa (incluye PM2.5, PM10, CO, NOx, O3, PAHs). PM2.5 (µg/m³) — variable intermedia para verificar el mecanismo de contaminación del aire (datos de monitores openAQ en países de bajos y medianos ingresos, n≈2,000 monitores). No se analizan contaminantes individuales por separado en el análisis principal.','FireCCILT11 (ESA CCI Fire) — área quemada mensual global basada en AVHRR (~5 km). ERA5 (Copernicus/ECMWF) — precipitación, temperatura, dirección y velocidad del viento mensual (~30 km). openAQ — datos de monitores PM2.5 en países de bajos y medianos ingresos (2014–2018). No se usan modelos de transporte químico — el diseño empírico evita explícitamente depender de modelos de emisiones.','FireCCILT11 (ESA Climate Change Initiative, versión 1.1) — área quemada mensual basada en imágenes AVHRR (Advanced Very High Resolution Radiometer) a 0.05° de resolución. No se usan MODIS, FIRMS, Sentinel, Himawari ni VIIRS directamente.','Demographic and Health Surveys (DHS) — 116 encuestas de 54 países (2004–2018); n=2,237,307 nacimientos; historias completas de nacimientos de mujeres 15–49 años; indicador binario de muerte en primeros 12 meses; coordenadas de clúster con desplazamiento aleatorio. IHME (Institute for Health Metrics and Evaluation) — IMR subnacional a 5×5 km para muestra extendida de 105 países. No se usan MINSA, postas ni registros clínicos individuales.','ERA5 (vectores de viento, temperatura, precipitación). WorldPop (2015) — distribución de nacimientos por celda. IHME — IMR subnacional 5×5 km. GBD (Global Burden of Disease) — estimaciones de muertes infantiles atribuibles a PM2.5 total. Estadísticas vitales de Turquía, México, Brasil, China, India (para muestra extendida). UN world births dataset. Datos de riqueza del hogar (quintiles de índice de activos) de DHS.','Lactantes (mortalidad en primeros 12 meses de vida) en países de bajos y medianos ingresos. Muestra DHS: 2,237,307 nacimientos en >90,000 localizaciones de clúster en 54 países; IMR medio 53 muertes/1,000 nacimientos. Muestra extendida: 105 países (98% de muertes infantiles globales). No se segmenta por sexo en resultados principales (incluido como control).','Clústeres DHS (georreferenciados, desplazamiento aleatorio 0–5 km rural, 0–2 km urbano). Radio de exposición: 30 km (principal), también 30–40 km y 40–50 km. Datos de área quemada: 0.05° (~5 km). IMR muestra extendida: grilla 5×5 km (IHME). Errores estándar agrupados a nivel de cuadrícula de 1°.','Mensual (área quemada, dirección del viento, PM2.5 en monitores). Seguimiento: 9 meses prenatales + 12 meses postnatales por nacimiento. Panel 2004–2018 (15 años). Período de línea base para escenarios contrafácticos: 2001–2003.','Global. Muestra de estimación: 54 países de bajos y medianos ingresos (África subsahariana, Asia meridional y sudoriental, América Latina). Muestra extendida: 105 países. Regiones con mayor carga: África subsahariana (~75% de muertes atribuibles), seguida de Asia y América Latina (cuenca amazónica).','2004-01 a 2018-12 (nacimientos y exposición). Datos de área quemada desde 2001–2003 para línea base. Validación PM2.5 con monitores openAQ: 2014–2018.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (76,'PM2.5 (contaminante de interés) no se mide directamente — se utiliza la proximidad a incendios como proxy. No se analizan CO, NO2, O3, AOD ni PM10.','Datos de incendios (fronteras) del Alaska Interagency Coordination Center combined fire geodatabase (1940–2020). Datos de población del Alaska Bureau of Labor and Workforce Development. No se usan estaciones terrestres de monitoreo de PM2.5 (solo 9 en todo Alaska — reconocida como limitación crítica), ni sensores IoT, ni modelos de reanálisis.','No se utilizan datos satelitales para exposición directa. Los datos de incendios provienen del AICC combined fire geodatabase (puede incluir detección satelital, pero no se especifica). No se usan MODIS, FIRMS, VIIRS, Sentinel-5P explícitamente.','BRFSS (Behavioral Risk Factor Surveillance System) — prevalencia de asma actual (current asthma) para adultos ≥18 años, ajustada por edad, por región BHS (2007–2017). Indicador: respuesta afirmativa a haber recibido diagnóstico médico de asma y seguir teniéndola. Datos agrupados a 11 regiones BHS (mínimo 20,000 hab.). No se usan datos de hospitalizaciones, urgencias, ICD ni registros clínicos individuales.','Datos de población de cada centro poblado (village) del Alaska Bureau of Labor and Workforce Development. Shapefiles de boroughs y áreas censales del US Census Bureau. Descripción geográfica de regiones BHS del Alaska Department of Health Services.','Adultos de 18 años o más con asma prevalente. Población mantenida constante al nivel del Censo 2010. No se incluyen niños.','Regiones BHS de Alaska (11 regiones). Buffers circulares de 5 a 70 millas alrededor de centroides de aldeas. Unidad de análisis final: región BHS.','Anual (prevalencia de asma BRFSS y exposición a incendios por año). Período 2007–2017 (11 años).','Estados Unidos — Alaska. 11 regiones del Behavioral Health System (BHS).','2007 a 2017 (11 años). Datos de incendios disponibles 1940–2020, pero análisis limitado a 2007–2017.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (77,'PM2.5 (µg/m³) — variable de exposición principal, medida en monitores terrestres. Humo HMS categorizado en tres niveles: bajo, medio y alto. NO2 y O3 se discuten como posibles causas alternativas pero no se incluyen en el modelo.','Red de monitores PM2.5: U.S. EPA, IMPROVE (Interagency Monitoring of Protected Visual Environments), TREX (Tribal Exchange Network), USFS (U.S. Forest Service, monitores BAM — beta attenuation monitors, Met One Inc.). NOAA HMS — densidad diaria de humo satelital (bajo/medio/alto). No se usan sensores IoT.','NOAA HMS (Hazard Mapping System Fire and Smoke Product) — plumas de humo generadas manualmente desde múltiples satélites geoestacionarios y de órbita polar, disponibilidad diaria. Solo disponible en horas de luz (medición en columna atmosférica visible). No se usan MODIS, FIRMS, VIIRS, Sentinel-5P explícitamente.','OSHPD (California Office of Statewide Health Planning and Development) — datos de visitas a urgencias por asma (ICD-9) 2008–2015. Variables por paciente: código postal de residencia, sexo, fecha de nacimiento, fecha de servicio, diagnósticos, causa y tratamientos. No se usan MINSA ni registros clínicos de otros países.','Población por código postal (U.S. Census). Coordenadas de centroide del polígono de código postal (lon, lat) para el spline espacial. Día del año como proxy de clima y estacionalidad.','Pacientes con visitas a urgencias por asma (ICD-9) en California 2008–2015, todas las edades. El modelo incluye sexo y fecha de nacimiento como variables individuales. Se menciona mayor vulnerabilidad de adultos mayores y niños.','Código postal (ZIP code) del paciente. Centroide del polígono de código postal para coordenadas geográficas. Splines s(lon,lat) y s(lon,lat,day) para capturar variación espacial y estacional.','Diaria (PM2.5 diario, datos de humo HMS diarios, visitas de urgencias diarias por zip code). Período 2008–2015 (8 años).','Estados Unidos — California (todo el estado). Se mencionan diferencias entre Sierra Nevada (elevación alta, PM2.5 alto en verano), Central Valley (PM2.5 alto en invierno) y áreas costeras metropolitanas.','2008-01 a 2015-12 (8 años). En algunos análisis se excluyó 2008 por ser año muy activo de incendios (OR de PM2.5>35: 114 incluyendo 2008 vs. 35 excluyendo 2008).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (78,'PM2.5 de humo de incendio (wildfire smoke PM2.5, µg/m³) — estimado diariamente a 10 km mediante modelo ML (Childs et al. 2022, R²=0.67). No se analizan CO, NO2, O3, AOD ni composición química del humo.','PM2.5 de humo diario a 10 km: modelo ML de Childs et al. 2022 (satélite + reanálisis + trayectorias de aire). Reanálisis meteorológico (ERA5/NCEP) para trayectorias HYSPLIT. Monitores EPA AQS para validación. PM2.5 total (1 km) para análisis transfronterizo: Swanson et al. 2022.','NOAA HMS — puntos de incendios productores de humo identificados por analistas entrenados; plumas anotadas manualmente. MODIS/NASA — polígonos de área quemada (GlobFire v3, ~23,900 incendios). VIIRS — hotspots de mayor resolución desde 2016 (437,500 fuentes adicionales). GOES-16/17/18 — imágenes geoestacionarias para validación visual.','OSHPD (California Office of Statewide Health Planning and Development) — visitas a urgencias por asma a nivel zip code×día en California 2006–2017 para estimar función concentración-respuesta. Media: 1.17 visitas diarias por 100,000 hab. No se usan datos de urgencias nacionales directamente.','WorldPop (1 km, ajustado ONU) — población por celda. GlobFire v3 — polígonos de área quemada MODIS. Baylis & Boomhower (2023) — costos de supresión (11 estados oeste, 2006–2016, >300 acres). Headwaters Economics/FAMWEB/NIFC — estructuras destruidas. Swanson et al. (2022) — PM2.5 total diario 1 km para 11 estados oeste.','Población general de EE.UU. continental. Pacientes con visitas a urgencias por asma (todas las edades) en California para función CR. Sin heterogeneidad significativa por terciles de ingreso. Comunidades hispanas y nativas americanas identificadas con mayor exposición.','Cuadrícula de 10×10 km (PM2.5 de humo, exposición acumulada). Zip code para función CR en California. Polígonos GlobFire (variables, buffer 2 km para matching). Buffer de 30 km para ventana espacial de atribución.','Diaria (PM2.5 de humo, visitas urgencias). Período: abril 2006–diciembre 2020. Lags: 0–7 días. Trayectorias: 6 días hacia adelante. Exposición acumulada sumada por duración del incendio.','Estados Unidos continental (CONUS). Análisis transfronterizo incluye Canadá (~8% de visitas atribuibles) y México (~3%). Enfoque especial en California, estados del oeste, y el incendio Bugaboo (Georgia/Florida, 2007).','2006-04 a 2020-12. Función CR estimada en California: 2006–2017.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (79,'PM2.5 superficial (µg/m³) — variable de salida del modelo. AOD (aerosol optical depth, MODIS MCD19A2) — predictor satelital principal. No se modelan directamente PM10, CO, NO2, O3.','EPA AQS — 1,935,006 observaciones PM2.5 de 823 locaciones (oeste EE.UU., 2003–2020). CFSR (Climate Forecast System Reanalysis, NCEP, 0.5°) — radiación de onda larga superficial, altura geopotencial 700 mb, velocidad del viento a 10 m, humedad relativa a 2 m, temperatura máxima a 2 m, cobertura nubosa de capa límite. EPA SMOKE program — 114 surrogados de emisión PM2.5 a 4 km. US Census Bureau 2010 — densidad de población a 60 m → 1 km (kernel gaussiano 2.5 km).','MODIS MCD19A2 (colección 6, algoritmo MAIAC) — AOD a 1 km, diario. MODIS NDVI (250 m, 8 días, GLAM) — máscara de nieve. MODIS LST — temperaturas de superficie mensuales (2003–2012) como predictores estáticos. No se usan VIIRS, Sentinel-5P, FIRMS.','No aplica directamente. El producto se desarrolló para estudios de salud pero este artículo no utiliza datos de salud. No se usan MINSA, postas, hospitales ni registros clínicos.','NED DEM (National Elevation Dataset, USGS) a 30 m → 1 km — índices topográficos. GeoMAC — perímetros de incendios activos (shapefile) para análisis post-hoc. EPA SMOKE — 114 surrogados de emisión. US Census Bureau 2010 — densidad poblacional suavizada (kernel gaussiano 2.5 km). Datos disponibles en figshare (NetCDF diario 2003–2020, smog potential layer).','No aplica — dataset de exposición ambiental. El producto está diseñado para estudios de exposición en población general del oeste intermontañoso de EE.UU. donde los monitores son escasos.','1 km × 1 km (predicciones finales). GWR ajustada a grilla de 10 km con interpolación bilineal → 1 km. AOD MODIS: 1 km. Índices topográficos NED: 30 m → 1 km.','Diaria (2003-01-01 a 2020-12-14). Archivos anuales NetCDF.','Estados Unidos — 11 estados del oeste (al oeste de −102° de longitud): Arizona, California, Colorado, Idaho, Montana, Nevada, New Mexico, Oregon, Utah, Washington, Wyoming.','2003-01-01 a 2020-12-14.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (80,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (81,'PM2.5 (µg/m³) — media diaria de 24 h, variable de exposición principal. El humo de incendio también contiene CO, O3, CH4, NOx — mencionados pero no medidos como variables de exposición.','NSW Air Quality Monitoring Network — estaciones fijas gubernamentales de PM2.5 (media diaria de 24 h). IDW para interpolación a domicilio residencial del participante. No se usan reanálisis, sensores IoT ni modelos de transporte químico.','Imágenes satelitales (sensor no especificado) — confirmación visual de presencia de incendio el día de estudio o hasta 3 días antes/después. No se usan MODIS, FIRMS, VIIRS, Sentinel-5P ni HMS para medición de exposición.','Registros médicos electrónicos y bases de datos clínicas del John Hunter Children\'s Hospital — Asthma Clinic (NSW). Desenlaces: FVC%, FEV1%, FEV1/FVC ratio%, FeNO50 (ppb), ACT score. Espirometría con criterios ATS/ERS; referencias GLI (ecuación \'Other/Mixed\' para primera nación australiana). No se usan registros administrativos hospitalarios masivos ni MINSA.','GLI — ecuaciones de referencia espirométricas. NSW Air Quality Index — percentil 95 de PM2.5 período 2010–2018 para Sydney GMR. Datos clínicos: sexo, edad, peso, talla, etnia, exposición al tabaco, dosis de beclometasona, ACT score, estación del año.','Niños asmáticos de 4 a 16 años con diagnóstico confirmado por especialista pediátrico, John Hunter Children\'s Hospital (NSW). n=129 niños, 212 visitas: 49 con 1 visita, 78 con 2, 1 con 3, 1 con 4. 36 visitas en días de incendio; 176 sin incendio. 19.4% de primera nación australiana en días de incendio vs. 5.8% sin incendio (p=0.01).','Sydney Greater Metropolitan Region (GMR, ~1,860 km²). Exposición asignada a dirección residencial individual mediante IDW.','Diaria (PM2.5 media de 24 h; día de visita clínica). Período: 2019-01 a 2020-04.','Australia — New South Wales (NSW), Sydney Greater Metropolitan Region.','2019-01 a 2020-04 (16 meses). Período de incendios principal: temporada primavera-verano 2019–2020. Período base para percentil 95: 2010–2018.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (82,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (83,'PM2.5 (µg/m³) — concentración horaria en superficie, variable de salida. AOD (GOES-16) — predictor satelital. No se modelan CO, NO2, O3.','EPA AQS — 108 monitores (41,947 obs. horarias). PurpleAir — 848 sensores calibrados (207,103 obs. horarias). HRRR (NOAA) — temperatura a 2 m, presión superficial, componentes u/v del viento a 10 m, PBLH, humedad relativa (3 km, actualización horaria).','GOES-16 (ABI) — AOD (cada 5 min, 2–5 km), aerosol detection binary (cada 15 min), fire spot characterization (fire mask, temperatura, área, radiative power, cada 5 min), smoke mask. MODIS Aqua — imágenes true-color para validación visual (no predictor). ASTER GDEM — elevación digital.','No aplica — estudio de desarrollo de producto de exposición. Los autores mencionan que las predicciones horarias pueden usarse para investigaciones epidemiológicas del Camp Fire, pero el artículo no contiene análisis epidemiológico propio.','NLCD 2011 (National Land Cover Database) a 30 m — variables de uso de suelo. ASTER GDEM — elevación. US Census TIGER/Line Shapefiles — distancias a carreteras primarias y secundarias. Capa convolucional IDW (5 vecinos más cercanos, misma hora).','No aplica — dataset de exposición ambiental. El estudio menciona comunidades \'downwind\' del Camp Fire en California como beneficiarias de los datos de exposición.','3×5 km² (grilla de modelado, 40,578 celdas). GOES-16 AOD: 2–5 km. HRRR: 3 km. Elevación ASTER, uso de suelo NLCD 30 m → grilla.','Horaria. Período: 2018-10-01 a 2018-11-30 (2 meses). Datos GOES-16 disponibles solo en horas de luz.','Estados Unidos — California (todo el estado). Epicentro: Butte County (norte de California), donde se originó el Camp Fire el 8 de noviembre de 2018.','2018-10-01 a 2018-11-30 (2 meses). Camp Fire: 8–25 noviembre 2018 (17 días activos).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (84,'AOD (Land Aerosol Optical Depth, MODIS MCD19A2, banda azul 0.47 µm) — variable explicativa principal como proxy de contaminación. El AOD se justifica como proxy de PM2.5, CO y SO2. No se miden directamente PM2.5, PM10, CO, NO2, O3 (monitoreo no disponible a escala de toda la AJB).','MODIS MCD19A2 (MAIAC) — AOD a 1 km, variable explicativa. ERA5 — velocidad y dirección del viento (0.25°, mensual) como variables instrumentales. CHIRPS — precipitación (0.05°, mensual). MOD11A2 — temperatura superficial terrestre (1 km, 8 días → mensual).','MODIS MCD64A1 (Terra + Aqua) — área quemada mensual (500 m) como instrumento IV principal. MODIS MYD14A1 (Aqua) — anomalías térmicas/incendios activos (1 km) como instrumento alternativo (robustness check). MODIS MCD19A2 (MAIAC) — AOD a 1 km. MODIS MOD11A2 — temperatura superficial.','DataSUS (TabNet) — hospitalización mensual por enfermedades respiratorias (ICD-10 J00–J99) por municipio de residencia: total respiratorio, asma (J45–J46), neumonía (J12–J18), bronquitis (J20–J21). Estratificado por grupo etario: niños pequeños (≤4 años), niños (5–14 años), adultos mayores (≥65 años), todos los grupos. Solo hospitalizaciones con estancia ≥24 h.','IBGE — PIB municipal (anual), delimitaciones municipales anuales. DataSUS — población estimada, mortalidad infantil, mortalidad por enfermedades crónicas, personal de salud, camas hospitalarias, instalaciones. DENATRAN — flota de vehículos (mensual, municipal). OpenStreetMap — red vial para densidad de carreteras. MapBiomas (Landsat, 30 m) — cobertura y uso de suelo urbano (1985–2019).','Población general de los 805 municipios de la Amazonía Legal Brasileña (AJB). Análisis estratificado por grupos etarios: niños pequeños (≤4), niños (5–14), adultos mayores (≥65) y total. Población media municipal: 32,295 habitantes.','Municipal (~6,300 km² promedio). 805 municipios de la AJB. Datos raster agregados a nivel municipal mediante Google Earth Engine.','Mensual (panel municipal-mensual). Período: 2005-08 a 2018-12 (162 meses).','Brasil — Amazonía Legal Brasileña (AJB, ~5 millones km²): Acre, Amapá, Amazonas, Mato Grosso, Rondônia, Roraima, Tocantins, Pará y parte de Maranhão (al este del meridiano 44°).','2005-08 a 2018-12 (condicionado por disponibilidad conjunta de variables de salud, camas y personal).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (85,'PM2.5 de humo (variable de exposición principal). 25 HAPs gaseosos del humo — acroína (85% de DALYs de HAPs), formaldehído (12%), acetaldehído, benceno y otros. El humo también contiene PAHs particulados (no incluidos en el análisis de HAPs). No se analizan CO, NO2, O3 ni AOD.','EPA AQS — observaciones diarias de PM2.5, krigeadas a 15×15 km. NOAA HMS — plumas de humo diarias (satélites visibles). WE-CAN (Western Wildfire Experiment on Cloud Chemistry, Aerosol Absorption, and Nitrogen) — ratios HAPs/PM1 para humo de diferentes edades de incendios del oeste (2018).','NOAA HMS (Hazard Mapping System) — polígonos de plumas de humo diarias desde imágenes satelitales visibles (múltiples satélites). No se especifican MODIS, VIIRS, Sentinel-5P explícitamente.','HCUP — NEDS y NIS para tasas de línea base de urgencias y hospitalizaciones por asma (ICD9-493) en EE.UU. para 2010. GBD 2019 — tasas de mortalidad y DALYs por todas las causas (enfermedades no comunicables + infecciones respiratorias bajas). No se usan MINSA, postas ni registros clínicos primarios.','NASA SEDAC — población gridded 2010 (2.5 arc-min → 15×15 km). GBD 2019 — tasas de mortalidad y DALYs. GEMM (Burnett et al. 2018) — función CR para mortalidad crónica. Meta-análisis Borchers Arriagada et al. 2019 — RRs específicos de humo para asma. Huijbregts et al. 2005 — factores DALY/ingesta para 1,192 contaminantes. Volumen de inhalación diaria (14.4 m³/día) de Logue et al. 2012.','Población general de los EE.UU. contiguos. Sin estratificación por edad, sexo ni grupos vulnerables. Tasas basales de asma nacionales (sin desagregación estatal ni estacional).','15×15 km (grilla de kriging PM2.5 y HIA). Resultados sumados por estado y por 9 regiones EPA.','Diaria (PM2.5 de humo agudo; morbilidad por asma a lag 0). Media 2006–2018 para exposición crónica y mortalidad. Resultados de morbilidad agregados por estación y año.','Estados Unidos contiguos (CONUS). 9 regiones: Northwest (NW), Rocky Mountain (RM), Southwest (SW), Midwest (MW), Great Plains (GP), Southern Plains (SP), Northeast (NE), Mid Atlantic (MA), Southeast (SE).','2006-01 a 2018-12 (13 años).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (86,'WFS PM2.5 (PM2.5 específico de humo de incendio, µg/m³) — diferencia entre PM2.5 diario observado en días de incendio y la media mensual de largo plazo. Ozono mencionado como posible confusor — solo disponible en Fairbanks (análisis de sensibilidad inconcluso). No se analizan CO, NO2, AOD.','Alaska DEC — monitores regulatorios EPA de PM2.5 (datos horarios → promedio diario) en Anchorage, Fairbanks y Matanuska-Susitna. Línea base: 2008–2019 (Anchorage y MatSu), 2009–2019 (Fairbanks). NOAA ASOS — temperatura y humedad relativa diarias del monitor más cercano. NOAA HMS — plumas de humo diarias para identificar días de incendio.','NOAA HMS (Hazard Mapping System) — shapefiles de plumas de humo diarias desde imágenes satelitales visibles (múltiples satélites). No se usan MODIS, FIRMS, VIIRS, Sentinel-5P explícitamente.','Alaska HFDR — registros de urgencias cardiorrespiratorias (ICD-9-CM e ICD-10-CM) de hospitales privados, municipales, estatales, federales y de organizaciones nativas, 2015–2019 (T2 y T3). Desenlaces: asma, EPOC, neumonía, bronquitis, arritmia, enfermedad cerebrovascular, insuficiencia cardíaca, cardiopatía isquémica, infarto; total respiratorio y cardiovascular. Solo diagnóstico primario; excluye atención planificada. n=26,619 visitas.','NOAA ASOS — temperatura y humedad relativa diarias. Datos demográficos de pacientes: edad, sexo, etnia (nativo de Alaska / no nativo). Datos de población del US Census Bureau.','Residentes de tres principales centros poblacionales de Alaska (>65% de la población estatal): Anchorage (~288,000 hab.), Fairbanks (~97,000 hab.) y Matanuska-Susitna Valley (~108,000 hab.). Estratificados por edad (<15, 15–65, >65 años), sexo y etnia (nativo de Alaska / no nativo).','Borough (condado): Anchorage, Fairbanks North Star y Matanuska-Susitna. Exposición uniforme por borough por día. Buffer de 50 km alrededor del monitor para definición de pluma HMS.','Diaria. Temporadas de incendios (abril-septiembre) 2015–2019.','Estados Unidos — Alaska. Tres áreas: Anchorage (clima costero), Fairbanks (interior continental, inversiones invernales documentadas) y Matanuska-Susitna Valley (valles fluviales, 35 millas al norte de Anchorage).','2015-04 a 2019-09 (temporadas de incendios, 5 años). Período de línea base para PM2.5: 2008–2019.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (87,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (88,'PM2.5 (principal, usado en HIA cuantitativo). CO, AOD y ozono troposférico — descritos para caracterizar el episodio, no usados en el cálculo cuantitativo de salud.','Red de monitoreo de calidad del aire de DPIE NSW (PM2.5, ozono, meteorología). Salidas de WRF-Chem con emisiones FINN. MERRA-2 para PM2.5 a gran escala. Productos de humedad del suelo (AWRA-L) y cobertura vegetal (CSIRO, MODIS). NCEP FNL — reanálisis meteorológico.','MODIS Terra/Aqua — hot spots, AOD, cobertura vegetal, área quemada (MCD64A1, VCF). CALIPSO/CALIOP — perfiles verticales de aerosoles para validación de transporte. MERRA-2 — PM2.5 a gran escala (asimila observaciones satelitales). FINN usa hot spots MODIS + tipos de vegetación MODIS LCT + VCF para calcular emisiones de fuego.','Registros de mortalidad y hospitalizaciones por enfermedades cardiovasculares y respiratorias de NSW: tasas de incidencia de mortalidad por SA4 y hospitalizaciones cardiovasculares por LGA y respiratorias por LHD (NSW Department of Health), promedio 2014–2016. Datos de población ABS 2016.','Población y tasas de mortalidad por SA4 del Australian Bureau of Statistics 2016. Tasas de hospitalización cardiovascular por LGA y respiratoria por LHD (NSW Health). Índices de riesgo de incendio (FFDI), humedad del suelo (AWRA-L) y cobertura vegetal (CSIRO/MODIS) para caracterizar condiciones de peligro.','Población general residente en las unidades SA4 de NSW, con énfasis en áreas urbanas del Greater Metropolitan Region (Sídney) y regiones costeras afectadas por el humo. Sin estratificación por edad, sexo o etnia en el HIA principal.','Grilla de 12×12 km (dominio WRF-Chem). Resultados del HIA agregados a nivel SA4 mediante superposición espacial de celdas del modelo sobre polígonos censales ABS.','Horaria (simulación WRF-Chem). Diaria para el HIA (concentraciones diarias × tasas de incidencia). Período: 2019-11-01 a 2020-01-08 (~70 días).','Australia — Nueva Gales del Sur (NSW), incluyendo el Greater Metropolitan Region de Sídney y otras regiones costeras e interiores afectadas por el Black Summer 2019–2020.','2019-11-01 a 2020-01-08 (episodio principal de incendios). Contexto meteorológico y de combustibles: primavera 2019 (sequía, baja humedad del suelo, alta carga de combustible).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (89,'WFS PM2.5 (µg/m³) — diferencia entre PM2.5 diario krigeado y mediana estacional de días sin humo. Temperatura y ozono máximo 8 h — confusores en el mismo lag. PM2.5 total: media 6.62 µg/m³; WFS media temporada: 0.55 µg/m³ (máximo 65 µg/m³ en 2015).','EPA AQS — 2,849 monitores en EE.UU. contiguos (49 en Colorado) para PM2.5, temperatura y ozono. Kriging diario a grilla 15×15 km (método O\'Dell et al. 2019). NOAA HMS — plumas de humo diarias para identificar días con humo.','NOAA HMS — plumas de humo diarias desde imágenes satelitales visibles (geoestacionarios y órbita polar). MODIS (NASA Worldview) — imágenes de color real para validación visual de eventos específicos (High Park, Waldo Canyon, Pacific Northwest). No se usan VIIRS, Sentinel-5P directamente.','Colorado Hospital Association (CHA) — registros de alta hospitalaria 2010–2015 (CDPHE), ingresos por urgencias con diagnóstico primario cardiopulmonar. ICD-9-CM: respiratorio (460–519), asma (493), EPOC (490–492, 494, 496), neumonía (480–486), bronquitis aguda (466), cardiovascular (390–459), arritmia (427), cerebrovascular (430–438), insuficiencia cardíaca (428), IHD (410–413), MI (410). Total: 46,585 hospitalizaciones respiratorias + 68,356 cardiovasculares. Registros de mortalidad ICD-10 (causas subyacentes) de CDPHE 2010–2015.','Datos de temperatura y ozono de AQS krigeados a la grilla (Martenies et al. 2019). Geocodificación de casos al ID de celda 15×15 km por CDPHE. Datos de evacuaciones y contexto de incendios 2012 (Waldo Canyon, High Park) de fuentes oficiales.','Residentes del corredor urbano Front Range de Colorado (Fort Collins a Colorado Springs): ~4.55 millones (~80% de la población del estado). Estratificados por edad (<15, 15–65, ≥65) y sexo (femenino/masculino). Temporadas de incendios (mayo-octubre) 2010–2015.','15×15 km (grilla kriging). Casos geocodificados al ID de celda por dirección residencial. Análisis por condado (El Paso para Waldo Canyon; Larimer para High Park) para incendios locales 2012.','Diaria. Temporadas de incendios: mayo-octubre, 2010–2015 (6 años). Lags evaluados: 0–5 días. Fases: temprana (mayo-julio) vs. tardía (agosto-octubre).','Estados Unidos — Colorado, corredor urbano Front Range (Fort Collins, Greeley, Boulder, Denver, Colorado Springs, Pueblo).','2010-05-01 a 2015-10-31 (6 temporadas). Hospitalizaciones hasta 2015-09-30. Mortalidad hasta 2015-12-31. Análisis específicos: 2012 (incendios locales + transporte) y 2015 (transporte de largo alcance de Pacific Northwest).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (90,'PM2.5 de humo de incendios (µg/m³) — contaminante principal. PM2.5 total de todas las fuentes. No se analizan CO, NO2, O3, AOD como variables de resultado de salud.','EPA AQS — monitores de PM2.5 en tierra (EE.UU., más de una década). NOAA HMS — plumas de humo y días de humo. Datos de área quemada (USFS/NIFC). Datos de aridez de combustible (west US). Datos de casas en WUI (ubicaciones de hogares + mapas NLCD). Datos de gasto federal en supresión (USFS).','Datos satelitales de plumas de humo, probablemente NOAA HMS (Hazard Mapping System). No se especifican MODIS, VIIRS, Sentinel-5P explícitamente.','No se usan datos de salud primarios. Se aplican funciones concentración-respuesta de mortalidad publicadas (Burnett et al. 2018, Vodonos et al. 2018, Shi et al. 2019) para estimar muertes evitadas en adultos mayores bajo escenarios estilizados.','Datos de hogares en WUI (ubicaciones de viviendas + mapas NLCD). Datos de área quemada (NIFC). Datos de gasto federal en supresión (USFS). Datos de días con humo (Childs et al.). Datos de origen del humo transfronterizo (Brey et al. 2018). Datos de mortalidad relacionada con temperatura (GBD) para comparación de escenarios.','Adultos mayores de 65 años para estimaciones de mortalidad. Población general para estimaciones de exposición a PM2.5 y número de hogares en WUI. Análisis de gradientes de justicia ambiental por proporción de blancos no hispanos a nivel de condado.','Nivel de condado para análisis de gradientes raciales. Grilla de cuadrícula y regiones (oeste, medio oeste, noreste). No se reporta resolución específica de la grilla del modelo.','Anual y por períodos (2006–2008 vs. 2016–2018). Tendencias históricas desde ~1984 para área quemada; desde ~1990 para WUI.','Estados Unidos contiguo (CONUS). Regiones: oeste, medio oeste, noreste, sureste. Análisis de transporte transfronterizo desde Canadá.','2006–2018 (modelo estadístico de exposición). Tendencias históricas de área quemada: ~1984–2018. Hogares en WUI: ~1990–2015.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (91,'PM10 (µg/m³), PM2.5 (µg/m³), NO2 (µg/m³) — mediciones en superficie. NO2 troposférico (columna) — TROPOMI/Sentinel-5P. Carbono orgánico (OC) de quema de biomasa — CAMS, como indicador de BB.','Red SDA (Secretaría Distrital de Ambiente, Bogotá) — estaciones fondo urbano (Centro de Alto Rendimiento) y tráfico (Las Ferias): PM10, PM2.5, NO2. Red SIATA (Medellín) — estaciones fondo suburbano (Concejo de Itagüí) y tráfico: PM10, PM2.5, NO2. NCEP GDAS1 — campos meteorológicos para HYSPLIT.','Sentinel-5P/TROPOMI — columnas troposféricas de NO2 (niveles 2 y 3). FIRMS/MODIS (NASA) — incendios activos (confianza ≥75%). CAMS (Copernicus) — emisiones de carbono orgánico de quema de biomasa (fire flux OC). No se usan VIIRS, GOES, Himawari, Landsat.','No se usan datos de salud. El estudio analiza solo concentraciones de contaminantes. Se menciona la relación entre contaminación y morbilidad/mortalidad por COVID-19 como contexto, sin análisis epidemiológico propio.','Datos de fuegos activos FIRMS/MODIS. Emisiones OC CAMS. Trayectorias HYSPLIT con meteorología GDAS1 (1°, 23 niveles). Google COVID-19 Community Mobility Report — reducción de tráfico (70% confinamiento estricto, 49% relajado). ECMWF/CAMS — actividad de incendios en NSA en 2020 por encima del promedio 2003–2019.','No aplica — estudio de calidad del aire, no epidemiológico. Contexto: Bogotá (~8 millones hab., 2,640 m s.n.m.) y Medellín (~3 millones hab., 1,495 m s.n.m., Valle de Aburrá).','4 estaciones de monitoreo (2 por ciudad: fondo y tráfico). TROPOMI: resolución ~3.5×5.5 km². FIRMS/MODIS: 1 km. HYSPLIT: GDAS1 1°.','Diaria (medias de 24 h). Análisis por período: pre-confinamiento (21 feb–19 mar), estricto (20 mar–26 abr), relajado (27 abr–30 jun). No se usa resolución horaria.','Colombia — Bogotá (Andes orientales, 2,640 m s.n.m.) y Medellín (Valle de Aburrá, Antioquia, 1,495 m s.n.m.). Contexto regional: Norte de Sudamérica (NSA) — Ecuador, Venezuela, Colombia, norte de Perú, norte de Brasil.','2020-02-21 a 2020-06-30 (4.3 meses). Baseline histórico: mismos períodos de 2015–2019.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (92,'PM2.5 (µg/m³) — variable de salida. AOD (MODIS) — predictor satelital intermedio. CMAQ estima PM2.5 de todas las fuentes (incendio + antropogénicas + biogénicas).','EPA AQS — 114 monitores FRM/FEM de PM2.5 diario en California. CARB/WFAQRP — 49 estaciones temporales (E-BAM y E-Samplers). CMAQ (BAAQMD, 4 km) con emisiones: GOES-16 FDC + FEER (incendios), CARB (área/no carretera), EMFAC2017 (carretera), EPA BEIS3.61 (biogénicas), BAAQMD (puntuales).','MODIS Terra — AOD a 3 km (MOD04_3K, algoritmo Dark Target, Colección 6, LAADS DAAC). GOES-16 FDC — detección de incendios cada 5 min a 2 km para emisiones en CMAQ (no como fuente directa de exposición). No se usan VIIRS, Sentinel-5P, FIRMS.','No se usan datos de salud. Los autores mencionan que el trabajo futuro incluye cuantificar impactos en salud usando las concentraciones estimadas. Se usan datos de población por census tract para estimar número de personas expuestas a distintos umbrales de PM2.5.','Datos de población a nivel de census tract. EPA Air Quality Index — umbrales PM2.5 (>35 µg/m³: insalubre para grupos sensibles; >150.5 µg/m³: muy insalubre). Shapefiles de condados de California.','No aplica directamente — dataset de exposición ambiental. Los autores estiman ~65,000 personas expuestas a PM2.5 ≥150.5 µg/m³ y 16 millones a PM2.5 >35 µg/m³. Condados más afectados: Napa y Sonoma.','1 km × 1 km (estimaciones finales BME). CMAQ: 4 km. MODIS AOD: 3 km. Monitores: puntos fijos.','Diaria. Período: 2017-10-01 a 2017-10-31. Período activo de fuego: 2017-10-08 a 2017-10-20.','Estados Unidos — California (norte de 36° de latitud). Condados más afectados: Napa y Sonoma. Bay Area como área de mayor concentración poblacional expuesta.','2017-10-01 a 2017-10-31 (un mes). Período activo de fuego: 2017-10-08 a 2017-10-20 (13 días).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (93,'Humo de incendio forestal — exposición definida por presencia de pluma (MODIS + HMS) superpuesta al ZIP code. PM2.5 mencionado como mecanismo de daño pero no medido cuantitativamente. No se usan concentraciones de PM2.5, CO, NO2, AOD como variables de regresión.','MODIS Rapid Response System — imágenes satelitales de color real para descripción visual de plumas y anomalías térmicas. NOAA HMS — polígonos de plumas de humo diarias (disponibles para 2007). FRAP (CAL FIRE) — perímetros de incendio. Vientos Santa Ana (SAW) de publicaciones previas. Sin monitores terrestres de PM2.5 ni sensores IoT.','MODIS (Terra/Aqua) — imágenes de color real y anomalías térmicas (infrarrojo medio e infrarrojo termal). NOAA HMS — polígonos de plumas satelitales para 2007. No se usan FIRMS, Sentinel-5P, VIIRS, GOES.','OSHPD (Office of Statewide Health Planning and Development) — hospitalizaciones diarias por enfermedades respiratorias (ICD-9 460–519: asma, EPOC, neumonía, enfermedad pulmonar intersticial) agregadas por ZIP code y día. ZIP code = dirección residencial del paciente. Población total condado: 3.1 millones (US Census 2010). Solo hospitalizaciones — sin urgencias ni consultas ambulatorias.','FRAP/CAL FIRE — perímetros de incendio 2003 y 2007. US Census 2010 — población por ZIP code (centroides ponderados para BHM). MODIS y HMS para plumas. NWS Red Flag Warnings — contexto meteorológico.','Población general del condado de San Diego (3.1 millones, 108 ZIP codes). Sin estratificación por edad, sexo o etnia en el análisis principal. Contexto: población diversa con barreras culturales y lingüísticas en las notificaciones de evacuación de 2007.','Código postal (ZIP code) — 108 polígonos en el condado de San Diego. BHM interpolado a grilla de 300×300 celdas raster. Centroides ponderados por población como ubicaciones de referencia.','Diaria. Período de análisis principal: octubre 2007 (22–26 expuestos; controles 2 sem antes y después). Sensibilidad: octubre 2003. Falsificación: octubre 2000 y 2004.','Estados Unidos — California, Condado de San Diego (108 ZIP codes). Incendios principales 2007: Witch, Harris, Rice, Ammo, Poomacha. Incendio 2003: Cedar.','Período expuesto: 2007-10-22 a 2007-10-26 (5 días). Controles: 2007-10-08 a 2007-11-09. Sensibilidad: oct 2003. Falsificación: oct 2000 y oct 2004.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (94,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (95,'PM2.5 (mortalidad urbana). NO2 (concentraciones y carga de asma pediátrica). Ozono troposférico (mortalidad por EPOC). Polvo (frecuencia de tormentas). Exposición directa a incendios (persona-días). Polen (inicio y duración de estación). No se analiza CO directamente.','Observaciones superficiales de PM2.5 y O3 (redes nacionales, TOAR para ozono global). Múltiples CTMs globales (GEOS-Chem, modelos CCMi). MODIS para incendios, NDVI, polvo. No se describen reanálisis meteorológicos individuales en este comentario.','MODIS (Terra/Aqua) — incendios activos (Collection 6, 1 km), NDVI (250 m), True Color (polvo). OMI (Aura) — NO2 troposférico (0.1°) y HCHO. TROPOMI (Sentinel-5P) — NO2. GOME2 y SCIAMACHY — NO2 para LUR global. NASA SEDAC GPWv4 — población. TEMPO y MAIA mencionados como futuros satélites de calidad del aire.','No aplica. Se mencionan estimaciones de carga de enfermedad del GBD (mortalidad PM2.5, asma por NO2, EPOC por ozono), pero no se usan datos primarios de hospitalizaciones, consultas ni mortalidad individual. No se usan MINSA ni registros clínicos.','NASA SEDAC GPWv4 — población gridded. Global Human Settlement Program (UE) — límites de 467 ciudades. TOAR — observaciones globales de ozono superficial. Lancet Countdown 2019 (Watts et al.). GBD 2017/2019. State of Global Air (HEI/IHME). C40 Cities.','Global. Indicador de incendios: población a nivel de país. PM2.5 urbano: 250 ciudades mundiales. NO2/asma: niños a escala global. Ozono: mortalidad global por EPOC.','Variable: MODIS incendios 1 km; NDVI 250 m; PM2.5/ozono 0.1°×0.1°; NO2 LUR 100 m; OMI 0.1°. PM2.5 urbano: 0.1°×0.1° agregado a límites de ciudades.','Variable por indicador: anual para mortalidad y carga de enfermedad; 2001–2018 para incendios; 1990–2017 para ozono. MODIS NDVI: 16 días. OMI/TROPOMI: diario.','Global, con énfasis en EE.UU. Análisis específicos en Madrid/España (NO2), ciudades C40 a nivel global.','Variable: 2001–2018 (incendios); 1990–2017 (ozono); 2018–2020 (Tiger Team). Variable por indicador.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (96,'PM2.5, PM10, AOD (aerosol optical depth) — contaminantes principales. CO, SO2, NO2, O3, cianuro y otros componentes del humo mencionados como contexto. Cenizas volcánicas (partículas ≤15 mm, ≤10 mm, ≤4 mm).','Variable por estudio incluido: monitores terrestres de PM2.5 y PM10 (gubernamentales). AOD satelital (Rapold et al.). Datos de calidad del aire locales (Indonesia, North Carolina, Sydney, California, Islandia).','MODIS — AOD y detección de incendios (mencionado en Rapold et al.). No se especifican sensores satelitales en detalle en la revisión.','Variable por estudio incluido: registros de urgencias (ED), hospitalizaciones, centros de salud primaria (puskesmas, Indonesia). Diagnósticos: IRA, neumonía, bronquitis, bronquiolitis, IVR superior (URI). Códigos ICD-10 para infecciones respiratorias. Tyas et al. (Indonesia): Centro de Salud Kepohbaru, 938 casos.','Guías OMS de calidad del aire (AQG): PM2.5 ≤10 µg/m³ anual, ≤25 µg/m³ 24 h; PM10 ≤20/≤50 µg/m³. BNPB Indonesia — 775 incendios y 62 erupciones volcánicas (2018–2019). Literatura sobre mecanismos de macrófagos alveolares. Los estudios primarios incluyeron covariables como edad, sexo, raza y condiciones preexistentes.','Población general expuesta a incendios forestales o erupciones volcánicas. Grupos etarios: niños (<18 años), adultos (18–64 años), adultos mayores (>65 años). Trabajadores al aire libre (agricultores). Variable por estudio incluido.','Nivel de condado, área metropolitana o municipio. Variable por estudio primario.','Diaria para exposición y desenlaces en los estudios primarios. Períodos variables: desde 45 días hasta 11 años.','Global: EE.UU. (North Carolina, California), Australia (Sydney), Islandia (Eyjafjallajökull), Indonesia (Kepohbaru, volcán Merapi).','Estudios primarios publicados entre 2000 y 2018. Búsqueda bibliográfica hasta diciembre 2019.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (97,'PM2.5 y PM10 — contaminantes principales. AOD — proxy satelital convertido a PM. FRP — input de modelos de emisiones. Venting Index — estabilidad atmosférica en BCCDC LUR.','Variable por estudio incluido: monitores FRM/FEM EPA, redes provinciales (BC, Canadá), redes gubernamentales Australia, Europa. Estaciones temporales E-BAM. Modelos CMAQ, HYSPLIT, WRF-Chem, GEOS-Chem, TAPM-CTM, SILAM, CATT-BRAMS.','Variable por estudio: MODIS (AOD, FRP, detección incendios). MISR — AOD multiángulo. NOAA HMS — polígonos de plumas. GOES GASP. FRP satelital como input para SILAM (IS4FIRES). No se menciona Sentinel-5P.','Variable por estudio incluido: visitas médicas, hospitalizaciones, urgencias (ED), dispensación de salbutamol, mortalidad, bajo peso al nacer, otitis media. Diagnósticos: asma, EPOC, IRA, bronquitis, cardiorespiratorio. Registros administrativos (Medicare EE.UU., OSHPD California, BC Pharmanet Canadá).','Variable por estudio: temperatura, humedad, día de semana, SES, edad, sexo, tabaquismo. Datos de incendios: WFEIS, BlueSky, HMS. GFED3. Datos censales demográficos.','Variable por estudio: desde 110,000 (Darwin) hasta 488 millones (Asia Ecuatorial). Grupos etarios: <5 años, <18 años, ≥65 años (Medicare). Población indígena australiana. Mujeres embarazadas (Brasil). Personas con asma, EPOC, enfermedades cardiovasculares.','Variable: desde 250 m (LUR machine learning) hasta 222×278 km (Johnston 2012 global). Comunes: 1 km (CALPUFF), 4–15 km (WRF-Chem), 5 km (BCCDC), 10–50 km (GEOS-Chem, SILAM). Análisis de salud: código postal, condado, LHA, código postal australiano.','Diaria para la mayoría. Horaria (Alman 2016, WRF-Chem). Semanal (Trang 2014). Anual (Johnston 2012, global). Pronósticos 24–48 h (FireWork, BlueSky).','EE.UU. (10 estudios), Canadá (7), Australia (4), Brasil (2), Rusia (1), Tailandia (1), 27 países europeos (1), Asia Ecuatorial (1), Global (1). 78% en solo 3 países. Ningún estudio en Perú o la región andina.','Estudios primarios: 1996–2018. Búsqueda: junio 2018, sin restricción de fecha. Mayoría de publicaciones posteriores a 2015.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (98,'PM2.5 de humo de incendios (smoke PM2.5) — variable de exposición principal. PM2.5 de fondo no-humo (non-smoke PM2.5) — variable de control. PM2.5 total = smoke + non-smoke. AOD MAIAC — usado en el modelo de exposición. No se analizan CO, NO2, O3.','EPA AQS — monitores terrestres FRM/FEM de PM2.5 en Colorado. National Park Service — monitores adicionales para capturar PM2.5 elevado cerca de incendios. CMAQ (dos escenarios: con y sin humo/polvo). US EPA emissions inventory — emisiones de incendios forestales y prescritos.','MAIAC AOD (Multi-angle Implementation of Atmospheric Correction, MODIS Terra/Aqua) — AOD a 1 km. MODIS fire count product (NASA FIRMS) — días de incendio por grid cell. Imágenes satelitales de color real (NASA) — validación visual de la pluma modelada. No se usan VIIRS, Sentinel-5P.','Colorado Department of Public Health and Environment (CDPHE) — registros individuales de urgencias (ED) y hospitalizaciones, mayo–agosto 2011–2014. ICD-9: asma (493), bronquitis (490), EPOC (491, 492, 496), IRA superior (460–465, 466.0), respiratorio combinado, cardiopatía isquémica (410–414), IAM (410), ICC (428), arritmia (427), cerebrovascular/periférico. Total: 446,106 eventos.','Temperatura diaria (media móvil 3 días para respiratorio, 2 días para cardiovascular). Spline para día del año (ns(doy), 2 nodos internos por año). Variables de uso de suelo (modelo de exposición). US EPA emissions inventory. Humedad relativa, capa límite, índice de calor y velocidad del viento evaluados pero omitidos del modelo final.','Población general de Colorado (446,106 eventos). Estratificación por edad: niños (0–18 años, n=94,022), adultos (19–64 años, n=202,665), adultos mayores (≥65 años, n=149,419). Sexo: 241,283 femeninos, 204,823 masculinos.','Modelo de exposición: 1 km × 1 km. Análisis epidemiológico: 4 km × 4 km (requerimiento de confidencialidad CDPHE). MAIAC AOD: 1 km.','Diaria (medias móviles 2, 3 y 7 días). Período: mayo–agosto 2011–2014. Modelo de exposición: abril–septiembre 2011–2014.','EE.UU. — Estado de Colorado (Región Montañosa/Rocky Mountain). Incendios principales: High Park Fire (junio 2012), Waldo Canyon Fire (junio–julio 2012), West Fork Fire Complex (junio 2013).','Mayo–agosto 2011 a mayo–agosto 2014 (4 temporadas de incendios). Modelo de exposición: abril–septiembre 2011–2014.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (99,'PM10 (µg/m³) y API (basado en PM10, CO, SO2, NO2, O3) — indicadores principales. PM2.5 mencionado como componente clave de la bruma (definición >80 µg/m³) pero no medido directamente.','8 estaciones CAQM (Continuous Air Quality Monitoring) de Johor, operadas por DOE/ASMA: PM10 (BAM 1020), SO2 (API M100A), NO2/NOx (API 200A), O3 (Teledyne 400A), CO (API M300). Instrumentos aprobados USEPA. Datos meteorológicos GDAS 0.5° para HYSPLIT.','No se usan satélites directamente. HYSPLIT usa campos meteorológicos GDAS (reanálisis). No se usan MODIS, FIRMS, VIIRS, Sentinel-5P.','Ministry of Health (MOH) Malaysia, Health Informatics Center (HIC) — datos mensuales de morbilidad ambulatoria (outpatients) de clínicas Larkin y Pasir Gudang. Diagnósticos ICD-10: conjuntivitis, URTI y asma. Datos de días laborables, período 2015. Sin hospitalizaciones ni urgencias.','API del Departamento de Ambiente (DOE/ASMA). Información demográfica de pacientes recolectada pero no analizada en este artículo. Literatura sobre quemas de biomasa en Sumatra/Kalimantan y patrones monzónicos.','Pacientes ambulatorios de clínicas Larkin (~3,990/mes) y Pasir Gudang (~7,726/mes) con conjuntivitis, URTI o asma durante 2015. Sin estratificación por edad, sexo ni nivel socioeconómico en los resultados.','Nivel de clínica (2 clínicas) y nivel de estación CAQM (2 estaciones). Trayectorias HYSPLIT desde Sumatra y Kalimantan hasta Johor (~800–1,000 km de transporte).','Mensual (casos en días laborables; API promedio mensual). HYSPLIT: 240 h por trayectoria trimestral.','Malaysia — Estado de Johor (sur de Peninsular Malaya): Larkin y Pasir Gudang (Johor Bahru). Fuentes de contaminación: Sumatra y Kalimantan Occidental (Indonesia).','2015 (enero–diciembre). Análisis trimestral: 15 de marzo, junio, septiembre y diciembre 2015.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (100,'Número de incendios activos/día/distrito (MODIS FIRMS) — proxy de exposición a PM2.5 de quemas agrícolas. PM2.5 mencionado como mecanismo pero no medido directamente. Quema de petardos (Diwali) como factor adicional.','NASA MODIS FIRMS — datos de incendios activos diarios (hotspots de 1 km², Terra). Sin monitores terrestres de PM2.5 en Haryana/Punjab (reconocido como limitación). Sin reanálisis meteorológico.','NASA MODIS Terra — FIRMS: detección diaria de incendios activos (coordenadas GPS, resolución 1 km²). Imagen MODIS para visualización de episodio típico de ACRB. No se usan AOD, Sentinel-5P, VIIRS, GOES.','DLHS-4 (India\'s fourth District Level Health Survey, IIPS 2015) — encuesta domiciliaria representativa a nivel de distrito. Desenlace: ARI autodeclarada + búsqueda de tratamiento en los últimos 15 días (privado/público). Muestra: 252,539 individuos (3 estados). 83% de quienes reportaron ARI buscaron tratamiento.','Índice de congestión vehicular (vehículos/km²) — Censo India 2011. Tasas de DALYs por estado (India State-Level Disease Burden Initiative, Dandona et al. 2017). GDP per cápita estatal (NITI Aayog 2017). Área quemada Punjab vs. Haryana (Lohan et al. 2018: Punjab 67%, Haryana 29%).','252,539 individuos (Haryana: 90,327; AP + Tamil Nadu: 162,212). Niños <5 años (n=18,760), adultos >60 años (n=29,282). Estratificación por residencia (rural/urbana) y sexo. 5,056 casos de ARI con búsqueda de tratamiento (2% del total).','Nivel de distrito. Incendios MODIS: 1 km² por hotspot, agregados a centroide de distrito. Estimación de carga de enfermedad: nivel estatal (Haryana, Punjab, Delhi).','Diaria (datos MODIS). ARI: recall 15 días (ajustado a 7 días). Período: 1 sept 2013–28 feb 2014 (6 meses, incluyendo pico ACRB oct–nov).','India — Norte: Haryana (alta ACRB); Punjab y Delhi (estimación de carga de enfermedad). Sur (comparador sin ACRB): Andhra Pradesh y Tamil Nadu.','2013-09-01 a 2014-02-28 (6 meses). Pico ACRB: octubre–noviembre 2013. Período Diwali: 3–10 noviembre 2013.');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (101,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (102,'PM2.5 de humo de incendios (smoke PM2.5) — variable de exposición principal (continua, µg/m³). PM2.5 de fondo no-humo — estimado y sustraído. AOD (MODIS) — input del modelo GWR.','EPA AQS + Washington DOE + Oregon norte, Idaho oeste, Montana oeste + British Columbia (UBC) — total 212 monitores PM2.5. WRF-Chem (15×15 km) — PM2.5 total y sin emisiones de incendios. NOAA HMS — días sin humo para estimar PM2.5 de fondo. Temperatura, humedad relativa, viento y precipitación ponderados por censo al nivel ZIP code.','MODIS (Terra y Aqua) — AOD para el modelo GWR. NOAA HMS — polígonos de plumas de humo para días sin incendios. FINN v1.5 — emisiones de biomasa satelitales para WRF-Chem. No se usan VIIRS, Sentinel-5P.','Washington State CHARS (Comprehensive Hospital Abstract Reporting System) — urgencias y atención urgente, ICD-9-CM: todos los respiratorios (460–519), asma (493), EPOC (490–492, 494, 496), neumonía (480–486), bronquitis aguda (466), cardiovascular (390–459), arritmia (427), cerebrovascular (430–438), ICC (428), cardiopatía isquémica (410–413), IAM (410). Fractura de radio/cúbito (813) — desenlace nulo esperado para validación. Total: 26,835 urgencias/atención urgente.','Temperatura, humedad relativa, velocidad del viento y precipitación (ponderados por censo al nivel ZIP code). Datos de población para ponderación. NOAA HMS para identificación de días sin humo.','Residentes de Washington con admisiones de urgencias o atención urgente (26,835 eventos). Estratificación por edad: <15, 15–65, >65 años. Estratificación por sexo. Excluidos: pacientes con múltiples admisiones por el mismo desenlace.','15×15 km (WRF-Chem, kriging, GWR). Análisis epidemiológico: ZIP code de residencia (ponderación por población). 212 monitores en la región.','Diaria. Período: 1 julio–31 octubre 2012 (4 meses). Análisis de lag: 0–5 días.','EE.UU. — Estado de Washington. Regiones central y este más afectadas (lee side de las Cascades, consistente con patrones de viento y ubicaciones de incendios).','2012-07-01 a 2012-10-31 (4 meses, temporada de incendios 2012).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (103,'PM2.5 (µg/m³) de humo de incendios forestales — variable de exposición principal. EM incluye todas las fuentes optimizado para humo; FireWork agrega PM2.5 de humo al fondo modelado; BlueSky solo PM2.5 de humo.','84 estaciones PM2.5 de BC Ministry of Environment (>75% datos completos). Inputs modelo empírico BCCDC: monitores terrestres, AOD satelital, trazados de plumas, venting index. FireWork y BlueSky: emisiones de incendios en tiempo real, meteorología de pronóstico. Temperatura diurna de estaciones de Environment Canada más cercanas por LHA.','MODIS y otras plataformas POES — AOD y trazados de plumas de humo para el modelo empírico BCCDC. FireWork y BlueSky usan datos satelitales de incendios activos para emisiones. No se especifican sensores individuales explícitamente.','BC Medical Services Plan (MSP) billings — visitas médicas ambulatorias por asma (ICD-9: 493), 2014–2015. Total: 74,341 visitas. BC PharmaNet — dispensaciones de salbutamol, 2014–2015. Total: 227,191 dispensaciones. Agregados por LHA y día.','Statistics Canada (censo 2006) — centroides de 7,469 DA para ponderación. BC Stats 2011 — 89 LHAs. BC Wildfire Service 2016 — área quemada histórica. Temperatura diurna de Environment Canada. Población LHA para offset en GEE.','Población general de BC (4.63 millones) que usa servicios de salud. 88 LHAs (una excluida por población muy pequeña). Sin estratificación por edad ni sexo.','EM BCCDC: 5×5 km. FireWork: 10 km. BlueSky: 4 km. Análisis epidemiológico: LHA (88 áreas). Ponderación por DA (7,469 centroides).','Diaria. Temporadas: 1 junio–31 agosto 2014 y 2015 (184 días potenciales, 164 analizados). FW: pronóstico 48 h; BS: pronóstico 60 h.','Canadá — Provincia de British Columbia. Temporadas de incendios 2014 (una de las peores en historia provincial, 370,000 ha) y 2015 (280,000 ha).','2014-06-01 a 2014-08-31 y 2015-06-01 a 2015-08-31 (dos temporadas de incendios, 3 meses cada una).');
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (104,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P2` (`idArticulo`,`contaminantes`,`fuente_ambiental`,`fuente_satelital`,`fuente_salud`,`otras_fuentes`,`poblacion`,`resolucion_espacial`,`resolucion_temporal`,`pais_region`,`periodo_cubierto`) VALUES (105,'PM2.5 (µg/m³) — contaminante principal, medido en continuo (horario y diario). Levoglucosano — marcador de quema de biomasa para validar el origen del PM2.5.','Monitores E-sampler portátiles (Met One Instruments) — PM2.5 en campo (Yarra Valley 2013). Red BLANkET (EPA Tasmania): 19 monitores PM en tiempo real. Red AIRSIS (USFS, EE.UU.): monitores portátiles PM durante quemas.','No se usan datos satelitales directamente. Se mencionan sistemas de teledetección y pronóstico de calidad del aire como herramientas disponibles (Yao y Henderson 2014), pero no se aplican en el estudio.','No aplica. No se usan datos primarios de salud. Se discuten efectos en salud (asma, EPOC, hospitalizaciones, mortalidad) con base en literatura de incendios forestales como proxy para anticipar efectos de quemas prescritas.','Literatura de impactos en salud de PM2.5 de incendios (como proxy). Datos de área quemada: Australia ~100,000–200,000 ha/año; objetivo Victoria post-2009: 385,000 ha/año. Sur de EE.UU.: 3–4 millones ha/año.','No aplica directamente. Se mencionan grupos vulnerables: adultos mayores y personas con condiciones preexistentes (asma, EPOC, enfermedades cardiovasculares). Contexto: comunidades rurales y regionales cercanas a zonas de quemas.','Dos puntos de monitoreo a ~9 km de distancia (Yarra Valley, Victoria). Sin resolución espacial formal.','Horaria y diaria. Campaña de campo: temporada de quemas de otoño (abril 2013). Duración de eventos: 9–15 horas por encima de 25 µg/m³ (Yarra Valley).','Australia — Victoria (Valle de Yarra: Warburton y Yarra Junction, 2013; Ovens, 2007); Australia Occidental (Manjimup, 2007); Tasmania (Sheffield, George Town, Carrick, Lilydale, Judbury, Huonville, Geeveston, Bryn Estyn, Hobart, 2010–2013).','2007 a 2013 (estudios de caso australianos). Estudio de campo Yarra Valley: abril 2013.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (106,'N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','No reportado','N/A — artículo de revisión','N/A — artículo de revisión','No','No (revisión; cita sistemas de pronóstico/alerta de terceros, no propone uno)','Asociación positiva fuerte entre humo de incendios / PM2.5 de incendios y mortalidad por todas las causas y morbilidad respiratoria (asma, EPOC, bronquitis, neumonía); evidencia cardiovascular mixta. Poblaciones susceptibles: enfermos respiratorios/CV, adultos mayores, niños, gestantes y fetos (~339 000 muertes/año globales).','El PM2.5 de incendios es un subrogado que no capta la toxicidad diferencial de cada incendio (mala clasificación de exposición); inconsistencia en desenlaces cardiovasculares; limitaciones de potencia y diseño de los estudios primarios; escasez histórica por ocurrir incendios en zonas rurales fuera de redes de monitoreo.','La integración de monitoreo en superficie + modelamiento + AOD satelital es aplicable a Áncash, donde la red de calidad del aire es limitada y debe complementarse con datos satelitales; el Community Health-Vulnerability Index es un marco transferible para identificar poblaciones vulnerables en cuencas altoandinas; la mayor susceptibilidad infantil respalda el foco en ocurrencia de IRA.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (107,'Regresión cuasi-Poisson (control de sobredispersión) con DLNM; efecto aleatorio por SA2.','Lags 0–3, 0–5, 0–7, 0–14, 0–21 días (dosis-respuesta de PM2.5). Desenlace = mortalidad, no IRA.','Temperatura máxima, estacionalidad (spline 4 gl), tendencia, día de semana, feriados, proporción ≥80 años.','No reportado (variación espacial vía efectos aleatorios por SA2, no variables topográficas como predictores).','Riesgo relativo (RR) e IC 95%; selección de gl por AIC/BIC.','6 meses post-incendio en Morwell: +29% mortalidad todas las causas (IC95% 4–59%), +88% IHD (32–167%). Por 10 µg/m³ PM2.5: +78% muertes por lesiones a lag 0–7 (20–164%). Sin asociación con mortalidad respiratoria.','No','No.','La exposición al humo del incendio de mina de carbón se asoció con aumento de muertes por lesiones durante el incendio y de muertes cardiovasculares (IHD) en los 6 meses posteriores; sin asociación con mortalidad respiratoria.','Datos desidentificados (no captan migración); pocos eventos por causa y baja densidad poblacional (poca potencia); sin análisis SA1 (heterogeneidad intra-SA2 ignorada); no se incluyeron O3/NO2/SO2 (no elevados) ni CO (colinealidad con PM2.5).','El diseño de series temporales interrumpidas + DLNM con lags 0–21 días es trasladable a Áncash para estimar el retraso exposición→IRA ante episodios agudos de humo; el manejo de variación espacial con efectos aleatorios por unidad geográfica es un molde para distritos/provincias andinos sin estaciones; el uso de PM2.5 modelado (TAPM+CTM) ante ausencia de monitoreo anticipa el enfoque para Áncash. La ausencia de señal respiratoria advierte sobre el tamaño poblacional mínimo en cuencas altoandinas poco pobladas.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (108,'Ensamble ML (Deep Learning + Random Forest + Gradient Boosting; imputación missRanger) para contaminantes; OLS con efectos fijos por ZIP para salud; GLM cuasi-Poisson como sensibilidad.','No evaluado (solo asociaciones mismo día; los autores señalan incorporar DLNM a futuro). Desenlace = hospitalizaciones.','Viento, temp mín/máx, humedad específica, día de semana, mes, tendencia lineal, efectos fijos por ZIP.','Reportado: la elevación se incluye como predictor (variable fija) en la estimación de PM10/O3, y se estratifica por cuenca atmosférica (air basin).','R² y RMSE/MAE (contaminantes); coeficientes de regresión con IC 95% (salud).','Ensamble PM10 R²=0,78 (todos), 0,68 (test); O3 R²=0,89 (todos), 0,78 (hold-out). PM2.5 incendios y admisiones respiratorias fuera de verano coef. 0,004152 (IC95% 0,002872–0,005536); PM10 y CV todos los meses coef. 0,01015 (0,00766–0,01265).','No','No.','Los contaminantes del humo más allá del PM2.5 (PM10 y O3) tienen efectos diferenciados y heterogéneos —por región, temporada y desenlace— sobre hospitalizaciones respiratorias y cardiovasculares; enfocarse solo en PM2.5 subestima la carga.','Exposición por ZIP de residencia y comunitaria (no individual); desenlace severo (hospitalizaciones); sin lags; se omitieron precursores de O3 (NO2, VOC); un contaminante a la vez; incertidumbre en detección satelital de humo.','El marco de ensamble ML para separar la fracción de PM2.5/PM10/O3 atribuible a incendios (plumas HMS + aerosoles satelitales) es valioso para Áncash, donde la señal de humo debe aislarse del fondo y la red terrestre es escasa. La incorporación de elevación y cuenca atmosférica como predictores conecta con el campo 26 y la trampa topográfica andina. La ausencia de lags que los autores reconocen es el vacío que un diseño espacio-temporal con DLNM podría cubrir en Áncash.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (109,'Regresión cuasi-Poisson (GLM); interacción LFS×PM2.5; sensibilidad por gl de splines.','Lags 0, 1, 2 días. Problemas respiratorios a lag 0–1; "otros cardíacos" a lag 2. Desenlace = despachos cardiorrespiratorios, no IRA.','Temperatura (spline + lag 1–3), HR (spline + lag 1–3), O3 máx, día de semana, feriados, influenza, tendencia.','No reportado.','Riesgo relativo (RR) por 10 µg/m³ de PM2.5, con IC 95%.','PM2.5,all: respiratorios RR 1,03 (IC95% 1,02–1,04), paro 1,03 (1,00–1,06), dolor torácico 1,01 (1,00–1,02). PM2.5,LFS: respiratorios RR 1,04 (1,02–1,05) mismo día; "otros cardíacos" 1,05 (1,01–1,09) a lag 2. PM2.5 en días LFS ≈2,5× el de no-LFS (16,4 vs 6,8 µg/m³).','No','No (propone los EAD como indicador sensible para vigilancia casi en tiempo real).','Los despachos de ambulancia por problemas respiratorios se asocian con PM2.5 total y de humo de incendios de paisaje, siendo un desenlace sensible y de recolección casi en tiempo real para investigación y vigilancia de eventos de calidad del aire.','Los códigos EAD no son diagnósticos clínicos específicos; exposición ciudad-agregada (sin usar la geolocalización fina disponible); IC más amplios para PM2.5,LFS por menor frecuencia de eventos.','Los despachos de ambulancia georreferenciados y con marca temporal como desenlace casi-en-tiempo-real son una vía atractiva para Áncash si MINSA/SAMU tuvieran registros equivalentes, sobre todo para exposiciones agudas y muy variables como el humo. Subraya la utilidad de separar PM2.5,LFS del total —misma lógica de aislamiento de la fracción de incendios de la tesis— y la geolocalización fina no explotada marca una mejora directa para un diseño espacio-temporal andino.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (110,'Dos etapas — etapa 1: Poisson sobredispersa por condado (ajuste temp, precip, Fourier+año); etapa 2: metaanálisis de efectos aleatorios (REML).','No aplica lag diario; exposición = media mensual (mediana duración). Sensibilidad con meteo del mes previo. Desenlace = mortalidad.','Temperatura y precipitación mensual, tendencia de largo plazo y estacionalidad (Fourier + año).','No reportado (regiones climáticas NOAA modulan el efecto, pero sin variables topográficas como predictores).','IRR y diferencia de riesgo absoluto por millón (ARD), con IC 95%.','Por 10 µg/m³ PM2.5 mensual: mortalidad total IRR 1,011 (1,009–1,013); CV 1,014 (1,011–1,018); respiratoria 1,016 (1,011–1,023); ARD respiratoria 1,676/millón (1,261–2,091). Heterogeneidad regional (ARD total −5,2 Upper Midwest a +16,3 Northeast).','No','No.','La exposición a PM2.5 de mediana duración (mensual) —intervalo no regulado— se asocia positivamente con mortalidad total, CV y respiratoria; mayor impacto en adultos mayores, varones, minorías no negras y comunidades metropolitanas y socialmente vulnerables, con fuerte heterogeneidad regional.','Diseño ecológico (falacia ecológica, sin confusores individuales); mala clasificación por distribución desigual de monitores (subrepresentación rural); sin modificadores individuales para mortalidad respiratoria ni 0-19 por escasez de eventos.','El intervalo mensual de exposición es pertinente para Áncash, donde los episodios de humo por quema de biomasa pueden durar semanas; el enfoque de dos etapas (modelo por unidad + metaanálisis) maneja heterogeneidad entre distritos andinos; el tratamiento de la región climática como modificador abre la puerta a la geografía andina, aunque no modela variables topográficas (brecha del campo 26); el mayor riesgo en comunidades vulnerables respalda el foco rural altoandino.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (111,'Regresión logística condicional (caso-cruzado) + Generalized Random Forest (GRF) para efectos heterogéneos (CATEs) y perfiles de vulnerabilidad vía CART; ponderación por propensity score.','Lags 0–5 y 7; efecto respiratorio máximo a lag 0_1. Desenlace = enfermedad respiratoria/CV, no IRA estricta.','Temperatura y humedad diarias; por diseño caso-cruzado se controlan confusores fijos en el tiempo.','Reportado: análisis estructurado por cuenca atmosférica (Air Basin) —regiones meteo-geográficas homogéneas— como nivel de los perfiles de vulnerabilidad. (No incluye elevación/pendiente numérica.)','OR con IC 95% por 10 µg/m³; importancia de variables del GRF; CATEs.','Respiratorio OR 1,014 (IC95% 1,012–1,016) a lag 0_1; sin asociación CV. Variación por cuenca: San Diego County OR 1,130 (1,111–1,150). Modificadores: edad 0-14 (22% importancia), edad 15-64, sexo femenino, etnia hispana; A/C, disimilitud negro/blanco.','No','No.','El PM2.5 de incendios aumenta hospitalizaciones/urgencias respiratorias (no CV) en California, con perfiles de vulnerabilidad que varían fuertemente entre cuencas atmosféricas; el GRF identifica edad, sexo, raza/etnia y factores de área (A/C, segregación, desempleo) como principales modificadores.','No se consideraron otros contaminantes (CO, NO2); solo dos categorías amplias de desenlace; sin NSE individual; no se evaluó a quienes no pueden permanecer en interiores; GRF por cuenca por límites de cómputo; calibración mixta del BLP.','La cuenca atmosférica como unidad geográfica estructurante es conceptualmente cercana a la trampa topográfica de los valles andinos: en Áncash, las cuencas de altura con inversiones térmicas podrían cumplir un rol análogo para estratificar el efecto del humo. El enfoque GRF para perfiles de vulnerabilidad con múltiples modificadores es atractivo para una región heterogénea como Áncash, aunque exige muestras grandes. El foco en susceptibilidad infantil (edad 0-14 principal modificador) refuerza el énfasis en ocurrencia de IRA en menores.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (112,'Ecuaciones de estimación generalizadas (GEE) Poisson, correlación intercambiable, offset log-población, errores Huber-White; modelos uni- y multicontaminante (PM2.5 y O3 mutuamente ajustados).','Probaron lags hasta 7 días; mayor efecto a 1–2 días → media móvil de 2 días. Incluye IRA (ICD-9 460-465) además de asma/EPOC.','Índice de calor, tendencia (spline 3 gl), tabaquismo por ZIP, % ≥65, % ≤5, % no blanco, ingreso, día de semana, feriados.','No reportado (mencionan que topografía/combustible/meteo influyen en la composición del humo, pero no incorporan variables topográficas al modelo).','RR por 10 µg/m³ (PM2.5) o 10 ppb (O3), con IC 95%; exposición CV-R² (PM2.5 0,78; O3 0,73).','Durante el incendio (mutuamente ajustado): urgencias asma RR 1,112 (IC95% 1,087–1,138), EPOC 1,05 (1,019–1,082), respiratorio combinado 1,035 (1,023–1,046) por 10 µg/m³ PM2.5. O3 significativo solo solo (asma 1,05 [1,022–1,078]/10 ppb), se confunde al ajustar por PM2.5. PM2.5 superó 35 µg/m³ en 4 976 ZIP-días (hasta 6,07×).','No','No.','Durante un incendio de 2008 en el norte de California, el PM2.5 se asoció robustamente con hospitalizaciones y urgencias por asma y EPOC (persiste tras ajustar por O3); las asociaciones del O3 desaparecieron al ajustar por PM2.5 —el PM2.5 superó ampliamente su norma y el O3 apenas—.','Resultados específicos de ese incendio/lugar/población (combustible, meteo y topografía condicionan la composición del humo); posible error de medición de exposición pese al buen CV-R²; química no lineal del O3 (formación corriente abajo) dificulta su atribución.','El uso de mapas de superficie por ML que combinan AOD satelital + CTM + meteorología ante red de monitores escasa es el enfoque que Áncash necesita para reconstruir la exposición a humo. La inclusión explícita de infecciones respiratorias agudas (ICD-9 460-465) lo hace de los más cercanos a la variable de ocurrencia de IRA del corpus extraído. El reconocimiento de que topografía y combustible alteran la composición del humo —sin modelarlos— señala la brecha que el campo 26 propone llenar en el contexto andino.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (113,'GAMM quasi-Poisson con efectos aleatorios por SA2 y offset de log-población; dos análisis: (1) período de incendio vs. no-incendio (variable binaria); (2) PM2.5 diario vs. urgencias/admisiones con lag 0–7 y media móvil acumulada 0–7 días.','Urgencias: lag 2 días para todas las causas y EPOC; lag 4 días para enfermedades respiratorias y EPOC+asma; sin asociación para asma sola. Admisiones: lag 0 para respiratorio y cerebrovascular; lag 3 para EPOC y EPOC+asma; lag 7 para asma sola. Desenlace = urgencias/admisiones hospitalarias (ICD-10), no IRA infecciosa estricta.','Temperatura máxima diaria (media móvil 7 días, spline natural 3 gl), mes calendario (estacionalidad), día de semana, offset de población por SA2.','No reportado (variación espacial captada por efectos aleatorios por SA2; sin variables topográficas como predictores).','Riesgo relativo (RR) con IC 95%, para media móvil 0–7 días de PM2.5.','Por 10 µg/m³ de PM2.5 (media móvil 0–7 días): urgencias — todas las causas RR 1,06 (IC95% 1,02–1,09), respiratorio RR 1,14 (1,02–1,29), EPOC+asma RR 1,22 (1,02–1,45), EPOC RR 1,39 (1,06–1,83); admisiones — EPOC+asma RR 1,28 (1,01–1,63). Sin asociación significativa con causas cardiovasculares.','No','No (recomienda mensajes dirigidos a personas con enfermedades respiratorias y planes de automanejo durante futuros incendios).','Las tasas de urgencias y admisiones por causas respiratorias (EPOC, asma) aumentaron durante el incendio de mina de carbón; por cada 10 µg/m³ de PM2.5 acumulado 0–7 días, el riesgo de urgencias respiratorias aumentó 14% (RR 1,14; 1,02–1,29) y el de urgencias por EPOC un 39% (RR 1,39; 1,06–1,83); sin asociación con causas cardiovasculares.','Sin exposición individual a PM2.5 (sesgo hacia el nulo); solo se consideró PM2.5 de incendio, excluyendo otros contaminantes del carbón (O3, NO2, SO2); PM2.5 modelado en área amplia con zonas sin monitoreo (error de medición probable); baja densidad poblacional (potencia limitada para subgrupos); diseño ecológico.','El GAMM con lags 0–7 días y media móvil acumulada es directamente aplicable para estimar el retraso exposición→IRA en Áncash ante episodios de humo de biomasa; el lag diferenciado por tipo de desenlace (urgencias vs. admisiones, EPOC vs. asma) orienta la elección de ventanas temporales para los registros MINSA; el PM2.5 modelado con CTM+CCAM a 100 m ante ausencia de monitoreo es el enfoque más cercano a la situación de Áncash; la baja densidad poblacional como limitante de potencia estadística es una advertencia directa para cuencas andinas poco pobladas.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (114,'Regresión ridge ponderada geográficamente (GWR ridge, ensamble; Lassman et al. 2017 / Gan et al. 2017) para estimación de exposición a PM2.5 de humo; cálculo de carga de salud mediante fórmula C-R × tasa de línea base × población expuesta. No se desarrolla modelo propio de exposición-respuesta.','No aplica (el estudio no estima lags; las C-R compiladas de literatura usan lag 0 a lag 0–5 según el estudio fuente).','No aplica (sin modelo de regresión propio; el ajuste por confusores depende de los estudios primarios de los que se extraen las C-R).','No reportado (el análisis de proximidad usa GIS para clasificar condados por cercanía al incendio; se reconoce explícitamente que la meteorología y el terreno condicionan el transporte del humo, pero ninguna variable topográfica entra como predictor formal del modelo).','C-R compiladas de literatura (β por µg/m³ de PM2.5, con IC 95%); sin métrica de evaluación propia del modelo.','C-R para asma (urgencias): β 0,501 (IC95% 0,223–0,775) a lag 0–5 (Rappold 2011); β 0,008 (0,004–0,012) por µg/m³ a lag 0 y 0,014 (0,008–0,019) a lag 0–2 (Alman 2016). EPOC (urgencias): β 0,548 (0,058–1,040) a lag 0–5; β 0,008 (0,003–0,014) a lag 0 (Gan 2017). Valores propios del piloto no reportados cuantitativamente.','Si','Sí — herramienta web en desarrollo (beta) integrada en CDC NEPHTN: pronóstico operacional de humo (NOAA/NWS) + SVI + tasas de salud de línea base + cartografía interactiva; tipo: vulnerabilidad en tiempo real con visualización de mapa; orientada a practitioners y respondedores de emergencia, no sistema de alerta clínica automática.','Se diseña y valida en piloto una herramienta web integrada en la plataforma CDC NEPHTN que combina pronósticos de humo en tiempo real (NOAA/NWS), índice de vulnerabilidad social (SVI) y tasas de salud de línea base para identificar poblaciones en riesgo durante episodios de incendios forestales; el piloto con 11 incendios (2008–2013) demuestra factibilidad de integración de datos heterogéneos y documenta la disponibilidad variable de datos de salud por jurisdicción.','Las predicciones históricas de humo no están archivadas sistemáticamente para acceso público; la toxicidad diferencial de los componentes del humo es poco conocida; las C-R disponibles provienen de pocos incendios y no son necesariamente representativas a escala nacional; la herramienta no incluía validación empírica de sus predicciones al momento de publicación; el análisis de proximidad espacial ignora el transporte meteorológico y la topografía del terreno.','La arquitectura CDC NEPHTN —pronóstico de exposición + SVI + cartografía en tiempo real— es el referente conceptual más claro para el componente de alerta sanitaria del proyecto PROCIENCIA en Áncash (fuera del alcance directo de la tesis). El reconocimiento explícito de que la meteorología y el terreno condicionan el transporte de humo —sin modelarlos— marca precisamente la brecha metodológica que el campo 26 propone cubrir en el contexto andino. La compilación de C-R de literatura como insumo para estimar carga de enfermedad es transferible al contexto peruano, donde no existen C-R locales para IRA por humo de biomasa. La interoperabilidad con agencias sectoriales (USFS, NOAA, EPA) tiene un análogo directo en la coordinación SENAMHI-MINSA-SERFOR necesaria en Perú.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (115,'Modelo lineal generalizado (GLM) familia binomial con función de enlace log (RR) e identidad (diferencia de riesgo); errores estándar robustos (sandwich estimator); prueba de interacción multiplicativa y aditiva entre AQI y modificadores (enfermedad reactiva, prematuridad, tipo de vía aérea, cirugía de vía aérea, IMC, edad); DAG para identificar confusores y colisionadores.','No aplica como lag epidemiológico: la exposición se define como AQI>100 en los 14 días previos al acto quirúrgico; el desenlace es intraoperatorio/inmediato. No es IRA infecciosa ni diseño de lag exposición→infección.','Historia de enfermedad de vía aérea reactiva (ajuste formal en todos los modelos, identificado como colisionador potencial por DAG); los incendios se tratan como asignación aleatoria natural (sin confusores ambientales adicionales).','No reportado.','Riesgo relativo (RR) con IC 95% y valor p; diferencia de riesgo (RD) con IC 95%; número necesario para dañar (NNH); diferencia estandarizada absoluta para balance de grupos.','Niños con enfermedad reactiva: RR 1,50 (IC95% 1,04–2,17; p=0,032); interacción multiplicativa RR 1,56 (1,02–2,40; p=0,041); interacción aditiva RD 20,1% (1,9–38,3; p=0,031); NNH=5,5 (IC95% 2,9–41,0). Niños sin enfermedad reactiva: RR 0,96 (0,77–1,19; p=0,703). Prematuros (tendencia, no significativa): RR 1,87 (1,00–3,50; p=0,050). Post-hoc (reclasificando 13 niños): RR 1,57 (1,07–2,30; p=0,021).','No','No (propone que el AQI>100 sea considerado factor de riesgo adicional para posponer cirugías electivas en pacientes pediátricos con enfermedad de vía aérea reactiva).','El riesgo de eventos respiratorios adversos bajo anestesia general aumentó un 50% (RR 1,50; p=0,032) en niños con enfermedad de vía aérea reactiva expuestos a aire no saludable por humo de incendio (AQI>100); la modificación de efecto fue significativa en escala multiplicativa y aditiva; en niños sin ese antecedente no hubo efecto; el NNH de 5,5 sugiere que posponer cirugías electivas en días de AQI>100 es una medida clínicamente relevante para este subgrupo.','Diseño retrospectivo unicéntrico (posible subregistro de eventos leves; sesgo de reporte del anestesiólogo); exposición binaria por AQI domiciliario (sin gradiente de PM2.5 ni separación de fracción de humo); sin datos sobre uso de mascarillas, filtración domiciliaria ni infección respiratoria alta reciente; sin datos de tabaquismo pasivo en el hogar; muestra insuficiente para analizar prematuridad (n=54) y para tratar AQI como variable continua; dos períodos únicos sin replicación en otros centros; posible sesgo de cancelación de cirugías en niños sintomáticos (abordado con ajuste por enfermedad reactiva vía DAG).','La enfermedad de vía aérea reactiva como principal modificador del efecto del humo sobre eventos respiratorios agudos refuerza la pertinencia de estratificar por antecedente respiratorio en el análisis de ocurrencia de IRA en Áncash, donde la prevalencia de asma y EPOC puede ser un modulador relevante. El umbral AQI>100 como variable binaria de exposición operacionalizable es una alternativa pragmática para zonas con monitoreo limitado. El uso de DAG para identificar colisionadores es un aporte metodológico transferible al diseño de análisis en registros MINSA, donde la cancelación de atenciones durante episodios de humo podría introducir un sesgo análogo. El diseño de doble cohorte con períodos inmediatamente anteriores como control es replicable en contextos con datos históricos fragmentados.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (116,NULL,NULL,NULL,NULL,NULL,NULL,'No',NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (117,'Regresión Poisson con DLNM (función cross-basis lineal, polinomio de 4° orden para incendios con lag 0–10 días); spline natural para tendencia temporal (5 df para 5 años, 10 df para 10 años); variables dummy estacionales (verano referencia); longitud y latitud de centroides como efectos fijos; modelos separados para respiratorio y circulatorio en dos ventanas temporales.','Lag acumulado 0–10 días para focos activos de incendio (exposición principal); pico individual a lag 0–2 y lag 7–10 según gráficas. Desenlace = hospitalizaciones respiratorias (ICD-10 J00–J99), no IRA infecciosa estricta.','PM2.5, PM10, SO2, NO2 (covariables continuas); temperatura media (lag 0 y lag 1–3, efecto constante por estrato); humedad relativa (término lineal sin lag); estación del año (dummy); tendencia temporal (spline natural); longitud y latitud de centroide ZIP.','No reportado (la topografía del Pantanal —terreno plano rodeado de montañas que genera efecto \'trampa\' para el humo— se discute como factor explicativo y motivó la exclusión del viento del modelo, pero no se incorpora como variable cuantitativa predictor formal).','Riesgo relativo (RR) ajustado con IC 95% para un incremento de 10 focos activos acumulado en 10 días; excess relative risk (ERR = RR − 1).','2010–2019: respiratorio RR 1,232 (IC95% 1,224–1,240), +23,2%; circulatorio RR 1,224 (IC95% 1,212–1,236), +22,4%. 2015–2019: respiratorio +33,84%, circulatorio +29,30%. En Corumbá: días sin incendio = 2,26 hosp. respiratorias / 1,53 CV; días con incendio (lag 10) = 40,25 / 28,36 (~+1.680% y ~+1.754%).','No','No (el estudio propone que sus resultados orienten a autoridades brasileñas en anticipar aumentos de demanda hospitalaria; no implementa sistema de alerta operacional).','Un incremento de 10 focos activos de incendio se asoció con un aumento acumulado del 23,2% en hospitalizaciones respiratorias y del 22,4% en las cardiovasculares en el Pantanal (2010–2019); en 2015–2019 los efectos fueron más pronunciados (+33,8% y +29,3%); la topografía de cuenca plana rodeada de montañas se señala como factor que amplifica la exposición al humo.','Los datos NASA de focos activos son definiciones globales que pueden subestimar o sobreestimar eventos locales; el tamaño del área del ZIP introduce sesgo de escala; sin validación in situ ni delimitación local; exposición individual no disponible (diseño ecológico); no se modeló la relación entre incendios y PM2.5 por regresión separada; sensibilidad de funciones de suavizado y polinomios requeriría análisis extenso que excede los recursos computacionales; cobertura DataSUS incompleta (~72–80%).','El uso de focos FIRMS/MODIS como variable de exposición principal combinado con PM2.5/PM10/SO2/NO2 de MERRA-2 ante ausencia de red terrestre es el diseño más transferible al contexto de Áncash. La trampa topográfica del Pantanal (plano rodeado de montañas) es funcionalmente análoga a la trampa topográfica andina (valles de altura con inversiones térmicas), proporcionando respaldo empírico para incorporar variables topográficas en el campo 26. El modelo Poisson-DLNM con lag 0–10 días y covariables satelitales por ZIP es replicable a nivel de distrito/microrred en Áncash. La geolocalización de casos por código postal como proxy del individuo anticipa el enfoque para registros MINSA geolocalizados por establecimiento.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (118,'Regresión Poisson con DLNM no lineal; RR acumulado (cumulative RR) como medida de efecto; estratificación por sexo y edad mediante meta-regresión de efectos aleatorios univariada.','Lag 3–7 días para medicamentos respiratorios; lag 3–6 días para cardiovasculares y psiquiátricos. Inicio de asociación a partir del día 3 para los tres tipos. Desenlace = dispensación de medicamentos (proxy de morbilidad), no IRA infecciosa directa.','Temperatura máxima diaria (spline natural 4 gl, lag 0–7 días), estacionalidad (mes del año), tendencia a largo plazo (año como variable continua), día de semana, feriados y períodos de quiebre de demanda (excluidos del análisis).','No reportado.','RR acumulado con IC 95% y valor p; p-valor de diferencia entre estratos por meta-regresión univariada.','Por 10 µg/m³ PM2.5 (RR acumulado): respiratorio RR 1,25 (IC95% 1,19–1,32); cardiovascular RR 1,10 (1,07–1,13); psiquiátrico RR 1,12 (1,08–1,16). Por edad, mayor asociación respiratoria en 20–34 años (RR 1,62; 1,34–1,96); cardiovascular y psiquiátrico en ≥50. Mujeres > hombres en respiratorio y cardiovascular; hombres > mujeres en psiquiátrico.','No','No (los resultados se proponen como guía para respuesta de salud pública ante futuros incendios de mina de carbón).','El PM2.5 del incendio de mina de carbón se asoció con mayor dispensación de medicamentos respiratorios (RR 1,25), cardiovasculares (RR 1,10) y psiquiátricos (RR 1,12) a partir del día 3 de exposición; las asociaciones fueron más consistentes y fuertes que en estudios de incendios forestales, posiblemente por la duración prolongada (7 semanas) del evento.','La dispensación no refleja necesariamente exacerbación clínica real ni adherencia; solo medicamentos con subsidio PBS (excluye OTC); algunos medicamentos son inespecíficos (ej. corticoides sistémicos); sin exposición individual (asignación a nivel SA3); PM2.5 modelado con incertidumbre en emisiones, profundidad de quema y dispersión del penacho.','El uso de la dispensación de medicamentos como proxy objetivo de morbilidad respiratoria es transferible a Áncash si se dispone de registros SIS/SUSALUD sobre prescripciones en establecimientos MINSA. El lag de 3–7 días para medicamentos respiratorios amplía la evidencia del campo 24. La estratificación por edad que muestra mayor susceptibilidad en <35 años refuerza el foco en IRA pediátrica. La exposición prolongada (7 semanas) como factor amplificador es relevante para episodios de quema de biomasa de larga duración en Áncash.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (119,'Regresión Poisson de series temporales con parámetro de sobredispersión; control de tendencia y estacionalidad mediante triple interacción año×mes×día de semana (equivalente a caso-cruzado estratificado); modelos separados para días de humo y no-humo; selección de lag y forma funcional de temperatura por AIC.','Lags 0–4 días probados. Mortalidad CV significativa a lag 0 (≥65 años: +13,8%) y lag 3 (total: +12,4%; ≥65 años: +11,8%). EPOC/asma (hospitalizaciones) más fuerte a lag 2 (+15,8%). Desenlaces = mortalidad y hospitalizaciones (no IRA infecciosa estricta).','Temperatura media 24 h (lineal/cuadrático y promedios 2–3 días, selección por AIC); humedad relativa (misma lógica); influenza semanal (dummy percentil 80); polen total (dummy 100 granos/m³); feriados públicos; sobredispersión. Sensibilidad con O3 y PM2.5–10.','No reportado (estudio de transporte de largo alcance; topografía no se modela como predictor).','% de cambio en riesgo con IC 95% por 10 µg/m³ de PM2.5; p-valor reportado.','Días de humo: mortalidad CV total lag 3: +12,4% (IC95% −0,2 a 26,5; p=0,054); ≥65 años lag 0: +13,8% (−0,6 a 30,4; p=0,06) y lag 3: +11,8% (−2,2 a 27,7; p=0,10). Hosp. EPOC/asma lag 2: +15,8% (−2,1 a 37; p=0,09). Hosp. respiratorio ≥65 años lag 0: +10,5% (−2,2 a 24,8; p=0,11). Sin asociación en días no-humo con desenlaces CV ni hospitalizaciones.','No','No (recomienda avisos a la población para permanecer en interiores, cerrar ventanas, evitar actividad física al exterior y usar purificadores de aire en centros de cuidado de personas vulnerables durante episodios de humo).','El PM2.5 de humo transportado a larga distancia desde incendios de vegetación de Europa oriental se asoció con incrementos borderline-significativos en mortalidad cardiovascular (total: +12,4% lag 3; ≥65 años: +13,8% mismo día) e indicios de mayor hospitalización por EPOC/asma (+15,8% lag 2) en Helsinki; sin asociación con mortalidad no-accidental ni hospitalizaciones cardiovasculares.','Solo 72 días de humo en 10 años (potencia estadística limitada, IC amplios); imposible estudiar mortalidad respiratoria por escasos eventos; fracción exacta de PM2.5 atribuible a incendios desconocida (posible mezcla con contaminación antropogénica de Europa oriental); un solo monitor de fondo urbano como exposición área-agregada (posible mala clasificación); resultados en población de baja contaminación de fondo que puede no generalizarse a regiones con niveles basales altos.','El transporte de largo alcance de humo que multiplica ×3 el PM2.5 de fondo es análogo al fenómeno de acumulación en cuencas andinas con inversión térmica en Áncash, donde el humo puede ser local (quemas agrícolas) y transportado (incendios del Amazonas/selva alta). El diseño de caso-cruzado estratificado por tiempo —equivalente a la regresión Poisson con triple interacción año×mes×día— es un estándar transferible al análisis de series temporales distritales con registros MINSA. El lag 2–3 días para efectos respiratorios consolida la ventana de análisis del campo 24. El uso de NAAPS para identificar episodios de humo de largo alcance señala una fuente satelital disponible para caracterizar el aporte de humo transportado desde la Amazonia hacia Áncash.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (120,'Módulo 4 (pronóstico de salud): random forest (1.000 árboles) con predictores: PM2.5 ponderado day₀ y day₋₁ (OSSEM), tendencia larga plazo (mismo día de semana, 12 semanas), tendencia corto plazo (4 semanas), semana del año; pseudo-R²=0,94; RMSE=17,6 dispensaciones. Módulo 3 (PM2.5): random forest blending FireWork+OSSEM; pseudo-R²=0,85; RMSE=4,7 µg/m³.','No aplica como lag epidemiológico: el sistema usa PM2.5 del day₀ y day₋₁ como predictores; no estima lag exposición→desenlace en sentido causal. Desenlace = dispensaciones de inhalador (proxy asma/EPOC), no IRA infecciosa.','Día de semana y feriados (capturados en las tendencias de corto y largo plazo del RF); semana del año (estacionalidad); sin ajuste explícito por temperatura en el modelo de salud (RF los absorbe implícitamente).','Reportado: el Venting Index (VI), que refleja la capacidad de dispersión atmosférica condicionada por la topografía, se incorpora como predictor formal en el modelo OSSEM de estimación de PM2.5 (Módulo 1). La topografía compleja de BC se reconoce explícitamente como fuente de variabilidad en el desempeño del sistema entre HSDA.','IOA (index of agreement, 0–1); RMSE absoluto y por 10.000 hab. para dispensaciones; pseudo-R² para modelos de entrenamiento; % de pronósticos dentro del ±20% del valor observado.','PM2.5 2018: media ponderada provincial 22,0 µg/m³ (vs. 4,2 µg/m³ en 2016). Pronóstico PM2.5: IOA ponderado 0,85 (rango 0,65–0,95); RMSE 20,5 µg/m³. Dispensaciones de inhalador: +30% sobre 2016; IOA ponderado 0,95 (rango 0,92–0,98); 71% de pronósticos dentro del ±20% del observado; RMSE 0,56/10.000 hab.','Si','Sí — BCAPS: sistema operacional de vigilancia y predicción de impacto en salud por humo de incendios; tipo: pronóstico probabilístico diario (day₀ y day₊₁) de dispensaciones de inhalador por HSDA, integrado con pronóstico de PM2.5 y visualización cartográfica; distribuido a ~30 usuarios de salud pública de BC cada mañana durante la temporada de incendios.','El sistema BCAPS generó pronósticos diarios de dispensaciones de inhaladores con fuerte concordancia con las observaciones reales (IOA 0,95; 71% dentro del ±20%) durante la peor temporada de incendios de BC hasta 2018, a pesar de que los pronósticos de PM2.5 subestimaron las concentraciones más extremas; el desempeño fue mejor en HSDA con mayor población y exposiciones moderadas.','OSSEM y pronósticos PM2.5 limitados a 150 µg/m³ (cap inapropiado para 2018 donde se midieron hasta 883 µg/m³); modelo de salud entrenado sin exposiciones tan extremas, posiblemente atenuando pronósticos; random forest como \'caja negra\' dificulta interpretación; máximo del HSDA como representación de PM2.5 sobrestima la exposición promedio; sin evaluación cualitativa del uso de los informes; posicionamiento de estaciones no siempre refleja áreas de mayor impacto.','BCAPS es el sistema de alerta operacional más evaluado empíricamente del corpus: su arquitectura modular (exposición histórica + desenlace histórico + pronóstico de exposición + modelo de salud + visualización) es el referente directo para el componente de alerta del proyecto PROCIENCIA en Áncash (fuera del alcance de la tesis). El Venting Index como predictor proxy del efecto topográfico sobre la dispersión del humo es la aproximación más cercana a modelar la trampa topográfica andina en el campo 26; en Áncash podría sustituirse por un índice de estabilidad atmosférica o inversión térmica calculado con MERRA-2. La dependencia del desempeño respecto al tamaño poblacional del HSDA es una advertencia crítica para distritos andinos poco poblados.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (121,'N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','No','N/A — artículo de revisión','La revisión sintetiza evidencia sobre los efectos del humo de incendios forestales en asma y alergias: el PM2.5 de incendios es hasta 10 veces más dañino para la salud respiratoria infantil que el PM2.5 de otras fuentes; la exacerbación de asma es el desenlace con evidencia más robusta (RR 1,10 por 10 µg/m³); las poblaciones vulnerables incluyen niños, adultos mayores, embarazadas, trabajadores al aire libre y comunidades marginadas; el cambio climático amplifica frecuencia e intensidad de incendios y niega mejoras en calidad del aire logradas por transición energética. Se propone un enfoque multifactorial: máscaras N95, espacios de aire limpio, sistemas de alerta y gestión forestal.','Escasez de estudios sobre efectos respiratorios crónicos del humo de incendios; evidencia sobre EPOC menos robusta que para asma; falta de estudios controlados sobre uso de máscaras en niños; mecanismos de sensibilización alérgica por humo no del todo comprendidos; datos sobre exposición ocupacional de bomberos forestales predominan sobre datos de población general.','La síntesis de mecanismos inmunológicos (hipótesis de la barrera epitelial, estrés oxidativo, metilación de ADN) proporciona respaldo biológico para la asociación humo–IRA en Áncash, especialmente en niños con vías aéreas en desarrollo. La mayor susceptibilidad de comunidades indígenas y rurales sin acceso a monitoreo es directamente análoga a la situación de cuencas altoandinas sin red de monitoreo. La propuesta de microsensores fusionados con datos de estaciones como alternativa de bajo costo para zonas subatendidas es pertinente para el diseño de la red de monitoreo en Áncash. La figura conceptual de intervenciones (alerta oportuna → reducción de exposición) es el referente clínico-comunitario para el componente de alerta del proyecto PROCIENCIA.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (122,'N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','No','N/A — artículo de revisión','La revisión documenta que la neblina transfronteriza en Malaysia (originada en quemas de turba y agricultura de tala-y-quema en Sumatra y Kalimantan, Indonesia) es el fenómeno de contaminación recurrente más severo del SEA; el ENSO explica el 50–75% de la variabilidad interanual del PM10 local; los episodios de neblina incrementaron la mortalidad respiratoria en un 19% y las visitas hospitalarias por EPOC, IRA alta, asma y rinitis; los niños y adultos mayores son los más afectados; el costo hospitalario se estimó en ~USD 91.000 anuales; el PM en neblina está dominado por aerosoles inorgánicos secundarios (SO₄²⁻, NH₄⁺) y levoglucosano como marcador de quema de biomasa.','La mayoría de estudios sobre emisiones de turba son de laboratorio, sin confirmación de campo suficiente; red de monitoreo de calidad del aire en Malaysia subrepresneta zonas rurales; estimaciones de mortalidad dependen de funciones C-R de otros países; falta de estudios prospectivos sobre efectos crónicos; datos de focos activos satelitales (FIRMS) disponibles solo desde 2002, limitando el análisis histórico.','El patrón de quema de turba y biomasa de SEA —transporte transfronterizo modulado por ENSO y monzón— es funcionalmente análogo a los episodios de quema agrícola y de vegetación de la selva alta peruana que generan humo transportado hacia cuencas andinas de Áncash. El levoglucosano como marcador específico de quema de biomasa podría servir de referencia para caracterizar la fracción de incendios en muestras de PM de Áncash si se disponen de análisis químicos. La relación ENSO–intensidad de incendios es un antecedente metodológico para incorporar el ENSO (La Niña y sequías del Perú central) como modulador de la actividad de incendios en OE3. El transporte atmosférico a larga distancia como amplificador de la exposición local refuerza el argumento para incluir datos de focos FIRMS/VIIRS de la selva alta en el análisis espacial de Áncash.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (123,'Algoritmo PHIDO (Public Health Intelligence for Disease Outbreaks) — regresión iterativa con GAM ponderados para determinar la distribución esperada de recuentos de salud; identifica excursiones en percentiles 95 (inusual), 99 y 99,9 (raro). Para evaluación: sensibilidad y especificidad de umbrales de PM2.5 (≥5, ≥10, ≥25 µg/m³) como prueba de tamizaje de excursiones; ventanas de 7 días para asignar exposición.','No se estima un lag específico. Se usó ventana de 7 días (3 días antes, día de excursión, 3 días después) para asignar la PM2.5 máxima, reconociendo que las excursiones pueden ocurrir antes, durante o después del pico (por mensajes de salud pública o acumulación de demanda). Desenlace = visitas por asma y dispensaciones de salbutamol, no IRA infecciosa.','No hay ajuste por confusores clásicos en PHIDO (el algoritmo compara con tendencias históricas). Se excluyeron excursiones dentro de 3 días posteriores a feriado, salvo que se asociaran con PM2.5 ≥25 µg/m³.','No reportado. Se asigna exposición a nivel de HSDA pero sin variables topográficas (altitud, pendiente, cuencas, inversiones térmicas) en los modelos.','Sensibilidad y especificidad de umbrales de PM2.5 como prueba de tamizaje de excursiones; porcentaje de excursiones asociadas a distintos rangos de PM2.5; proporción de días con humo (smoky days) con al menos una excursión. Sin R², RMSE ni AUC.','Excursiones totales: 35 para visitas médicas (1 rara), 48 para dispensaciones de salbutamol (9 raras). PM2.5 medida ≥10 µg/m³: 55,9% de excursiones de visitas médicas, 51,3% de dispensaciones. PM2.5 ≥25 µg/m³: 100% de excursiones raras en ambos desenlaces. Días con humo (PM2.5 ≥25): 43 días-HSDA; 55,8% tuvieron excursión de visitas médicas, 69,8% de dispensaciones. Sensibilidad (PM2.5 medido ≥25 µg/m³): visitas médicas 71,4%, dispensaciones 85,7%. Especificidad: ~90% para ambos. Pronósticos BlueSky/FireWork: sensibilidades <40% en la mayoría de los casos.','Si','Sí — BCAMS (British Columbia Asthma Monitoring System). Sistema de vigilancia pasiva que genera informes semanales durante la temporada de incendios, identificando excursiones (alertas) en dos categorías: \'inusual\' (recuento >percentil 95) y \'raro\' (percentil 99,9). Apoya toma de decisiones de salud pública y gestión de emergencias. No es un sistema automatizado en tiempo real (rezagos en datos de salud).','El sistema BCAMS alertó más frecuentemente cuando las concentraciones de PM2.5 eran relativamente altas (≥10–25 µg/m³). La sensibilidad del umbral de PM2.5 ≥25 µg/m³ para detectar excursiones fue 71–86%, con especificidad ~90%. Las dispensaciones de salbutamol mostraron señal más fuerte (más excursiones, mayor sensibilidad) que las visitas médicas por asma. Los pronósticos de humo específicos (BlueSky, FireWork) tuvieron desempeño inferior en la predicción de excursiones.','Rezago de hasta 5 días en datos de visitas médicas y hasta 2 semanas en dispensaciones de salbutamol (impide vigilancia en tiempo real). Posible clasificación errónea de desenlaces por códigos de diagnóstico. Agregación espacial amplia (HSDA) introduce error de medición de exposición. Las excursiones pueden ocurrir por razones distintas al humo (ruido), aunque se mitigó con exclusión de días festivos. Los pronósticos de humo (BlueSky, FireWork) mostraron baja sensibilidad.','El BCAMS es la implementación operacional más documentada de un sistema de vigilancia asma-humo con evaluación formal de sensibilidad/especificidad, lo que lo convierte en referente directo para el componente de alerta del proyecto PROCIENCIA en Áncash. El uso de múltiples métricas de exposición (medida, modelada, pronosticada) anticipa el enfoque híbrido necesario en regiones sin red de monitoreo densa. La evaluación de sensibilidad/especificidad de umbrales de PM2.5 es directamente aplicable para definir umbrales de alerta en Áncash, aunque el estudio no considera topografía de montaña ni IRA infecciosa, que son los desenlaces centrales de la tesis.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (124,'GAM binomial negativo con efectos aleatorios por SA2 y offset poblacional; modelos de lag distribuido (lag 0–20 días); comparación binaria período de incendio vs. resto del período de análisis.','Lags 0–20 días. Por cada 10 µg/m³ de PM2.5 del incendio (lag 0–20): asistencias respiratorias +42% (IC95% 14–76%). Durante el período del incendio (30 días): asistencias respiratorias +47% (19–81%). Desenlace = asistencias de ambulancia (no IRA infecciosa estricta).','Temperatura máxima diaria (spline, lag no lineal hasta 21 días), estacionalidad (spline cúbico natural, 4 gl), tendencia a largo plazo (año continuo), día de semana (categórico), feriados (binaria), intercepto aleatorio por SA2, offset poblacional.','No reportado (variación espacial captada por efectos aleatorios por SA2; sin variables topográficas como predictores formales).','Riesgo relativo (RR) con IC 95%, para PM2.5 continuo (por 10 µg/m³) y para el período de incendio (binario).','Por 10 µg/m³ de PM2.5 (lag 0–20): asistencias respiratorias RR 1,42 (IC95% 1,14–1,76); todas las causas RR 1,07 (1,00–1,14). Durante el período del incendio (vs. no-incendio): respiratorio RR 1,47 (1,19–1,81); todas las causas RR 1,15 (1,08–1,21). Sin asociación significativa para causas cardiovasculares ni lesiones.','No','No (los resultados apoyan el desarrollo de planes de respuesta de salud pública ante futuros incendios de mina de carbón, pero no implementa sistema de alerta).','El PM2.5 del incendio de mina de carbón Hazelwood se asoció con un aumento del 42% en asistencias de ambulancia por causas respiratorias (lag 0–20 días) y del 47% durante el período activo del incendio; sin efectos significativos en causas cardiovasculares ni lesiones.','Sin exposición individual a PM2.5 (asignación a nivel SA2, sesgo hacia el nulo). Baja densidad poblacional del Valle de Latrobe (potencia limitada para subgrupos). PM2.5 modelado con incertidumbre en emisiones, profundidad de quema y dispersión de penacho. Datos de asistencia de ambulancia sin diagnóstico clínico confirmado. No se incluyeron otros contaminantes (NO2, SO2, metales pesados del carbón).','Las asistencias de ambulancia con código de motivo como desenlace casi en tiempo real para vigilancia activa representan una vía directamente replicable con datos de emergencias SAMU/MINSA en Áncash. El lag extendido de 0–20 días para efectos respiratorios amplía la ventana de análisis más allá de los 7 días estándar y es relevante para episodios prolongados de humo de biomasa andina. El diseño Hazelwood con PM2.5 modelado ante ausencia de monitoreo es el análogo más directo a la situación de Áncash, donde la red de monitoreo es igualmente limitada.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (125,NULL,NULL,NULL,NULL,NULL,NULL,'No',NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (126,NULL,NULL,NULL,NULL,NULL,NULL,'No',NULL,NULL,NULL,NULL);
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (127,'Modelos de regresión supervisada: SVR, MLP, Random Forest, XGBoost y NGBoost. Grid Search para hiperparámetros; validación cruzada 5-fold; eliminación de outliers por Cook\'s distance. Interpretación con SHAP (Shapley Additive Explanations). NGBoost fue el modelo seleccionado como mejor.','No estimado. El estudio no analiza retrasos entre exposición y mortalidad. Los modelos de PM2.5 predicen concentraciones del mismo día; los de mortalidad asocian exposición anual con mortalidad anual sin lags. Desenlace = mortalidad por EPOC y cáncer de pulmón, no IRA.','No hay ajuste por confusores en sentido epidemiológico. En el modelo de mortalidad, las variables de entrada son edad, sexo, tipo de contaminación y año. En el modelo de PM2.5, los predictores son meteorológicos y de combustible, sin ajustar por fuentes de PM ajenas a los incendios.','No reportado. Sin variables topográficas (altitud, pendiente, cuencas, inversiones térmicas) en los modelos. La única referencia geográfica es la localización de la estación meteorológica en Wagga Wagga.','RMSE, MAE, MAPE y MBE. Para selección de modelos se privilegió el MAE por robustez a outliers.','Modelo PM2.5 (NGBoost, test): RMSE=23,4; MAE=8,0; MAPE=66%; MBE=−1,5. Importancia de características (Gini): radiación solar 0,35; humedad de combustible 0,29; temperatura 0,21; velocidad del viento 0,08. Modelo EPOC (NGBoost, test): MAE=5,6; RMSE=11,2. SHAP: contaminación ambiental > doméstica > sexo > edad > año. Modelo cáncer de pulmón: MAE=6,4; RMSE=14,3. SHAP: contaminación doméstica > edad > ambiental.','No','No es un sistema de alerta operativo, aunque se discute su potencial como herramienta para anticipar condiciones de humo y apoyar la gestión de incendios y la salud pública. No se desarrolla ni evalúa un sistema de alerta concreto.','Los modelos ensemble (NGBoost) predicen eficazmente PM2.5 a partir de variables meteorológicas y de combustible, siendo la radiación solar, la humedad de combustible y la temperatura los factores más importantes. La contaminación ambiental es el principal predictor de mortalidad por EPOC, mientras que la edad es más influyente en la mortalidad por cáncer de pulmón.','Diferencia de escala temporal y geográfica entre los dos modelos (local/anual para PM2.5 vs. global/multianual para mortalidad). PM2.5 de monitoreo ambiental, no de exposición personal. Sin control de otras causas de mortalidad (tabaquismo, comorbilidades). Período de un año para el modelo de PM2.5 puede ser insuficiente. Generalización limitada a otras regiones o subpoblaciones.','El enfoque de NGBoost+SHAP para predecir PM2.5 a partir de variables meteorológicas y de humedad de combustible es transferible a regiones andinas, donde la humedad de combustible y la radiación solar también son determinantes de la actividad de incendios. La falta de datos satelitales y la ausencia de topografía (altitud, inversiones térmicas) señalan las brechas directas que la tesis podría llenar incorporando FIRMS/MODIS y variables de relieve andino.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (128,'N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','No','N/A — artículo de revisión','Esta revisión con meta-análisis de efectos aleatorios (REML, paquete metafor en R v4.2.2) sintetiza evidencia sobre efectos a corto plazo del PM2.5 de incendios en mortalidad y morbilidad. Por cada 1 µg/m³ de aumento en PM2.5 de incendios: mortalidad por todas las causas +0,15% (IC95% 0,01–0,28%); hospitalizaciones respiratorias +0,25% (0,09–0,52%); visitas a emergencias respiratorias +0,36% (0,19–0,53%); hospitalizaciones cardiovasculares +0,06% (0,00–0,12%); visitas a emergencias cardiovasculares no significativas. Heterogeneidad alta (I² 79–93%) excepto para hospitalizaciones cardiovasculares (44%). Los estudios incluidos provienen de EE.UU. (California, Washington, Colorado), Brasil, Finlandia y Australia (publicados hasta agosto 2023). Las respuestas conductuales (quedarse en casa) pueden modificar la relación exposición-salud, especialmente en exposiciones extremas.','Solo se incluyeron efectos del mismo día (lag 0), ignorando efectos acumulativos y con retraso. Heterogeneidad significativa entre estudios (I² alta). Las categorías de desenlace (respiratorio, cardiovascular) son amplias y pueden ocultar efectos específicos. No se evaluaron efectos diferenciales por subpoblaciones (edad, sexo, nivel socioeconómico). Posible sesgo de publicación no detectado. Los estudios primarios varían en calidad de los datos de PM2.5 específico de incendios.','Las estimaciones agrupadas de este meta-análisis (0,25–0,36% por 1 µg/m³ de PM2.5 de incendios para desenlaces respiratorios) son la referencia cuantitativa más sólida disponible para contrastar los efectos que se estimen en Áncash. La alta heterogeneidad entre estudios (I² 79–93%) subraya que los efectos son sensibles al contexto geográfico, lo que abre espacio para un estudio específico en ecosistemas andinos de alta montaña. La discusión sobre respuestas conductuales (quedarse en casa) es relevante para poblaciones rurales altoandinas con recursos limitados de protección.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (129,'Enfoque en dos pasos: (1) regresión lineal múltiple (selección por AIC, hasta 6 variables incluyendo 5 meteorológicas y 10 interacciones de dos vías) para obtener residuos de PM2.5 (uPM) y SARD (uSARD) eliminando el efecto de meteorología; (2) correlación de Pearson y Spearman entre uPM y uSARD (y entre uPM y tasa de pruebas negativas uNR), con promedio móvil centrado de 3 semanas.','No se estima un lag específico en días. Se justifica el promedio móvil de 3 semanas en un lag potencial de 6–7 días (literatura previa). Los pronósticos CAMS tienen horizonte de 4 días. Desenlace = SARD (incluye IRA severa pero no exclusivamente).','Ajuste por precipitación, temperatura mínima y máxima, humedad relativa mínima y máxima, y todas las interacciones de dos vías (hasta 6 variables por AIC). Sin estacionalidad explícita ni tendencia temporal (parcialmente absorbidas por las variables meteorológicas).','No reportado. Se usan SREGIC que capturan diferencias regionales en acceso a salud, pero sin variables topográficas (altitud, pendiente, cuencas, inversiones térmicas) en los modelos. Se reconoce como debilidad la mezcla de contextos ambientales y socioeconómicos en las SREGIC.','Coeficiente de correlación de Pearson (lineal) y Spearman (rango, para relaciones no lineales); valor p de significancia; AIC para selección de modelos. Sin R², RMSE ni AUC.','Correlaciones significativas (p<0,05) entre uPM y uSARD suavizados: Maranhão ρ=0,52 (p<0,01); Alagoas ~0,35; Bahia ~0,30; Amapá ~0,30; Mato Grosso ~0,24; Pernambuco ~0,28. Correlaciones negativas en el Sur (Rio Grande do Sul, Santa Catarina). Correlaciones positivas entre uPM y uNR en Rio de Janeiro, Rio Grande do Sul, Santa Catarina (~0,3–0,4). Simulación de alertas (2019–2020): 2.071 municipios (37%) excedieron 25 µg/m³ al menos un día; 2 municipios excedieron nivel de emergencia (250 µg/m³).','Si','Sí, se evalúa factibilidad para construir un sistema de alerta temprana, aunque no es un sistema operativo. Se discuten umbrales basados en CONAMA 491/2018 (atención 125 µg/m³, alerta 210 µg/m³, emergencia 250 µg/m³) y valores intermedios (37, 50, 60 µg/m³) y el umbral OMS (25 µg/m³). Se proporciona ejemplo de pronóstico diario por municipio.','Es factible utilizar los pronósticos globales de PM2.5 del CAMS (horizonte de 4 días) para predecir enfermedades respiratorias agudas severas en Brasil y construir un sistema de alerta temprana. Las correlaciones positivas entre PM2.5 y SARD son significativas en varias regiones (especialmente Norte, Nordeste y Centro-Oeste); en el Sur la relación mejora al considerar la tasa de pruebas negativas (infecciones no virales).','La delimitación de áreas de exposición (SREGIC) es el punto más débil: mezcla diferentes contextos ambientales y socioeconómicos. El promedio como estadístico de resumen suaviza información espacial y temporal importante. Los pronósticos CAMS pueden tener sesgos en Brasil (subestimación en Centro-Oeste) y los cambios en el IFS afectan la consistencia de la serie temporal. No se consideró la composición química del PM2.5. Los umbrales de alerta no se definieron de manera local (solo se propusieron).','El enfoque CAMS+InfoGripe con ajuste meteorológico es el más directamente transferible a Perú para construir un sistema de alerta de IRA por humo de biomasa en Áncash: CAMS ofrece pronósticos de PM2.5 con cobertura global (incluyendo regiones sin monitoreo terrestre), e InfoGripe tiene un análogo peruano en el sistema MINSA/CDC-Perú de vigilancia de IRA. La metodología de correlación de residuos (ajuste por meteorología) es simple y reproducible con datos locales. La falta de topografía andina en el modelo señala la brecha más importante a llenar en la tesis.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (130,'Modelo bayesiano jerárquico de dos etapas. Primera etapa: quasi-Poisson por ZCTA con offset poblacional, ajustando por día de semana, temperatura (spline, mismo día y promedio 3 días previos) y spline de tiempo (13 gl/año). Segunda etapa: pooling (efectos fijos o aleatorios) para asociaciones globales y por subgrupo. Se evaluaron tres enfoques: asociación constante, estratificación en dos períodos y spline de año (4 nudos) para tendencia no lineal.','Promedio móvil de 3 días (lag 0–2) como exposición principal. La asociación es mayor para lag 0 y disminuye para lags 1 y 2. No reportan lag óptimo para IRA específicamente. Desenlace = cuidados agudos circulatorios y respiratorios (no IRA exclusiva).','Día de semana, temperatura del mismo día (spline cúbico natural, 3 gl), temperatura promedio de 3 días previos (spline, 3 gl), punto de rocío (misma estructura), y spline cúbico de tiempo con 13 gl por año para controlar tendencias a largo plazo y estacionalidad.','No reportado. Sin variables topográficas explícitas en los modelos. La clasificación de ZCTAs según exposición a incendios extremos (PM2.5 >35 µg/m³) podría correlacionarse con topografía, pero no se modela explícitamente.','Porcentaje de aumento en el riesgo de cuidados agudos por cada 10 µg/m³ de aumento en PM2.5, con intervalos creíbles del 95% (bayesianos). Cambio porcentual en asociaciones entre períodos. Cochran\'s Q test (p<0,1) para heterogeneidad entre subgrupos.','Asociación global (2006–2019, lag 0–2, por 10 µg/m³): circulatorio +0,56% (IC95% 0,17–0,96%); respiratorio +2,61% (2,29–2,94%). Cambio del primer al segundo período: circulatorio +0,13% (0,02–0,22%); respiratorio +1,40% (1,24–1,54%). Por subgrupos (respiratorio): asiáticos no hispanos la mayor asociación (~4–5% hacia el final del período); hispanos ~3–4%. ZCTAs sin incendios extremos mostraron mayores asociaciones respiratorias en 2014–2019 vs. ZCTAs con incendios extremos.','No','No. El estudio es epidemiológico observacional. Sin sistema de alerta sanitaria.','La exposición a corto plazo a PM2.5 en California se asoció con aumentos significativos en cuidados agudos circulatorios y respiratorios entre 2006 y 2019, y estas asociaciones aumentaron con el tiempo. Las disparidades son importantes: adultos mayores (≥65 años) y asiáticos no hispanos mostraron los mayores riesgos y los mayores aumentos temporales. Las áreas sin exposición extrema a incendios experimentaron mayores aumentos en las asociaciones respiratorias hacia el final del período.','Exclusión de áreas rurales y menos pobladas (solo 192 ZCTAs con ≥50.000 hab.), por lo que los resultados no son generalizables a esas regiones (las más afectadas por incendios). Sin inclusión de personas sin hogar ni comunidades no incorporadas. Sin interseccionalidad de modificadores de efecto. Sin examen de cambios temporales para fuentes específicas de PM2.5 distintas del incendio.','El aumento temporal de las asociaciones PM2.5–salud respiratoria entre 2006–2012 y 2013–2019 proporciona evidencia de que el efecto no es estático y puede intensificarse con el tiempo y la frecuencia de incendios, algo relevante para contextos andinos con aumento de la actividad de quema por cambio climático. La exclusión de áreas rurales —paradójicamente las más expuestas a incendios— es la limitación más importante para el contexto de cuencas altoandinas poco pobladas de Áncash, y señala directamente el nicho metodológico que la tesis puede ocupar.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (131,'Regresión logística en dos enfoques: (1) PM2.5 como variable continua (exposición-respuesta) y (2) comparación binaria (expuesto >25 µg/m³ vs. no/mínimamente expuesto) con propensity score usando Generalized Boosted Models (GBM, 80.000 árboles, profundidad 3, learning rate 0,002) e Inverse Probability Weighting (IPW). Se estimó el Average Treatment Effect in the Treated (ATT). Análisis separados para cohortes IU e infantil.','No estiman retraso agudo (días). Evalúan asociaciones a mediano/largo plazo: la exposición al incendio ocurrió durante la gestación o el primer año de vida, y los resultados se midieron en el primer año de vida o en el año posterior al incendio (meses a más de un año entre exposición y resultado). Desenlace incluye infecciones respiratorias agudas entre otros outcomes.','Sexo, tabaquismo materno, edad materna, país de nacimiento de la madre, paridad, IRSAD (desventaja socioeconómica por SA1), estación y año de nacimiento (IU), período de seguimiento y edad en meses al inicio (infantil), vulnerabilidad al nacer (prematurez, bajo peso, UCIN; solo infantil). Para IPW: también PM2.5 ambiental de fondo como confusor.','No reportado. El estudio asigna exposición a nivel SA1 (capturando gradientes espaciales de PM2.5; ver Fig. 3 del artículo), pero sin variables topográficas (altitud, pendiente, tipo de valle, inversiones térmicas) en los modelos.','Odds Ratio (OR) con IC 95%. Para exposición-respuesta: OR por IQR (240 µg/m³ acumulados para PM2.5 de incendio; 1,4 µg/m³ anual para PM2.5 ambiental). Para IPW: OR comparando expuestos vs. no expuestos.','Exposición-respuesta (IU, por 240 µg/m³ de incendio): urgencias por alergias/rash OR 1,34 (1,01–1,76). PM2.5 ambiental (por 1,4 µg/m³, IU): urgencias cualquier causa OR 1,18 (1,05–1,33); hospitalizaciones por infecciones OR 1,23 (1,00–1,52). IPW (exposición binaria al incendio, cohorte infantil): urgencias respiratorias OR 1,37 (1,05–1,80); urgencias infecciones respiratorias OR 1,39 (1,05–1,83); urgencias cualquier causa OR 1,17 (1,05–1,30). Cohorte IU (IPW): sin asociaciones significativas.','No','No. El estudio es epidemiológico observacional.','La exposición prenatal al PM2.5 del incendio de mina de carbón se asoció con mayor riesgo de visitas a emergencias por alergias/rash, mientras que la exposición infantil se asoció con mayor riesgo de visitas por causas respiratorias e infecciones respiratorias. El PM2.5 ambiental de fondo a niveles bajos (<6,5 µg/m³) también se asoció con mayor uso de servicios de salud. Los efectos difieren según la etapa del desarrollo (prenatal vs. infantil).','Posible error de clasificación de exposición (asignación por SA1, no monitoreo personal; fechas estimadas de concepción). Datos administrativos pueden tener errores en códigos de diagnóstico. Sin ajuste por estrés materno, educación ni ingresos familiares. Bajo número de expuestos en IU (n=518) limita potencia estadística para algunos outcomes. Distribución bimodal de la exposición al incendio impidió usar splines. Resultados pueden no generalizarse a otros contextos (incendio de carbón vs. biomasa).','El estudio distingue los efectos del episodio severo (incendio) de los del PM2.5 crónico de fondo — distinción análoga a la que la tesis deberá hacer entre episodios agudos de quema de biomasa y contaminación de fondo en Áncash. La asociación con infecciones respiratorias (OR 1,39 en cohorte infantil) es el hallazgo más cercano a la variable de ocurrencia de IRA de la tesis. El uso de IPW con GBM para comparación de expuestos vs. no expuestos es una técnica de inferencia causal transferible al diseño de análisis con datos MINSA geolocalizados.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (132,'Regresión logística condicional (case-crossover) con DLNM. Función lineal para exposición-respuesta; spline cúbica natural (df=3) para respuesta al lag (0–28 días). Ajuste por temperatura, humedad relativa, precipitación (spline df=3) y PM2.5 total (lag 0). Análisis estratificados por género, edad, estación y región de alta/baja exposición. Cálculo de fracciones atribuibles (AF) y casos atribuibles (AC).','Período de lag 0–28 días. La asociación negativa inicial en los primeros 6 días se revierte a partir del día 6, con efectos positivos que aumentan hasta el día 28 y se atenúan después. El lag 0–28 días se seleccionó como el más apropiado, alineándose con los períodos de incubación de las enfermedades estudiadas (influenza: 1–7 días; sarampión: 7–14 días; tos ferina: 7–14 días; rubéola: 14–21 días). Desenlace = enfermedades respiratorias transmitidas, que incluyen IRA.','Temperatura media diaria (lag 0, spline df=3), humedad relativa media diaria (lag 0, spline df=3), precipitación diaria (lag 0, spline df=3) y PM2.5 total (lag 0, lineal). Día de semana controlado por diseño de casos cruzados.','No reportado. Estratificación por región de alta vs. baja exposición (umbral 1,5 µg/m³ anual), pero sin variables topográficas (altitud, pendiente, cuencas, inversiones térmicas) en los modelos. La discusión sugiere que el envejecimiento del humo durante el transporte a larga distancia puede aumentar la toxicidad, pero sin modelar la topografía.','Odds Ratio (OR) con IC 95% (interpretados como RR en el contexto case-crossover). Percent Change (PC) = (RR−1)×100%. Attributable Fraction (AF) y Attributable Cases (AC). Prueba de razón de verosimilitud en metarregresión para comparar subgrupos.','Por cada 5 µg/m³ de aumento en PM2.5 de incendios (lag 0–28 días): incidencia general de enfermedades respiratorias transmitidas OR 1,068 (IC95% 1,050–1,087) → +6,8%. Enfermedades específicas: influenza OR 1,286 (+28,6%); rubéola OR 1,126 (+12,6%); sarampión OR 1,136 (+13,6%); escarlatina OR 1,052 (+5,2%). Para PM2.5 no relacionado con incendios: OR 1,012 (+1,2%). Subgrupos: hombres OR 1,199 vs. mujeres OR 1,047; edad 9–12 años OR 1,089; otoño OR 1,519; regiones de baja exposición OR 1,284. Fracción atribuible: PM2.5 de incendios (2,7% del total) contribuye al 10,8% de los casos atribuibles a PM2.5; en regiones de baja exposición, esa proporción alcanza el 29,7%.','No','No. El estudio no propone ni evalúa un sistema de alerta sanitaria, aunque los autores discuten la necesidad de sistemas de alerta temprana como estrategia de adaptación.','La exposición a corto plazo a PM2.5 de incendios forestales se asocia con un aumento significativo en la incidencia de enfermedades respiratorias transmitidas en niños y adolescentes chinos (+6,8% por 5 µg/m³), con un efecto por unidad de masa notablemente mayor que el del PM2.5 de otras fuentes (+1,2%). El PM2.5 de incendios, aunque solo constituye el 2,7% del PM2.5 total, contribuye al 10,8% de los casos atribuibles a PM2.5, y este efecto es especialmente pronunciado en regiones con bajas concentraciones de PM2.5 de incendios (hasta el 29,7% de los casos atribuibles).','Posible error de medición de exposición al usar promedios a nivel de ciudad como proxy de exposición individual (sesgo hacia el nulo). Resolución espacial gruesa (~28 km). Posible subnotificación de casos (aunque el CISDCP cubre >95% de los centros de salud). Datos solo de China; exclusión de niños <4 años puede subestimar la carga de sarampión, tos ferina y meningitis meningocócica. Número limitado de muertes (1.034) restringe poder estadístico para análisis de mortalidad.','Este es el estudio del corpus más cercano al desenlace de la tesis: analiza específicamente infecciones respiratorias transmitidas (influenza, tos ferina, sarampión, rubéola) que se superponen con IRA, en niños y adolescentes (4–24 años), con un diseño case-crossover que controla por confusores invariantes en el tiempo. La demostración de que el PM2.5 de incendios tiene un efecto por unidad de masa ~6 veces mayor que el PM2.5 de fondo respalda el énfasis metodológico en aislar la fracción de incendios. El hallazgo de que incluso en regiones con bajas concentraciones de PM2.5 de incendios el impacto sanitario es sustancial (hasta 29,7% de los casos atribuibles) es directamente relevante para cuencas andinas que reciben humo transportado desde la Amazonia. La ausencia de variables topográficas (altitud, inversiones térmicas) es la principal brecha que la tesis puede llenar para el contexto andino.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (133,'N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','No','N/A — artículo de revisión','Esta revisión narrativa (2014–2024, 81% estudios primarios, 19% revisiones) documenta que el humo de incendios forestales (WFS) causa efectos sistémicos en la salud a través de inflamación, estrés oxidativo, daño al ADN y modificaciones epigenéticas. Los niños son especialmente vulnerables por su fisiología (mayor ventilación por kg, vías aéreas más pequeñas y pulmones en desarrollo). Hallazgos cuantitativos sintetizados: por cada 10 µg/m³ de aumento en PM2.5 de incendios, la mortalidad global aumenta un 1,9% (RR 1,019), la mortalidad respiratoria un 1,9% (1,013–1,025) y la cardiovascular un 1,7% (1,012–1,021). En Brasil (2000–2016): 31.287 muertes respiratorias atribuibles; en niños <5 años: 4,88% aumento de hospitalizaciones por 10 µg/m³. En California, el PM2.5 de incendios fue 10 veces más dañino para la salud respiratoria infantil que el PM2.5 urbano. Las infecciones respiratorias agudas bajas representan el 36% de la mortalidad atribuible a PM2.5 de incendios.','Revisión narrativa (no sistemática), con posible sesgo de selección. Solo el 29% de los estudios revisados se enfocan específicamente en niños/adolescentes. Se desconocen los efectos a largo plazo del WFS en niños. La mayoría de los estudios se enfocan en exposición aguda, no crónica. Escasez de estudios en regiones de alta montaña (ningún estudio andino incluido).','La cifra síntesis de que las infecciones respiratorias agudas bajas representan el 36% de la mortalidad atribuible a PM2.5 de incendios proporciona la justificación epidemiológica más directa para el foco en IRA de la tesis. La vulnerabilidad infantil (<5 años) destacada en la revisión es el grupo etario prioritario en los registros MINSA de Áncash. La recomendación de mejorar sistemas de alerta temprana es el componente práctico que conecta con el objetivo del proyecto PROCIENCIA. La ausencia de factores topográficos de montaña en todos los estudios revisados es la brecha que la tesis puede ocupar.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (134,'Regresión logística condicional (case-crossover). Estratificación por grid (12 km), ajuste por temperatura del grid y día de semana. Tres lags: lag 0, promedio móvil lag 0–1 y promedio móvil lag 0–1–2. Dos métricas de PM2.5: promedio 24 h y máximo horario. PM2.5 también modelado como variable categórica (categorías de 10 µg/m³) para explorar no linealidades.','Lag 0 (mismo día) fue el principal, con promedios móviles de 2 y 3 días como análisis de sensibilidad. Para asma/sibilancias, los OR aumentaron con lags más largos (lag 0–1–2: OR 1,07 vs. lag 0: OR 1,04 por 5 µg/m³). Las infecciones respiratorias altas (ICD-9 460–465) corresponden a IRA y mostraron OR 1,02 (1,00–1,03) a lag 0.','Temperatura del grid (promedio diario) y día de semana (categórico). Sin ajuste por humedad ni estacionalidad (período muy corto, 32 días). Ozono evaluado como potencial confusor en modelos bicontaminantes y descartado por parsimonia.','No reportado. El estudio controla por ubicación (grid) mediante estratificación, pero no incorpora variables topográficas (altitud, pendiente, cuencas, inversiones térmicas) a pesar de la alta variabilidad topográfica de Colorado (Montañas Rocosas, altiplano).','Odds Ratio (OR) con IC 95% por incremento de 5 µg/m³ para promedio 24 h, y por 10 µg/m³ para máximo horario. También PM2.5 como variable categórica para no linealidades.','Lag 0, promedio 24 h, por 5 µg/m³: asma/sibilancias OR 1,04 (IC95% 1,02–1,06); EPOC OR 1,05 (1,02–1,08); enfermedad respiratoria (todos) OR 1,02 (1,01–1,03); infección respiratoria alta OR 1,02 (1,00–1,03). Por máximo horario (10 µg/m³): asma/sibilancias OR 1,01 (1,00–1,01); EPOC OR 1,01 (1,00–1,02). Cardiovasculares: todos con IC que incluyen 1 o con OR <1. Por edad (asma, lag 0–1–2): ≥65 años OR 1,29 (1,03–1,61) por 5 µg/m³.','No','No. El estudio es puramente epidemiológico.','El PM2.5 proveniente de incendios forestales en Colorado (2012) se asoció significativamente con visitas a emergencias por asma/sibilancias, EPOC e infecciones respiratorias altas (IRA, ICD-9 460–465), con efectos más fuertes en adultos mayores de 65 años. No se encontraron asociaciones para outcomes cardiovasculares.','El modelo WRF-Chem tiene sesgos y puede no capturar características localizadas (sesgo absoluto 13–19 µg/m³). Período de estudio corto (32 días), limitando potencia estadística. No se pudo separar PM2.5 de incendios del PM2.5 de fondo. Las evacuaciones durante incendios (32.000 personas) pueden causar clasificación errónea de exposición. Sin ajuste por comportamientos de adaptación (quedarse en casa, usar mascarillas).','Las infecciones respiratorias altas (ICD-9 460–465) son explícitamente el código que el estudio usa para \'upper respiratory infection\', constituyendo la aproximación más cercana a IRA en el corpus de P3 fuera de P3-007. El diseño case-crossover estratificado por grid (12 km) es el más directamente comparable al diseño que la tesis podría implementar a nivel de distrito en Áncash, con datos WRF-Chem o MERRA-2 como sustitutos del monitoreo terrestre. La alta variabilidad topográfica de Colorado (análoga a los Andes) sin que se modele explícitamente subraya la principal brecha metodológica que la tesis puede llenar.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (135,'N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','N/A — artículo de revisión','No','N/A — artículo de revisión','Esta revisión crítica sintetiza el conocimiento sobre partículas ultrafinas (UFP, <100 nm) emitidas por incendios en la interfaz urbano-forestal (WUI). Los UFP dominan numéricamente el humo (77–90%, hasta 1,25×10⁵ partículas/cm³) pero representan solo el 5–15% de la masa de PM2.5; contienen PAHs carcinogénicos, metales pesados (0,01–1 µg/m³) y PFAS de materiales sintéticos. Su envejecimiento fotoquímico genera aerosoles orgánicos secundarios y ozono. Los UFP atraviesan barreras biológicas causando estrés oxidativo e inflamación, con aumento del 87% en prevalencia de asma y elevados riesgos cardiovasculares, neurológicos y cancerígenos. Las comunidades de bajos ingresos, indígenas y bomberos sufren impactos desproporcionados. La mortalidad por EPOC asociada a smoke PM2.5 muestra un HR de 1,09 a escala nacional (EE.UU.) y hasta 1,40 en regiones de bajo riesgo de incendio. Técnicas avanzadas (HAADF-STEM, DEG-SMPS, TEMPO) permiten caracterizar UFP hasta 1–3 nm. Los filtros HEPA reducen UFPs en interiores en un 90%.','Ausencia de protocolos estandarizados globales para monitoreo de UFPs. Sensibilidad reducida para partículas sub-10 nm en muchos instrumentos. Alto costo de instrumentación avanzada. Escasez de datos sobre perfiles de emisión de combustibles mixtos (WUI). Conocimiento insuficiente sobre toxicidad de UFPs asociados a PAHs y metales de baterías de vehículos eléctricos. Limitados estudios longitudinales de salud para efectos crónicos. Diferenciación insuficiente entre humo de incendios forestales vs. quemas prescritas.','El enfoque en partículas ultrafinas (<100 nm) amplía el marco conceptual más allá del PM2.5 estándar, señalando que la toxicidad del humo no es completamente capturada por los monitores convencionales — lo que es relevante para entender por qué el efecto por unidad de masa del humo de incendios es mayor que el del PM2.5 de fondo (como se documenta en P3-027 y P3-031). En cuencas andinas con inversiones térmicas, los UFPs podrían acumularse y envejecer fotoquímicamente de manera análoga a los WUI, aumentando su toxicidad. La propuesta de microsensores de bajo costo (PurpleAir) y modelos CNN+satélites para predicción en tiempo real es tecnológicamente viable para el componente de monitoreo del proyecto PROCIENCIA en Áncash.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (136,'Modelos de riesgos proporcionales de Cox con covariables tiempo-dependientes. Estratificación por grupo etario, sexo, raza, elegibilidad Medicaid y presencia de enfermedades cardiovasculares. Smoke PM2.5 y non-smoke PM2.5 incluidos simultáneamente. Ajuste por temperatura, humedad, tasas de tabaquismo y año calendario. Análisis de sensibilidad con smoke-days como exposición alternativa.','Promedio móvil de 12 meses previos al mes de muerte (exposición a largo plazo). Sin lags agudos en días. Para smoke-days: conteo de días en los 12 meses previos. Desenlace = mortalidad por EPOC (no IRA).','Temperatura (promedio ponderado por población), humedad relativa, proporción de fumadores actuales y exfumadores (ZIP code), año calendario. Estratificación no paramétrica por edad, sexo, raza, Medicaid y CVD preexistente.','No reportado. División en regiones de riesgo de incendio (bajo/moderado/alto) por datos USDA como variable proxy, pero sin variables topográficas (altitud, pendiente, tipo de valle, inversiones térmicas) en los modelos.','Hazard Ratio (HR) ajustado con IC 95%. HR por IQR (rango intercuartil). Inverse-variance weighting para combinar estimaciones de 10 sub-cohortes.','Nacional: por 1 µg/m³ de smoke PM2.5 (promedio 12 meses): HR 1,092 (IC95% 1,088–1,097) → +9,2%. Por 1 µg/m³ de non-smoke PM2.5: HR 1,005 (+0,5%). Por región: bajo riesgo HR 1,404 (+40,4%); moderado riesgo HR 1,096 (+9,6%); alto riesgo HR 1,039 (+3,9%). Sensibilidad (smoke days >2,5 µg/m³): cada día adicional → HR 1,07 (1,06–1,08).','No','No. El estudio es epidemiológico observacional.','La exposición a largo plazo a PM2.5 de humo de incendios forestales aumenta significativamente la mortalidad por EPOC en adultos mayores de EE.UU. (+9,2% por 1 µg/m³), con un efecto mucho mayor que el PM2.5 de otras fuentes (+0,5%). Sorprendentemente, las regiones de bajo riesgo de incendio presentan el mayor riesgo asociado (+40,4% por 1 µg/m³), posiblemente por exposición a humo envejecido más tóxico o menor comportamiento protector de la población.','Se asume que todos en el mismo ZIP code tienen la misma exposición outdoor (sesgo hacia el nulo). El modelo de exposición no distingue incendios forestales de quemas prescritas. Las regiones de riesgo se usan como proxy grueso. Sin datos individuales de tabaquismo ni factores socioeconómicos detallados. Período 2008–2016 puede no reflejar cambios recientes de comportamiento.','El hallazgo de que las regiones con baja concentración habitual de smoke PM2.5 muestran el mayor riesgo unitario (+40,4% por 1 µg/m³) es directamente relevante para cuencas andinas altoandinas donde el humo de incendios es un contaminante episódico sobre una población no acostumbrada a él — analogía exacta a la situación de Áncash, donde el humo transportado desde la Amazonia o generado localmente en época seca impacta a poblaciones expuestas a bajas concentraciones de fondo. La separación metodológica entre smoke PM2.5 y non-smoke PM2.5 mediante el modelo random forest+HMS es el enfoque que la tesis necesita adaptar usando FIRMS/MODIS y datos SENAMHI para Áncash.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (137,'Regresión lineal simple (cada índice PM2.5 vs. mortalidad por enfermedad/género), regresión lineal múltiple (cuatro índices combinados) y Red Neuronal Convolucional (CNN) 1D con arquitectura densa de 3 capas convolucionales + capas densas. La CNN predice mortalidad por enfermedad, estado y género a partir de los cuatro índices de extremos de PM2.5. Regularización L2 y dropout para evitar sobreajuste.','No estimado (el estudio trabaja con mortalidad anual, no con retraso agudo). Analiza efectos a largo plazo (décadas). Sin lags diarios/semanales.','No se aplica ajuste estadístico explícito en los modelos de regresión (solo correlación bivariada y multivariada entre PM2.5 y mortalidad). La CNN incluye regularización pero sin variables confusoras epidemiológicas (temperatura, humedad, nivel socioeconómico, tabaquismo).','No reportado. Se mencionan diferencias norte-sur y el papel de la topografía (cuencas del IGP, inversiones térmicas) en la discusión, pero sin incorporar variables topográficas (altitud, pendiente, tipo de valle) en los modelos.','Para regresiones: R². Para CNN: R², Nash-Sutcliffe Efficiency (NSE), Percent Bias (PBIAS) y Mean Squared Error (MSE).','Regresión simple: R² para MPM2.5 — neurológicos: 0,18–0,21; respiratorios crónicos: 0,18–0,21; cardiovasculares: 0,15–0,16; infecciones respiratorias: 0,07–0,09. Regresión múltiple: R² máximo 0,32 (neurológicos masculinos). CNN densa (3 capas): R² por enfermedad entre 0,84 y 0,96 según género y fase (ej. infecciones respiratorias masculinas testing: R²=0,96; neurológicas femeninas testing: R²=0,87). NSE en rangos similares; PBIAS entre −3,74% y 15,54%.','No','No. El estudio no propone un sistema de alerta operativo. Es puramente predictivo/modelamiento de mortalidad a nivel anual.','Los extremos de PM2.5 en India (especialmente MPM2.5 y PM2.5D) se asocian moderadamente con mortalidad por trastornos neurológicos y enfermedades respiratorias crónicas, y débilmente con infecciones respiratorias (R²=0,07–0,09 en regresión lineal). Un modelo CNN denso predice mortalidad por estado, género y enfermedad con alta precisión (R² 0,84–0,96), revelando una marcada disparidad norte-sur en el impacto sanitario.','Los modelos de regresión muestran R² bajos para infecciones respiratorias, indicando baja predictibilidad solo con PM2.5. Incertidumbres en las estimaciones de mortalidad GBD. Diseño ecológico a nivel estatal (falacia ecológica). Solo se considera PM2.5 total (no componentes ni otros contaminantes). Resolución espacial gruesa de MERRA-2 (~55 km). Resultados específicos de India, no directamente generalizables.','El uso de MERRA-2 para estimar PM2.5 en ausencia de red de monitoreo terrestre densa es directamente transferible a Áncash, donde MERRA-2 es una de las fuentes satelitales contempladas en OE2. La débil correlación entre PM2.5 total y mortalidad por infecciones respiratorias (R²=0,07–0,09) — frente a la correlación moderada con enfermedades crónicas — respalda la importancia de aislar el PM2.5 específico de incendios de biomasa (como hace P3-027) en lugar de usar el PM2.5 total. La arquitectura CNN 1D podría adaptarse para predicción de series temporales de IRA en Áncash combinando índices de extremos de PM2.5 de incendios con datos FIRMS/MODIS.');
INSERT INTO `EXTRACCION_P3` (`idArticulo`,`metodo_modelamiento`,`lag_estimado`,`ajuste_confusores`,`factores_topograficos`,`metrica_evaluacion`,`valor_alcanzado`,`sistema_alerta`,`tipo_alerta`,`resultado_principal`,`limitaciones`,`oportunidades`) VALUES (138,NULL,NULL,NULL,NULL,NULL,NULL,'No',NULL,NULL,NULL,NULL);
